class ValidationError(Exception):
    pass


UniqueKeyLoaderBase = getattr(yaml, "CSafeLoader", yaml.SafeLoader)


class UniqueKeyLoader(UniqueKeyLoaderBase):
    pass


UniqueKeyLoader.yaml_implicit_resolvers = {
    key: [resolver for resolver in resolvers if resolver[0] != "tag:yaml.org,2002:timestamp"]
    for key, resolvers in UniqueKeyLoaderBase.yaml_implicit_resolvers.items()
}


class NoAliasSafeDumper(yaml.SafeDumper):
    def ignore_aliases(self, data: Any) -> bool:
        return True


def construct_unique_mapping(loader: UniqueKeyLoader, node: yaml.MappingNode, deep: bool = False) -> dict[Any, Any]:
    mapping: dict[Any, Any] = {}
    for key_node, value_node in node.value:
        key = loader.construct_object(key_node, deep=deep)
        if key in mapping:
            raise ValidationError(f"duplicate YAML key: {key}")
        mapping[key] = loader.construct_object(value_node, deep=deep)
    return mapping


UniqueKeyLoader.add_constructor(
    yaml.resolver.BaseResolver.DEFAULT_MAPPING_TAG,
    construct_unique_mapping,
)


def require(condition: bool, message: str) -> None:
    if not condition:
        raise ValidationError(message)


def callable_harness_sha256(function: Any) -> str:
    try:
        source = textwrap.dedent(inspect.getsource(function)).replace("\r\n", "\n").rstrip() + "\n"
    except (OSError, TypeError) as error:
        raise ValidationError(f"validation harness source unavailable: {error}") from error
    return sha(source.encode())


def completed_check_entry(check_id: str, harness_sha256: str) -> dict[str, Any]:
    require(HEX64_RE.match(harness_sha256) is not None, f"validation harness digest malformed: {check_id}")
    completed = {
        "id": check_id,
        "result": "PASS",
        "execution_state": "COMPLETED",
        "harness_sha256": harness_sha256,
    }
    return {**completed, "execution_sha256": sha(canonical_json(completed).encode())}


def validate_executed_check_entries(entries: list[dict[str, Any]], required_ids: set[str], expected_harnesses: dict[str, str]) -> list[str]:
    require(isinstance(entries, list) and all(isinstance(item, dict) for item in entries), "validation report checks must be a list of objects")
    require(all(set(item) == {"id", "result", "execution_state", "harness_sha256", "execution_sha256"} for item in entries), "validation report check entry schema drift")
    ids = [item["id"] for item in entries]
    require(len(ids) == len(set(ids)), "validation report contains duplicate check IDs")
    require(set(expected_harnesses) == required_ids, "validation report expected harness set drift")
    for item in entries:
        require(item["id"] in expected_harnesses and item == completed_check_entry(item["id"], expected_harnesses[item["id"]]), f"validation report check was not actually completed by the attested harness: {item.get('id')}")
    require(set(ids) == required_ids, f"validation report executed check set drift: missing={sorted(required_ids - set(ids))} extra={sorted(set(ids) - required_ids)}")
    return sorted(ids)


def load_yaml(raw: str | bytes) -> dict[str, Any]:
    value = yaml.load(raw, Loader=UniqueKeyLoader)
    require(isinstance(value, dict), "YAML root must be a mapping")
    return value


def dump_yaml(value: dict[str, Any]) -> bytes:
    return yaml.dump(value, Dumper=NoAliasSafeDumper, sort_keys=False, width=1000000, allow_unicode=False).encode()


def sha(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def canonical_json(value: Any) -> str:
    try:
        return json.dumps(value, sort_keys=True, separators=(",", ":"), ensure_ascii=True, allow_nan=False)
    except (TypeError, ValueError) as error:
        raise ValidationError(f"canonical JSON rejects non-finite or unsupported values: {error}") from error


def reject_json_constant(value: str) -> None:
    raise ValidationError(f"JSON non-finite constant rejected: {value}")


def strict_json_loads(raw: str | bytes, label: str) -> Any:
    try:
        return json.loads(raw, parse_constant=reject_json_constant)
    except (UnicodeDecodeError, json.JSONDecodeError) as error:
        raise ValidationError(f"{label} is not strict JSON") from error


SEMANTIC_DASH_TRANSLATION = str.maketrans({
    "\u2010": "-", "\u2011": "-", "\u2012": "-", "\u2013": "-", "\u2014": "-", "\u2212": "-",
})


def normalize_markdown_semantic_words(text: str) -> str:
    """Return Markdown/punctuation/hyphen-insensitive lowercase word tokens."""
    normalized = unicodedata.normalize("NFKC", text).translate(SEMANTIC_DASH_TRANSLATION)
    normalized = re.sub(r"<!--.*?-->", " ", normalized, flags=re.DOTALL)
    normalized = re.sub(r"\[([^\]]+)\]\([^)]*\)", r"\1", normalized)
    normalized = re.sub(r"[`*_~]+", "", normalized)
    normalized = re.sub(r"(?<=[A-Za-z])(?=\d)|(?<=\d)(?=[A-Za-z])", " ", normalized)
    return re.sub(r"\s+", " ", re.sub(r"[^A-Za-z0-9]+", " ", normalized).lower()).strip()


def split_cells(line: str) -> list[str]:
    return [cell.strip().strip("`") for cell in line.strip().strip("|").split("|")]


def parse_issue_table(text: str) -> dict[str, list[str]]:
    rows: dict[str, list[str]] = {}
    for line in text.splitlines():
        if line.startswith("| FMB-"):
            cells = split_cells(line)
            if len(cells) >= 3:
                require(cells[0] not in rows, f"duplicate Markdown issue row: {cells[0]}")
                rows[cells[0]] = cells
    return rows


def parse_semicolon_fields(value: str) -> dict[str, str]:
    fields: dict[str, str] = {}
    for part in value.split(";"):
        key, separator, item = part.strip().partition("=")
        require(separator == "=" and key and key not in fields, f"invalid or duplicate pre-execution intent field: {part}")
        fields[key] = item
    return fields


def parse_pre_execution_intents(markdown: str) -> dict[str, dict[str, Any]]:
    rows = parse_issue_table(markdown)
    intents: dict[str, dict[str, Any]] = {}
    for issue, cells in rows.items():
        if len(cells) != 8 or not cells[2].isdigit():
            continue
        doc = parse_semicolon_fields(cells[4])
        smoke = parse_semicolon_fields(cells[6])
        tdd = parse_semicolon_fields(cells[7])
        require(set(doc) == {"trigger", "companion", "scope"}, f"doc intent fields drift: {issue}")
        require(set(smoke) == {"ha_real_hardware", "scope", "operator_override"}, f"smoke intent fields drift: {issue}")
        require(set(tdd) == {"mode", "expected_paths"}, f"TDD intent fields drift: {issue}")
        intents[issue] = {
            "schema": "pre-execution-intent-v1",
            "repo": cells[1],
            "complexity": int(cells[2]),
            "risk_classes": cells[3].split(","),
            "doc_gate": {
                "trigger": doc["trigger"] == "yes",
                "companions": [] if doc["companion"] == "none" else [doc["companion"]] if doc["companion"] == "self" else doc["companion"].split(","),
                "scope": doc["scope"],
            },
            "transport_summary": cells[5],
            "smoke": {"ha_real_hardware": smoke["ha_real_hardware"] == "yes", "scope": smoke["scope"], "operator_override": smoke["operator_override"]},
            "tdd": {"mode": tdd["mode"], "expected_paths": tdd["expected_paths"]},
        }
        intents[issue]["intent_sha256"] = sha(canonical_json(intents[issue]).encode())
    return intents


def render_pre_execution_intent_row(issue: str, intent: dict[str, Any]) -> str:
    companions = intent["doc_gate"]["companions"]
    companion_text = "none" if not companions else "self" if companions == ["self"] else ",".join(companions)
    cells = [
        issue, intent["repo"], str(intent["complexity"]), ",".join(intent["risk_classes"]),
        f"trigger={'yes' if intent['doc_gate']['trigger'] else 'no'}; companion={companion_text}; scope={intent['doc_gate']['scope']}",
        intent["transport_summary"],
        f"ha_real_hardware={'yes' if intent['smoke']['ha_real_hardware'] else 'no'}; scope={intent['smoke']['scope']}; operator_override={intent['smoke']['operator_override']}",
        f"mode={intent['tdd']['mode']}; expected_paths={intent['tdd']['expected_paths']}",
    ]
    return "| " + " | ".join(cells) + " |"


def validate_pre_execution_intent_authority(plan: dict[str, Any], observed_markdown: dict[str, dict[str, Any]] | None = None) -> None:
    intents = plan.get("pre_execution_intents")
    require(isinstance(intents, dict), "pre_execution_intents machine authority missing")
    milestones = {item["id"]: item for item in plan["milestones"]}
    require(set(intents) == set(milestones), "pre_execution_intents exact issue set drift")
    required_fields = {"schema", "repo", "complexity", "risk_classes", "doc_gate", "transport_summary", "smoke", "tdd", "intent_sha256"}
    for issue, intent in intents.items():
        require(set(intent) == required_fields and intent["schema"] == "pre-execution-intent-v1", f"pre-execution intent schema drift: {issue}")
        require(intent["repo"] == milestones[issue]["repo"], f"pre-execution intent repo drift: {issue}")
        require(isinstance(intent["complexity"], int) and 1 <= intent["complexity"] <= 10, f"pre-execution complexity drift: {issue}")
        require(isinstance(intent["risk_classes"], list) and intent["risk_classes"] and len(intent["risk_classes"]) == len(set(intent["risk_classes"])), f"pre-execution risk classes drift: {issue}")
        if {"transport", "protocol", "security", "network", "rtu", "custody", "concurrency"} & set(intent["risk_classes"]):
            require(intent["complexity"] >= 9, f"high-risk pre-execution complexity downgrade: {issue}")
        if issue in {"FMB-00D", "FMB-02A", "FMB-02B", "FMB-02C", "FMB-02R-A"}:
            require(intent["complexity"] == 10, f"critical transport/control complexity downgrade: {issue}")
        unsigned = {key: value for key, value in intent.items() if key != "intent_sha256"}
        require(intent["intent_sha256"] == sha(canonical_json(unsigned).encode()), f"pre-execution intent digest drift: {issue}")
        milestone = milestones[issue]
        require(
            milestone["complexity"] == intent["complexity"]
            and milestone["risk_classes"] == intent["risk_classes"]
            and milestone["doc_gate_intent"] == intent["doc_gate"]
            and milestone["smoke_intent"] == intent["smoke"]
            and milestone["tdd_intent"] == intent["tdd"]
            and milestone["pre_execution_intent_sha256"] == intent["intent_sha256"],
            f"milestone pre-execution intent parity drift: {issue}",
        )
    require(plan.get("pre_execution_intents_sha256") == sha(canonical_json(intents).encode()), "pre_execution_intents aggregate digest drift")
    if observed_markdown is not None:
        require(observed_markdown == intents, "93 pre-execution table is not an exact machine render")


def parse_lane_table(text: str) -> dict[str, list[str]]:
    lanes: dict[str, list[str]] = {}
    active = False
    for line in text.splitlines():
        if line.strip() in {"## Serialized Repository Lanes", "## Executable Per-Repository Lanes"}:
            active = True
            continue
        if active and line.startswith("## "):
            break
        if active and line.startswith("| helianthus-"):
            cells = split_cells(line)
            lanes[cells[0]] = [part.strip() for part in cells[1].replace("~>", "->").split("->")]
    return lanes


def parse_bullet_lanes(text: str) -> dict[str, list[str]]:
    lanes: dict[str, list[str]] = {}
    for line in text.splitlines():
        match = re.match(r"^- `(helianthus-[^`]+)`: (FMB-.+)$", line)
        if match:
            lanes[match.group(1)] = [part.strip() for part in match.group(2).replace("~>", "->").split("->")]
    return lanes


def parse_milestone_groups(text: str) -> dict[str, list[str]]:
    groups: dict[str, list[str]] = {}
    for line in text.splitlines():
        if line.startswith("| M"):
            cells = split_cells(line)
            if len(cells) >= 2 and cells[0] not in {"M", "Milestone"}:
                groups[cells[0]] = [part.strip() for part in cells[1].split(",")]
    return groups


def internal_consumes(milestone: dict[str, Any], ids: set[str]) -> list[str]:
    return [edge["source"] for edge in milestone.get("consumes_if", []) if edge.get("source") in ids]


def artifact_edges(milestones: list[dict[str, Any]]) -> set[tuple[str, str]]:
    ids = {m["id"] for m in milestones}
    edges: set[tuple[str, str]] = set()
    for target in milestones:
        edges.update((source, target["id"]) for source in target.get("depends_on", []))
        edges.update((source, target["id"]) for source in internal_consumes(target, ids))
    return edges


