def expected_modbus_operation_descriptor(milestone: dict[str, Any], plan: dict[str, Any]) -> dict[str, Any]:
    entries = plan["transport_intents"][milestone["id"]]
    families = sorted({entry["family"] for entry in entries if entry["family"].startswith("MODBUS_")})
    behavior = ISSUE_BEHAVIOR_CLASS_BY_ID[milestone["id"]]
    transport_declares_operation = bool(families) and behavior != "planning_gate" and milestone["id"] != "FMB-00F-MODBUSREG"
    artifact_declares_operation = milestone["acceptance_artifact"] in EXPECTED_MODBUS_OPERATION_ARTIFACTS
    sources = (["transport_intent"] if transport_declares_operation else []) + (["acceptance_artifact"] if artifact_declares_operation else [])
    capable = bool(sources)
    read_codes: list[str] = []
    read_authority = "not-applicable"
    if capable:
        critical = expected_critical_issue_oracle(milestone["id"])
        if critical is not None and "allowed_function_codes_hex" in critical["numeric_limits"]:
            read_codes = list(critical["numeric_limits"]["allowed_function_codes_hex"])
            read_authority = f"critical-oracle:{milestone['id']}.numeric_limits.allowed_function_codes_hex"
        elif behavior in {"modbus_pdu", "modbus_tcp", "modbus_rtu", "gateway_api"}:
            read_codes = ["01", "02", "03", "04"]
            read_authority = f"execution-class:{behavior}:raw-read-contract"
        else:
            read_codes = ["03", "04"]
            read_authority = f"execution-class:{behavior}:register-profile-contract"
    return {
        "schema": "typed-modbus-operation-descriptor-v1",
        "capability": "execute-read-only" if capable else "none",
        "capability_sources": sources,
        "transport_families": families,
        "read_function_codes_hex": read_codes,
        "read_function_code_authority": read_authority,
        "write_supported": False,
        "derivation": "union-of-typed-transport-intents-and-independent-acceptance-artifact-schema-authority",
        "acceptance_artifact": milestone["acceptance_artifact"],
    }


def validate_modbus_operation_descriptor(milestone: dict[str, Any], plan: dict[str, Any]) -> None:
    descriptor = milestone.get("modbus_operation_descriptor")
    require(descriptor == expected_modbus_operation_descriptor(milestone, plan), f"typed Modbus operation descriptor drift: {milestone['id']}")
    require(descriptor["write_supported"] is False and not ({"05", "06", "0F", "10"} & set(descriptor["read_function_codes_hex"])), f"write-capable Modbus operation descriptor forbidden: {milestone['id']}")


def issue_exposes_raw_modbus(milestone: dict[str, Any]) -> bool:
    descriptor = milestone.get("modbus_operation_descriptor")
    require(isinstance(descriptor, dict), f"typed Modbus operation descriptor missing: {milestone['id']}")
    return descriptor.get("capability") == "execute-read-only"


def render_cross_repo_gate_rows(plan: dict[str, Any]) -> str:
    by_id = {milestone["id"]: milestone for milestone in plan["milestones"]}
    cross_edges = {
        (source, target)
        for source, target in artifact_edges(plan["milestones"])
        if by_id[source]["repo"] != by_id[target]["repo"]
    }
    consumers: dict[str, list[str]] = {}
    for source, target in sorted(cross_edges):
        consumers.setdefault(source, []).append(target)
    lines = []
    for source in sorted(consumers):
        milestone = by_id[source]
        artifact = milestone["acceptance_artifact"]
        edges = ", ".join(f"{source} -> {target}" for target in consumers[source])
        lines.append(
            f"| G-AE-{source.removeprefix('FMB-')} | {source} / {milestone['repo']} | `{artifact}` | {edges} | "
            f"{source} validates and publishes `{artifact}`; each target verifies exact digest/predicate before use. | "
            "Revoke or pin producer artifact; block only consuming edges; preserve unrelated schedule lanes. |"
        )
    return "\n".join(lines)


def raw_write_rejection_limits(milestone: dict[str, Any]) -> dict[str, Any]:
    return {
        "declared_modbus_operation_function_codes_hex": milestone["modbus_operation_descriptor"]["read_function_codes_hex"],
        "raw_write_supported": False,
        "write_attempt_error": "UNSUPPORTED",
        "write_authorization_effect": "NONE",
        "write_rejection_stage": "BEFORE_TRANSPORT_ACCESS",
        "write_transport_call_count": 0,
        "write_rejection_receipt_schema": "raw-modbus-write-rejection-receipt-v1",
        "write_rejection_receipt_signer_role": "independent-issue-verifier",
    }


def raw_write_rejection_receipt(milestone: dict[str, Any], request_kind: str, authorization_state: str) -> dict[str, Any]:
    require(request_kind in {item[0] for item in RAW_MODBUS_WRITE_REQUESTS}, f"unknown raw Modbus write request fixture: {request_kind}")
    require(authorization_state in RAW_MODBUS_AUTHORIZATION_STATES, f"unknown raw Modbus authorization fixture: {authorization_state}")
    return {
        "schema": "raw-modbus-write-rejection-receipt-v1",
        "issue": milestone["id"],
        "request_kind": request_kind,
        "authorization_state": authorization_state,
        "authorization_effect": "NONE",
        "outcome": "UNSUPPORTED",
        "decision_stage": "BEFORE_TRANSPORT_ACCESS",
        "transport_accessed": False,
        "transport_call_count": 0,
        "write_transport_call_count": 0,
        "evidence_provider": f"{milestone['repo']}:{milestone['id']}:exact-head-evidence",
        "signer_role": "independent-issue-verifier",
    }


def expected_raw_write_fixtures(milestone: dict[str, Any], provider: str) -> list[dict[str, Any]]:
    require(issue_exposes_raw_modbus(milestone), f"raw write fixtures requested for non-raw issue: {milestone['id']}")
    fixtures: list[dict[str, Any]] = []
    for request_kind, function_code_hex in RAW_MODBUS_WRITE_REQUESTS:
        for authorization_state in RAW_MODBUS_AUTHORIZATION_STATES:
            fixtures.append({
                "fixture_id": f"{milestone['id']}-REJECT-RAW-WRITE-{request_kind}-{authorization_state}",
                "input": {
                    "source_head": "EXACT",
                    "raw_modbus_request": {
                        "request_kind": request_kind,
                        "function_code_hex": function_code_hex,
                        "authorization_state": authorization_state,
                    },
                },
                "expected_output": None,
                "expected_failure": "UNSUPPORTED",
                "expected_receipt": raw_write_rejection_receipt(milestone, request_kind, authorization_state),
                "evidence_provider": provider,
            })
    return fixtures


def expected_failure_fixture_multiplicity(milestone: dict[str, Any]) -> dict[str, int]:
    return {
        row["error_code"]: (len(RAW_MODBUS_WRITE_REQUESTS) * len(RAW_MODBUS_AUTHORIZATION_STATES) if row["error_code"] == "UNSUPPORTED" else 1)
        for row in expected_issue_failure_outcomes(milestone)
    }


def expected_issue_limits(milestone: dict[str, Any]) -> dict[str, Any]:
    behavior_class = issue_behavior_class(milestone)
    common = {"normative_schema": "behavior-specific-normative-limits-v2", "behavior_class": behavior_class, "scope": milestone["scope"]}
    limits: dict[str, Any]
    if behavior_class == "modbus_pdu":
        limits = {
            "specification": "MODBUS-Application-Protocol-V1.1b3",
            "specification_url": "https://modbus.org/docs/Modbus_Application_Protocol_V1_1b3.pdf",
            "max_pdu_bytes": 253,
            "supported_function_codes_hex": ["01", "02", "03", "04"],
            "max_read_bits_fc01_fc02": 2000,
            "max_read_registers_fc03_fc04": 125,
            "write_supported": False,
            "register_address_min": 0,
            "register_address_max": 65535,
            "exception_function_or_mask_hex": "80",
            "allowed_exception_codes_hex": ["01", "02", "03", "04"],
            **raw_write_rejection_limits(milestone),
        }
    elif behavior_class == "modbus_tcp":
        limits = {"mbap_header_bytes": 7, "protocol_id": 0, "max_adu_bytes": 260, "transaction_id_bits": 16, "unit_id_bytes": 1, "partial_or_uncertain_stream_retry": "forbidden"}
    elif behavior_class == "modbus_rtu":
        limits = {"max_adu_bytes": 256, "crc_bytes": 2, "server_address_min": 1, "server_address_max": 247, "broadcast_address": 0, "minimum_inter_frame_chars": 3.5, "same_frame_retry_after_partial": "forbidden"}
    elif behavior_class == "repository_governance":
        visibility = "public" if "public" in milestone["scope"] else "private"
        limits = {"required_visibility": visibility, "default_branch": "main", "merge_strategy": "squash-only", "max_open_issue_pr_cycles_per_repo": 1, "branch_delete_after_merge": True}
    elif behavior_class == "protocol_documentation":
        limits = {"max_unattributed_protocol_claims": 0, "required_public_license": "permissive", "source_provenance_required": True, "generated_example_drift": 0, "restricted_source_bytes_in_public_output": 0}
    elif behavior_class == "private_binding":
        limits = {"public_source_detail_exports": 0, "canonical_input_manifest_required": True, "generic_binding_preserved": True, "private_repo_visibility": "private", "unsupported_capability_advertisement": "forbidden"}
    elif behavior_class == "home_assistant_consumer":
        limits = {"graphql_major_version": 1, "breaking_entity_unique_id_changes": 0, "unsupported_entity_advertisements": 0, "stale_entity_retention": "explicit-unavailable", "poll_failure_wholesale_replace": "forbidden"}
    elif behavior_class == "release_activation":
        limits = {"authoritative_active_records": 1, "durable_immediate_predecessor_backups": 1, "atomic_publish_required": True, "directory_fsync_required": True, "rollback_target": "immediate-durable-predecessor", "max_unverified_objects": 0}
    elif behavior_class == "profile_registry":
        limits = {"duplicate_profile_ids": 0, "unbounded_register_ranges": 0, "unsupported_profile_advertisement": "forbidden", "exact_source_epoch_required": True, "non_go_rows_retained": True}
    elif behavior_class == "canonical_semantics":
        limits = {"enabled_capabilities": ["pv.v1"], "breaking_schema_changes": 0, "non_destructive_merge_required": True, "unsupported_domains_retained": ["hvac", "dhw"], "major_version": 1}
    elif behavior_class == "gateway_api":
        limits = {**raw_write_rejection_limits(milestone), "breaking_api_changes": 0, "source_provenance_required": True, "unbounded_endpoint_routes": 0}
    elif behavior_class == "gateway_runtime":
        limits = {**raw_write_rejection_limits(milestone), "unbounded_workers": 0, "per_endpoint_circuit_breaker_required": True, "partial_failure_wholesale_replace": "forbidden", "transport_factory_bypass": 0, "exact_profile_epoch_required": True}
    else:
        limits = {"missing_mandatory_gates": 0, "shadow_authority_paths": 0, "unresolved_external_blockers_allowed_at_lock": 0, "required_route_complexity": 10, "required_route_effort": "max"}
    if issue_exposes_raw_modbus(milestone):
        limits = {**limits, **raw_write_rejection_limits(milestone)}
    return {**common, **limits}


