def markdown_without_generated_block(markdown: str, plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_8_contracts"]["generated_mirrors"]
    return re.sub(re.escape(contract["begin_marker"]) + r".*?" + re.escape(contract["end_marker"]), "", markdown, flags=re.DOTALL)


def generated_json_label(markdown: str, label: str) -> Any:
    matches = re.findall(rf"(?m)^{re.escape(label)}: `(.*)`$", markdown)
    require(len(matches) == 1, f"generated label cardinality drift: {label}")
    return json.loads(matches[0])


def plan_metrics_display_text(plan: dict[str, Any]) -> str:
    metric = plan["plan_metrics"]
    fields = [
        ("executable-issues", "executable_issue_count"),
        ("depends-on-edges", "artifact_dependency_edge_count"),
        ("conditional-artifact-edges", "conditional_artifact_edge_count"),
        ("schedule-edges", "schedule_edge_count"),
        ("lane-schedule-edges", "lane_schedule_edge_count"),
        ("serialized-repo-lanes", "serialized_repo_lane_count"),
        ("canonical-gates", "canonical_gate_count"),
        ("direct-gate-edges", "direct_gate_consumer_edge_count"),
        ("cross-repo-artifact-edges", "cross_repo_artifact_edge_count"),
        ("justified-non-gate-edges", "justified_non_gate_edge_count"),
        ("pre-execution-intent-rows", "pre_execution_intent_row_count"),
        ("simulation-cases", "simulation_case_count"),
        ("mutation-cases", "mutation_case_count"),
        ("supplemental-artifact-consumption-edges", "supplemental_artifact_consumption_edge_count"),
        ("promoted-typed-artifact-edges", "promoted_typed_artifact_edge_count"),
        ("ta6-mcdc-pairs", "ta6_mcdc_pair_count"),
        ("ta6-dispatched-mutants", "ta6_dispatched_mutant_count"),
        ("ta6-killed-mutants", "ta6_killed_mutant_count"),
    ]
    require(all(key in metric for _, key in fields), "Plan-Metrics source field missing")
    return "; ".join(f"{label}={metric[key]}" for label, key in fields)


def parse_eebus_lineage_prose(prose: str) -> dict[str, bool]:
    normalized = re.sub(r"\s+", " ", prose).strip()
    lower = normalized.lower()
    manifest_binding = all(token in lower for token in ["fmb-08eebus-a", "signed fmb-07a manifest", "full producer identity"])
    schedule_only = all(token in lower for token in ["fmb-07b", "schedule ordering only", "no artifact to fmb-08eebus-a"])
    choice_owner = bool(re.search(r"\bFMB-08EEBUS\s+(?:owns|selects)", normalized))
    wrong_owner = bool(re.search(r"\bFMB-08EEBUS-A\s+(?:owns|selects|chooses|conditionally consumes)[^.]{0,180}(?:extension|genesis|FMB-07B)", normalized, re.I))
    return {
        "manifest_binding": manifest_binding,
        "schedule_only": schedule_only,
        "choice_owner": choice_owner,
        "wrong_owner": wrong_owner,
    }


def expected_roadmap_chunk_contract(plan: dict[str, Any]) -> dict[str, Any]:
    return {
        "schema": "indexed-roadmap-chunk-declarations-v1",
        "file": "13-roadmap-issues-risks.md",
        "chunk_index": 13,
        "index_file": "01-index.md",
        "index_link": "[13-roadmap-issues-risks.md](./13-roadmap-issues-risks.md)",
        "begin_marker": "<!-- ROADMAP_CHUNK_DECLARATIONS_BEGIN -->",
        "end_marker": "<!-- ROADMAP_CHUNK_DECLARATIONS_END -->",
        "declaration_order": ["scope", "idempotence", "falsifiability", "coverage"],
        "declaration_labels": {
            "scope": "Scope",
            "idempotence": "Idempotence contract",
            "falsifiability": "Falsifiability gate",
            "coverage": "Coverage",
        },
        "declarations": {
            "scope": "Defines the plan.yaml-derived milestone roadmap, issue and lane ordering, planning gates, rollback boundaries, risk register, current DRAFT status, and generated execution mirrors.",
            "idempotence": "Regeneration from the same plan.yaml renders byte-identical declarations and preserves artifact ordering independently from schedule ordering; reruns add no issue, edge, gate, or state transition.",
            "falsifiability": "Validation fails if any declaration is missing, duplicated, reordered, not byte-equal to plan.yaml, detached from the index entry, or claims review-clean, lock-ready, or PLAN_LOCK while the package remains DRAFT.",
            "coverage": f"Covers M0A through M9, all {len(plan['milestones'])} executable issues, planning and pre-lock gates, repository lanes, artifact and schedule edges, rollback, risks, current-round repair status, generated mirrors, report checks, and lock blockers.",
        },
        "mutation_classes": ["omission", "duplicate", "reorder", "wrong-value", "index-detachment"],
    }


def render_roadmap_chunk_contract(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_12_contracts"]["targeted_repair_12b"]["roadmap_chunk"]
    lines = [contract["begin_marker"]]
    for key in contract["declaration_order"]:
        lines.append(f"{contract['declaration_labels'][key]}: {contract['declarations'][key]}")
    lines.append(contract["end_marker"])
    return "\n\n".join(lines)


def validate_roadmap_chunk_contract(markdown: str, index_markdown: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_12_contracts"]["targeted_repair_12b"]["roadmap_chunk"]
    require(contract == expected_roadmap_chunk_contract(plan), "Terminal Repair 12b roadmap chunk authority drift")
    begin = contract["begin_marker"]
    end = contract["end_marker"]
    require(markdown.count(begin) == markdown.count(end) == 1, "roadmap chunk declaration marker cardinality drift")
    match = re.search(re.escape(begin) + r".*?" + re.escape(end), markdown, re.DOTALL)
    require(match is not None and match.group(0) == render_roadmap_chunk_contract(plan), "roadmap chunk declarations differ from plan.yaml authority")
    require(index_markdown.count(contract["index_link"]) == 1, "roadmap chunk is detached from its unique index entry")
    observed_labels = re.findall(r"(?m)^(Scope|Idempotence contract|Falsifiability gate|Coverage):", match.group(0))
    expected_labels = [contract["declaration_labels"][key] for key in contract["declaration_order"]]
    require(observed_labels == expected_labels, "roadmap chunk declaration omission/duplicate/order drift")


