def validate_audit_12_current_round_state(markdown: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_12_contracts"]["targeted_repair_12b"]["current_round"]
    require(contract == expected_audit_12_current_round_contract(plan), "Terminal Repair 12b / Audit 12 current-round authority drift")
    for begin, end, rendered, label in [
        (contract["header_begin_marker"], contract["header_end_marker"], render_audit_12_current_round_header(plan), "header"),
        (contract["ledger_begin_marker"], contract["ledger_end_marker"], render_audit_12_current_round_ledger(plan), "ledger"),
    ]:
        require(markdown.count(begin) == markdown.count(end) == 1, f"Audit 12 current-round {label} marker cardinality drift")
        match = re.search(re.escape(begin) + r".*?" + re.escape(end), markdown, re.DOTALL)
        require(match is not None and match.group(0) == rendered, f"Audit 12 current-round {label} differs from plan.yaml authority")
    status = plan["planning_status"]
    require(status.get("terminal_repair_12b_findings") == contract["finding_ids"] and status.get("terminal_audit_12_findings") == contract["finding_ids"], "Audit 12 current-round planning-status finding set drift")
    require(status.get("terminal_repair_12b_state") == contract["state"] and status.get("terminal_audit_12_state") == contract["state"], "Audit 12 current-round planning-status state drift")
    if plan["state"] == "draft":
        require(status["review_clean"] is False and status["lock_ready"] is False and status["terminal_review"] == "pending" and status["plan_lock"] == "pending_unauthorized", "Audit 12 current-round DRAFT/lock status drift")
    else:
        require(plan["state"] == "locked" and status["review_clean"] is True and status["lock_ready"] is True and status["terminal_review"] == "complete" and status["plan_lock"] == "authorized_locked", "Audit 12 current-round locked-candidate transition drift")


