def render_manual_lock_prerequisites(plan: dict[str, Any]) -> str:
    contract = plan.get("terminal_repair_15_contracts", {}).get(
        "lock_block_sensitivity",
        plan["terminal_repair_13_contracts"]["lock_prerequisites"],
    )
    return "\n".join([contract["begin_marker"], contract["canonical_statements"][0], contract["end_marker"]])


def manual_lock_prerequisite_paragraphs(markdown: str, plan: dict[str, Any]) -> list[str]:
    return [paragraph for paragraph in manual_markdown_paragraphs(markdown, plan) if is_sensitive_plan_lock_paragraph(paragraph, plan)]


def validate_manual_lock_prerequisites(markdowns: dict[str, str], plan: dict[str, Any]) -> None:
    contract = plan.get("terminal_repair_15_contracts", {}).get("lock_block_sensitivity", plan.get("terminal_repair_14_contracts", {}).get("lock_assertion_blocks", plan["terminal_repair_13_contracts"]["lock_prerequisites"]))
    if "terminal_repair_15_contracts" in plan:
        require(contract == expected_terminal_repair_15_contract(plan)["lock_block_sensitivity"], "Terminal Repair 15 lock sensitivity authority drift")
    elif "terminal_repair_14_contracts" in plan:
        require(contract == expected_lock_assertion_block_contract(plan), "Terminal Repair 14 lock assertion authority drift")
    else:
        require(contract == expected_lock_prerequisite_contract(), "Terminal Repair 13 lock prerequisite authority drift")
    allowed = canonical_normalized_statement_set(contract)
    require(set(contract["manual_files"]) <= set(markdowns), "manual lock prerequisite canonical files missing")
    for name in contract["manual_files"]:
        markdown = markdowns[name]
        manual_markdown = markdown_without_generated_block(markdown, plan)
        begin, end = contract["begin_marker"], contract["end_marker"]
        require(manual_markdown.count(begin) == manual_markdown.count(end) == 1, f"manual lock prerequisite marker cardinality drift: {name}")
        match = re.search(re.escape(begin) + r".*?" + re.escape(end), manual_markdown, re.DOTALL)
        require(match is not None and match.group(0) == render_manual_lock_prerequisites(plan), f"manual lock prerequisite differs from machine authority: {name}")
        require(manual_lock_prerequisite_paragraphs(markdown, plan), f"manual lock prerequisite paragraph missing: {name}")
    for name, markdown in sorted(markdowns.items()):
        for paragraph in manual_lock_prerequisite_paragraphs(markdown, plan):
            require(paragraph in allowed, f"noncanonical sensitive manual PLAN_LOCK paragraph: {name}: {paragraph}")


