def canonical_coverage_authority(canonical_markdown: str) -> dict[str, Any]:
    invariant_match = re.search(r"(?ms)^## Architectural Invariants\s*$\n(.*?)(?=^## )", canonical_markdown)
    require(invariant_match is not None, "canonical invariant section missing")
    invariant_ids = [int(value) for value in re.findall(r"(?m)^(\d+)\.\s", invariant_match.group(1))]
    require(invariant_ids and invariant_ids == list(range(1, invariant_ids[-1] + 1)), "canonical invariant IDs are not exact contiguous authority")
    decision_match = re.search(r"(?ms)^## Decision Matrix\s*$\n(.*?)(?=^## |\Z)", canonical_markdown)
    require(decision_match is not None, "canonical decision matrix missing")
    decision_numbers = [int(value) for value in re.findall(r"(?m)^\| AD(\d+) \|", decision_match.group(1))]
    require(decision_numbers and decision_numbers == list(range(1, decision_numbers[-1] + 1)), "canonical AD IDs are not exact contiguous authority")
    decision_ids = [f"AD{number:02d}" for number in decision_numbers]
    return {
        "invariants": {
            "first": invariant_ids[0], "last": invariant_ids[-1], "count": len(invariant_ids),
            "ids_sha256": sha(canonical_json(invariant_ids).encode()),
        },
        "architecture_decisions": {
            "first": decision_ids[0], "last": decision_ids[-1], "count": len(decision_ids),
            "ids_sha256": sha(canonical_json(decision_ids).encode()),
        },
    }


