def render_terminal_repair_14_header(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_14_contracts"]["current_round"]
    labels = {"plan_state": "Plan state", "current_revision": "Current revision", "current_round": "Current round", "review_clean": "Review clean", "lock_ready": "Lock ready", "authoritative_plan_lock": "Authoritative PLAN_LOCK"}
    order = ["plan_state", "current_revision", "current_round", "review_clean", "lock_ready", "authoritative_plan_lock"]
    return "\n".join([contract["header_begin_marker"], *[f"{labels[key]}: `{contract['header_values'][key]}`" for key in order], contract["header_end_marker"]])


def render_terminal_repair_14_ledger(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_14_contracts"]["current_round"]
    lines = [contract["ledger_begin_marker"], "## Terminal Repair 14 Closure Ledger", "", "| Finding | Executable closure | Mandatory check | Status |", "| --- | --- | --- | --- |"]
    lines.extend(f"| {row['finding']} | {row['closure']} | `{row['mandatory_check']}` | {row['status']} |" for row in contract["rows"])
    lines.append(contract["ledger_end_marker"])
    return "\n".join(lines)


def validate_terminal_repair_14_current_round(markdown: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_14_contracts"]["current_round"]
    checks = [(contract["ledger_begin_marker"], contract["ledger_end_marker"], render_terminal_repair_14_ledger(plan), "ledger")]
    if "terminal_repair_15_contracts" not in plan:
        checks.insert(0, (contract["header_begin_marker"], contract["header_end_marker"], render_terminal_repair_14_header(plan), "header"))
    for begin, end, rendered, label in checks:
        require(markdown.count(begin) == markdown.count(end) == 1, f"Terminal Repair 14 {label} marker cardinality drift")
        match = re.search(re.escape(begin) + r".*?" + re.escape(end), markdown, re.DOTALL)
        require(match is not None and match.group(0) == rendered, f"Terminal Repair 14 {label} differs from machine authority")
    status = plan["planning_status"]
    require(status.get("terminal_repair_14_findings") == plan["terminal_repair_14_contracts"]["finding_ids"] and status.get("terminal_repair_14_state") == plan["terminal_repair_14_contracts"]["state"], "Terminal Repair 14 planning status drift")


