def parse_canonical_report_bytes(raw: bytes, label: str) -> dict[str, Any]:
    value = strict_json_loads(raw, label)
    require(isinstance(value, dict) and raw == canonical_json(value).encode(), f"{label} JSON is not canonical")
    return value


def validate_selected_profile_live_report(report: dict[str, Any], contract: dict[str, Any], verified_inputs: dict[str, Any]) -> None:
    fields = {"schema", "target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256", "selected_profile_ids", "profile_results", "test_results", "status"}
    require(set(report) == fields and report["schema"] == contract["live_report_schema"] and report["status"] == "PASS", "selected-profile live report schema/status drift")
    for field in ["target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256"]:
        require(report[field] == verified_inputs[field], f"selected-profile live report stale binding: {field}")
    selected = verified_inputs["selected_profile_ids"]
    require(report["selected_profile_ids"] == selected and selected == sorted(set(selected)) and selected, "selected-profile live report selected set drift")
    require(report["profile_results"] == [{"profile_id": profile_id, "status": "PASS", "measurement_count": 1} for profile_id in selected] and all(isinstance(row["measurement_count"], int) and not isinstance(row["measurement_count"], bool) for row in report["profile_results"]), "selected-profile live report profile coverage/result drift")
    require(report["test_results"] == [{"test_id": test_id, "status": "PASS"} for test_id in contract["live_required_tests"]], "selected-profile live report required test drift")


def validate_selected_profile_slo_report(report: dict[str, Any], contract: dict[str, Any], verified_inputs: dict[str, Any], run_id: str) -> None:
    fields = {"schema", "run_id", "target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256", "selected_profile_ids", "profile_metrics", "ebus_p95_regression_percent", "recovery_bound_met", "status"}
    require(set(report) == fields and report["schema"] == contract["slo_report_schema"] and report["run_id"] == run_id and report["status"] == "PASS", "selected-profile SLO report schema/run/status drift")
    for field in ["target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256"]:
        require(report[field] == verified_inputs[field], f"selected-profile SLO report stale binding: {field}")
    selected = verified_inputs["selected_profile_ids"]
    require(report["selected_profile_ids"] == selected and selected == sorted(set(selected)) and selected, "selected-profile SLO selected set drift")
    thresholds = contract["slo_thresholds"]
    metrics = report["profile_metrics"]
    numeric = lambda value: isinstance(value, (int, float)) and not isinstance(value, bool) and math.isfinite(value)
    require(isinstance(metrics, list) and [item.get("profile_id") for item in metrics] == selected and all(set(item) == {"profile_id", "scheduled_polls", "healthy_polls_within_2x_percent"} and isinstance(item["scheduled_polls"], int) and not isinstance(item["scheduled_polls"], bool) and item["scheduled_polls"] >= thresholds["minimum_scheduled_polls_per_profile"] and numeric(item["healthy_polls_within_2x_percent"]) and thresholds["healthy_polls_within_2x_percent_min"] <= item["healthy_polls_within_2x_percent"] <= 100 for item in metrics), "selected-profile SLO profile coverage/type/range/threshold drift")
    require(numeric(report["ebus_p95_regression_percent"]) and 0 <= report["ebus_p95_regression_percent"] <= thresholds["ebus_p95_regression_percent_max"] <= 100 and report["recovery_bound_met"] is thresholds["recovery_bound_required"], "selected-profile SLO eBUS/recovery type/range/threshold drift")


def validate_selected_profile_release_evidence(value: dict[str, Any], plan: dict[str, Any], expected_bindings: dict[str, str], verified_inputs: dict[str, Any], registry: dict[str, Any], report_bytes: dict[str, bytes]) -> None:
    contract = plan["terminal_repair_19_contracts"]["selected_profile_release_evidence"]
    require(set(value) == set(contract["exact_fields"]), "selected-profile release evidence field set drift")
    require(value["schema"] == contract["schema"] and value["producer_issue"] == contract["producer_issue"] and value["consumer_issue"] == contract["consumer_issue"], "selected-profile release evidence identity drift")
    require(value["independent_slo_run_count"] == contract["independent_slo_run_count"] and value["signer_id"] == contract["signer_id"], "selected-profile release evidence authority/run-count drift")
    verify_signed(value, registry)
    require(set(verified_inputs) == {"target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256", "selected_profile_ids"}, "selected-profile verified input schema drift")
    require(all(expected_bindings[field] == verified_inputs[field] for field in ["target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256"]), "selected-profile evidence caller bindings differ from verified consumed artifacts")
    for field in contract["binding_fields"]:
        require(value[field] == expected_bindings[field], f"selected-profile release evidence binding mismatch: {field}")
    for field in contract["digest_fields"]:
        require(isinstance(value[field], str) and re.fullmatch(r"[0-9a-f]{64}", value[field]) is not None, f"selected-profile release evidence digest invalid: {field}")
    receipts = [value["live_receipt"], *value["slo_run_receipts"]]
    require(len(value["slo_run_receipts"]) == value["independent_slo_run_count"] == 3, "selected-profile SLO receipt count drift")
    require(len({item["run_id"] for item in receipts}) == len(receipts) and len({item["execution_identity"] for item in receipts}) == len(receipts), "selected-profile run identities are not independent")
    previous_end: datetime | None = None
    for index, receipt in enumerate(receipts):
        expected_schema = contract["live_receipt_schema"] if index == 0 else contract["slo_receipt_schema"]
        expected_ordinal = 0 if index == 0 else index
        require(set(receipt) == set(contract["receipt_exact_fields"]) and receipt["schema"] == expected_schema and receipt["run_ordinal"] == expected_ordinal and receipt["status"] == contract["receipt_status"] and receipt["signer_id"] == contract["signer_id"], "selected-profile run receipt schema/status/ordinal drift")
        for field in ["target_head_sha", "selected_profile_set_sha256", "canonical_catalog_sha256", "candidate_image_sha256"]:
            require(receipt[field] == expected_bindings[field], f"selected-profile run receipt binding mismatch: {field}")
        started = parse_utc(receipt["started_at"])
        completed = parse_utc(receipt["completed_at"])
        require(started < completed and (previous_end is None or started >= previous_end), "selected-profile run intervals overlap or are unordered")
        previous_end = completed
        require(receipt["run_id"] in report_bytes and sha(report_bytes[receipt["run_id"]]) == receipt["report_sha256"], "selected-profile referenced report bytes do not match receipt")
        verify_signed(receipt, registry)
        parsed_report = parse_canonical_report_bytes(report_bytes[receipt["run_id"]], f"selected-profile report {receipt['run_id']}")
        if index == 0:
            validate_selected_profile_live_report(parsed_report, contract, verified_inputs)
        else:
            validate_selected_profile_slo_report(parsed_report, contract, verified_inputs, receipt["run_id"])
    require(value["live_conformance_report_sha256"] == value["live_receipt"]["report_sha256"], "selected-profile live report digest is detached from receipt")
    require(value["three_run_slo_report_sha256"] == sha(canonical_json(value["slo_run_receipts"]).encode()), "selected-profile SLO aggregate digest is detached from signed receipts")
    binding_payload = {field: value[field] for field in contract["binding_fields"]}
    binding_payload.update({"live_receipt_sha256": sha(canonical_json(value["live_receipt"]).encode()), "slo_receipts_sha256": sha(canonical_json(value["slo_run_receipts"]).encode())})
    expected_digest = sha(canonical_json(binding_payload).encode())
    require(value["bindings_sha256"] == expected_digest, "selected-profile release aggregate binding mismatch")


