def validate_public_release_license_closure(value: dict[str, Any], plan: dict[str, Any], registry: dict[str, Any]) -> None:
    contract = plan["public_release_license_contract"]
    require(contract == expected_public_release_license_contract(), "public release license contract drift")
    require(set(value) == set(contract["closure_exact_fields"]) and value["schema"] == contract["closure_schema"] and value["signer_id"] == contract["signer_id"] and value["compatibility_result"] == contract["required_result"], "public license closure schema/result/signer drift")
    reports = value["reports"]
    require(isinstance(reports, list) and [item.get("repo") for item in reports] == sorted(contract["required_spdx_by_repo"]) and value["reports_sha256"] == sha(canonical_json(reports).encode()), "public license closure repository coverage/digest drift")
    for report in reports:
        require(set(report) == set(contract["report_exact_fields"]) and report["schema"] == contract["report_schema"] and report["signer_id"] == contract["signer_id"] and report["compatibility_result"] == contract["required_result"], "public repository license report schema/result/signer drift")
        require(report["spdx_expression"] == contract["required_spdx_by_repo"][report["repo"]] and report["spdx_expression"] in contract["allowed_spdx_expressions"], "public repository SPDX expression missing, unknown, denied, or incompatible")
        require(COMMIT_RE.match(report["source_head_sha"]) and all(HEX64_RE.match(report[field]) and report[field] != "0" * 64 for field in ["license_text_sha256", "sbom_sha256", "provenance_sha256"]), "public repository license/SBOM/provenance identity drift")
        verify_signed(report, registry)
    verify_signed(value, registry)


