def render_terminal_repair_23_header(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_23_contracts"]
    values = contract["header_values"]
    return "\n".join([contract["header_begin_marker"], f"Plan state: `{values['plan_state']}`", f"Current revision: `{values['current_revision']}`", f"Current round: `{values['current_round']}`", f"Review clean: `{values['review_clean']}`", f"Lock ready: `{values['lock_ready']}`", f"Authoritative PLAN_LOCK: `{values['authoritative_plan_lock']}`", contract["header_end_marker"]])


def render_terminal_repair_23_ledger(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_23_contracts"]
    lines = [contract["ledger_begin_marker"], "## Terminal Repair 23 / Audit 23 Closure Ledger", "", "| Finding | Severity | Executable closure | Mandatory check | Status |", "| --- | --- | --- | --- | --- |"]
    lines.extend(f"| {row['finding']} | {row['severity']} | {row['closure']} | `{row['mandatory_check']}` | {row['status']} |" for row in contract["rows"])
    lines.append(contract["ledger_end_marker"])
    return "\n".join(lines)


def render_terminal_repair_23_canonical_contract(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_23_contracts"]
    payload = {key: contract[key] for key in ["schema", "finding_ids", "final_release", "rollback", "selected_profile_release_binding", "critical_execution", "emma_deferral"]}
    return "\n".join([contract["canonical_begin_marker"], "## Terminal Repair 23 / Audit 23 Contract", "", f"Machine contract: `{canonical_json(payload)}`", contract["canonical_end_marker"]])


def validate_terminal_repair_23_current_round(review: str, canonical: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_23_contracts"]
    require(contract == expected_terminal_repair_23_contract(plan), "Terminal Repair 23 machine contract drift")
    for text, begin, end, rendered, label in [
        (review, contract["header_begin_marker"], contract["header_end_marker"], render_terminal_repair_23_header(plan), "header"),
        (review, contract["ledger_begin_marker"], contract["ledger_end_marker"], render_terminal_repair_23_ledger(plan), "ledger"),
        (canonical, contract["canonical_begin_marker"], contract["canonical_end_marker"], render_terminal_repair_23_canonical_contract(plan), "canonical contract"),
    ]:
        require(text.count(begin) == text.count(end) == 1, f"Terminal Repair 23 {label} marker cardinality drift")
        match = re.search(re.escape(begin) + r".*?" + re.escape(end), text, re.DOTALL)
        require(match is not None and match.group(0) == rendered, f"Terminal Repair 23 {label} differs from machine authority")


def validate_final_release_closure_v3(value: dict[str, Any], plan: dict[str, Any], registry: dict[str, Any], object_root: Path, producer_issue: str, consumer_issue: str, expected_binding: dict[str, Any], verified_license_closure: dict[str, Any], verified_repository_inputs: list[dict[str, Any]]) -> None:
    contract = plan["terminal_repair_23_contracts"]["final_release"]
    validate_public_release_license_closure(verified_license_closure, plan, registry)
    require(set(value) == set(contract["closure_fields"]) and value["schema"] == contract["closure_schema"], "final release closure v3 field/schema drift")
    require(value["producer_issue"] == producer_issue and value["consumer_issue"] == consumer_issue and value["stage"] == "FINAL_AFTER_EXACT_VALIDATION", "final release closure issue/stage drift")
    license_reports = verified_license_closure["reports"]
    require(isinstance(verified_repository_inputs, list) and [row["repo"] for row in verified_repository_inputs] == sorted(plan["public_release_license_contract"]["required_spdx_by_repo"]), "verified repository input coverage/order drift")
    reports_by_repo = {row["repo"]: row for row in license_reports}
    expected_rows = []
    for source in verified_repository_inputs:
        report = reports_by_repo[source["repo"]]
        expected_rows.append({
            "repo": source["repo"], "head_sha": source["head_sha"], "tree_sha256": source["tree_sha256"],
            "spdx_expression": report["spdx_expression"], "license_text_sha256": report["license_text_sha256"],
            "lockfile_sha256": source["lockfile_sha256"], "source_sbom_sha256": report["sbom_sha256"],
            "source_provenance_sha256": report["provenance_sha256"],
        })
        require(report["source_head_sha"] == source["head_sha"], f"verified public-license HEAD detached: {source['repo']}")
        validate_content_addressed_object(object_root, source["lockfile_sha256"], f"{source['repo']} lockfile")
        source_sbom, _ = parse_canonical_cas_json(object_root, report["sbom_sha256"], f"{source['repo']} source SBOM")
        source_provenance, _ = parse_canonical_cas_json(object_root, report["provenance_sha256"], f"{source['repo']} source provenance")
        require(source_sbom == {"schema": contract["source_sbom_schema"], "repo": source["repo"], "source_head_sha": source["head_sha"], "components": [], "complete": True}, f"{source['repo']} source SBOM schema/HEAD drift")
        require(source_provenance == {"schema": contract["source_provenance_schema"], "repo": source["repo"], "source_head_sha": source["head_sha"], "materials_sha256": source["tree_sha256"]}, f"{source['repo']} source provenance schema/HEAD/tree drift")
    repository_rows = value["repository_rows"]
    require(repository_rows == expected_rows and all(set(row) == set(contract["repo_row_fields"]) for row in repository_rows), "final release repository/license input join drift")
    objects = value["objects"]
    require(set(objects) == set(contract["required_objects"]), "final release object set drift")
    object_bytes = {name: validate_content_addressed_object(object_root, digest, f"final release {name}") for name, digest in objects.items()}
    sbom, _ = parse_canonical_cas_json(object_root, objects["sbom"], "canonical release SBOM")
    provenance, _ = parse_canonical_cas_json(object_root, objects["provenance"], "canonical release provenance")
    binding = value["release_binding"]
    require(set(binding) == set(contract["binding_fields"]) and binding == expected_binding and binding["schema"] == contract["binding_schema"], "signed release-binding tuple drift")
    verify_signed(binding, registry)
    require(binding["image_sha256"] == objects["image"] and binding["embedded_manifest_sha256"] == objects["embedded_manifest"] and binding["sbom_sha256"] == objects["sbom"] and binding["provenance_sha256"] == objects["provenance"] and binding["validation_artifact_sha256"] == objects["validation_artifact"], "release-binding object join drift")
    require(binding["repository_rows_sha256"] == sha(canonical_json(repository_rows).encode()) and binding["public_license_closure_sha256"] == sha(canonical_json(verified_license_closure).encode()), "release-binding repository/license digest drift")
    require(isinstance(binding["release_serial"], int) and not isinstance(binding["release_serial"], bool) and binding["release_serial"] > 0, "release serial invalid")
    require(HEX64_RE.fullmatch(binding["predecessor_release_binding_sha256"]) is not None and HEX64_RE.fullmatch(binding["signing_key_state_sha256"]) is not None, "release predecessor/key state omitted")
    require(isinstance(binding["persistent_schema_range"], list) and len(binding["persistent_schema_range"]) == 2 and all(isinstance(item, int) and not isinstance(item, bool) for item in binding["persistent_schema_range"]) and binding["persistent_schema_range"][0] <= binding["persistent_schema_range"][1], "release persistent schema range invalid")
    require(set(sbom) == set(contract["sbom_fields"]) and sbom["schema"] == contract["sbom_schema"], "canonical SBOM schema drift")
    components = [{"name": row["repo"], "head_sha": row["head_sha"], "tree_sha256": row["tree_sha256"], "spdx_expression": row["spdx_expression"], "license_text_sha256": row["license_text_sha256"], "lockfile_sha256": row["lockfile_sha256"], "source_sbom_sha256": row["source_sbom_sha256"], "source_provenance_sha256": row["source_provenance_sha256"]} for row in repository_rows]
    require(all(set(row) == set(contract["component_fields"]) for row in sbom["components"]), "canonical SBOM component schema drift")
    require(sbom == {"schema": contract["sbom_schema"], "release_id": binding["release_id"], "version": binding["version"], "image_sha256": objects["image"], "repository_rows": repository_rows, "repository_rows_sha256": binding["repository_rows_sha256"], "components": components, "component_count": len(components), "complete": True}, "canonical SBOM subject/component completeness drift")
    receipt_entries = value["clean_builder_receipts"]
    require(isinstance(receipt_entries, list) and all(set(entry) == set(contract["builder_entry_fields"]) for entry in receipt_entries), "clean builder receipt entry schema drift")
    receipt_digests = []
    for index, entry in enumerate(receipt_entries, 1):
        receipt, _ = parse_canonical_cas_json(object_root, entry["receipt_object_sha256"], f"clean builder receipt {index}")
        require(set(receipt) == set(contract["builder_receipt_fields"]) and receipt == entry["receipt"] and receipt["result"] == "PASS" and receipt["signer_id"] == contract["signer_id"], "clean builder receipt bytes/schema/result/signer drift")
        verify_signed(receipt, registry)
        receipt_digests.append(entry["receipt_object_sha256"])
    require(len(receipt_digests) >= 2 and len({(row["receipt"]["builder_id"], row["receipt"]["build_root_sha256"], row["receipt"]["environment_sha256"]) for row in receipt_entries}) == len(receipt_entries), "clean builder receipt independence drift")
    expected_subjects = sorted(
        [{"name": name, "sha256": objects[name]} for name in ["image", "sbom", "validation_artifact"]]
        + [{"name": f"clean_builder_receipt_{index}", "sha256": digest} for index, digest in enumerate(receipt_digests, 1)],
        key=lambda row: row["name"],
    )
    require(set(provenance) == set(contract["provenance_fields"]) and provenance["schema"] == contract["provenance_schema"], "canonical provenance schema drift")
    require(provenance == {"schema": contract["provenance_schema"], "release_id": binding["release_id"], "version": binding["version"], "subjects": expected_subjects, "clean_builder_receipt_sha256": receipt_digests, "source_head_tree_set": [{"repo": row["repo"], "head_sha": row["head_sha"], "tree_sha256": row["tree_sha256"]} for row in repository_rows], "source_head_tree_set_sha256": sha(canonical_json([{"repo": row["repo"], "head_sha": row["head_sha"], "tree_sha256": row["tree_sha256"]} for row in repository_rows]).encode()), "validation_artifacts": [objects["validation_artifact"]], "predecessor_release_binding_sha256": binding["predecessor_release_binding_sha256"], "signing_key_state_sha256": binding["signing_key_state_sha256"], "persistent_schema_range": binding["persistent_schema_range"]}, "canonical provenance subjects/source/validation/state join drift")
    manifest = parse_canonical_report_bytes(object_bytes["embedded_manifest"], "embedded release manifest")
    require(manifest == {
        "schema": "embedded-public-release-manifest-v3", "release_id": binding["release_id"], "version": binding["version"],
        "release_serial": binding["release_serial"], "image_sha256": objects["image"], "sbom_sha256": objects["sbom"],
        "provenance_sha256": objects["provenance"], "validation_artifact_sha256": objects["validation_artifact"],
        "repository_rows_sha256": binding["repository_rows_sha256"], "public_license_closure_sha256": binding["public_license_closure_sha256"],
        "predecessor_release_binding_sha256": binding["predecessor_release_binding_sha256"], "signing_key_state_sha256": binding["signing_key_state_sha256"],
        "persistent_schema_range": binding["persistent_schema_range"], "successor_selected_profile_binding_sha256": binding["successor_selected_profile_binding_sha256"],
    }, "embedded manifest release tuple/object join drift")
    require(value["closure_sha256"] == sha(canonical_json({key: item for key, item in value.items() if key not in {"closure_sha256", "signature", "revocation_generation"}}).encode()), "final release closure self digest drift")
    verify_signed(value, registry)


def resolve_committed_activation_wal(wal: dict[str, Any], registry: dict[str, Any], plan: dict[str, Any]) -> tuple[dict[str, Any], dict[str, Any], str, str]:
    contract = plan["terminal_repair_23_contracts"]["rollback"]
    require(set(wal) == {"schema", "ledger_id", "store_id", "state", "records", "records_sha256", "head_record_sha256", "signer_id", "revocation_generation", "signature"} and wal["schema"] == contract["wal_schema"] and wal["state"] == "COMMITTED" and wal["signer_id"] == "release-activation-wal-authority", "activation WAL schema/state/signer drift")
    records = wal["records"]
    require(isinstance(records, list) and len(records) >= 2 and wal["records_sha256"] == sha(canonical_json(records).encode()), "activation WAL record coverage/digest drift")
    predecessor_digest = "GENESIS"
    for sequence, record in enumerate(records, 1):
        require(set(record) == {"schema", "sequence", "predecessor_record_sha256", "transition", "release_tuple", "state_schema", "signer_id", "revocation_generation", "signature"} and record["schema"] == contract["activation_record_schema"], "activation WAL record schema drift")
        require(record["sequence"] == sequence and record["predecessor_record_sha256"] == predecessor_digest and record["transition"] == "ACTIVATION_COMMITTED" and record["signer_id"] == "release-activation-wal-authority", "activation WAL chain/transition/signer drift")
        verify_signed(record, registry)
        predecessor_digest = sha(canonical_json(record).encode())
    require(wal["head_record_sha256"] == predecessor_digest, "activation WAL torn/stale head")
    verify_signed(wal, registry)
    current, predecessor = records[-1], records[-2]
    return current, predecessor, sha(canonical_json(current).encode()), sha(canonical_json(predecessor).encode())


def validate_authoritative_rollback_token(token: dict[str, Any], wal: dict[str, Any], ledger: dict[str, Any], now: datetime, registry: dict[str, Any], plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_23_contracts"]["rollback"]
    current, predecessor, current_sha, predecessor_sha = resolve_committed_activation_wal(wal, registry, plan)
    require(set(token) == set(contract["token_fields"]) and token["schema"] == contract["token_schema"] and token["signer_id"] == "offline-release-rollback-root", "authoritative rollback token schema/root drift")
    validate_authoritative_rollback_ledger(ledger, registry, plan)
    require(token["ledger_id"] == ledger["ledger_id"] == wal["ledger_id"] and token["store_id"] == ledger["store_id"] == wal["store_id"], "rollback ledger/store identity drift")
    require(ledger["active_record_sha256"] == current_sha and ledger["active_tuple"] == current["release_tuple"], "rollback authority ledger is detached from committed active WAL state")
    require(token["current_active_record_sha256"] == current_sha and token["predecessor_record_sha256"] == predecessor_sha and token["current_tuple"] == current["release_tuple"] and token["target_tuple"] == predecessor["release_tuple"], "rollback current/immediate predecessor binding drift")
    require(token["generation"] == ledger["generation"] and token["high_water"] == ledger["high_water"], "rollback generation/high-water drift")
    schema_range = token["state_schema_range"]
    require(isinstance(schema_range, list) and len(schema_range) == 2 and all(isinstance(item, int) and not isinstance(item, bool) for item in schema_range) and schema_range[0] <= predecessor["state_schema"] <= schema_range[1], "rollback target schema incompatibility")
    require(token["reason"] in contract["allowed_reasons"] and re.fullmatch(r"[A-Za-z0-9._:-]{16,128}", token["nonce"]) is not None and parse_utc(token["issued_at"]) <= now < parse_utc(token["expiry"]), "rollback reason/nonce/validity drift")
    verify_signed(token, registry)
    return sha(canonical_json(token).encode())


def validate_authoritative_rollback_ledger(ledger: dict[str, Any], registry: dict[str, Any], plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_23_contracts"]["rollback"]
    require(set(ledger) == set(contract["ledger_fields"]) and ledger["schema"] == contract["ledger_schema"] and ledger["signer_id"] == "rollback-store-cas-authority", "authoritative rollback ledger schema/signer drift")
    require(isinstance(ledger["generation"], int) and ledger["generation"] >= 0 and ledger["high_water"] == ledger["generation"] and len(ledger["records"]) == ledger["generation"], "rollback ledger generation/high-water drift")
    require(len(ledger["consumed_token_sha256"]) == len(set(ledger["consumed_token_sha256"])) == len(ledger["consumed_nonces"]) == len(set(ledger["consumed_nonces"])), "rollback consumed identity drift")
    require(len(ledger["consumed_token_sha256"]) == len(ledger["records"]), "rollback consumed identity/record cardinality drift")
    for sequence, record in enumerate(ledger["records"], 1):
        require(set(record) == set(contract["record_fields"]) and record["schema"] == contract["record_schema"] and record["ledger_id"] == ledger["ledger_id"] and record["store_id"] == ledger["store_id"], "rollback committed record schema/store drift")
        require(record["generation"] == record["high_water"] == sequence and record["transition"] == "ROLLBACK_COMMITTED", "rollback committed record sequence/high-water/transition drift")
        require(record["token_sha256"] == ledger["consumed_token_sha256"][sequence - 1] and record["nonce"] == ledger["consumed_nonces"][sequence - 1], "rollback record/consumption ledger drift")
        verify_signed(record, registry)
    if ledger["records"]:
        require(ledger["active_record_sha256"] == ledger["records"][-1]["active_record_sha256"] and ledger["active_tuple"] == ledger["records"][-1]["active_tuple"], "rollback ledger active state detached from committed record")
    else:
        require(ledger["predecessor_ledger_sha256"] == "GENESIS", "rollback genesis ledger is not authority-rooted")
    verify_signed(ledger, registry)


def validate_authoritative_rollback_transition(ledger: dict[str, Any], token: dict[str, Any], token_sha256: str, updated: dict[str, Any], cas_receipt: dict[str, Any], authoritative_store_state: dict[str, Any], registry: dict[str, Any], plan: dict[str, Any], expected_generation: int, expected_high_water: int) -> dict[str, Any]:
    contract = plan["terminal_repair_23_contracts"]["rollback"]
    validate_authoritative_rollback_ledger(ledger, registry, plan)
    require(set(authoritative_store_state) == {"store_id", "ledger_sha256", "generation", "high_water", "applied_operation_ids"}, "rollback authoritative store state schema drift")
    require(isinstance(authoritative_store_state["applied_operation_ids"], list) and len(authoritative_store_state["applied_operation_ids"]) == len(set(authoritative_store_state["applied_operation_ids"])), "rollback authoritative store operation ledger drift")
    require(authoritative_store_state["store_id"] == ledger["store_id"] and authoritative_store_state["ledger_sha256"] == sha(canonical_json(ledger).encode()) and authoritative_store_state["generation"] == ledger["generation"] and authoritative_store_state["high_water"] == ledger["high_water"], "rollback caller supplied a cloned or stale ledger outside authoritative store state")
    require(ledger["generation"] == expected_generation and ledger["high_water"] == expected_high_water, "rollback signed CAS generation/high-water conflict")
    require(token_sha256 == sha(canonical_json(token).encode()) and token_sha256 not in ledger["consumed_token_sha256"] and token["nonce"] not in ledger["consumed_nonces"], "rollback token/nonce replay across generation or reopen")
    predecessor_ledger_sha = sha(canonical_json(ledger).encode())
    generation = ledger["generation"] + 1
    high_water = ledger["high_water"] + 1
    require(set(updated) == set(contract["ledger_fields"]), "rollback next ledger field set drift")
    require(updated["ledger_id"] == ledger["ledger_id"] and updated["store_id"] == ledger["store_id"] and updated["generation"] == generation and updated["high_water"] == high_water and updated["predecessor_ledger_sha256"] == predecessor_ledger_sha, "rollback next ledger CAS identity/counter/predecessor drift")
    require(updated["records"][:-1] == ledger["records"] and updated["consumed_token_sha256"] == [*ledger["consumed_token_sha256"], token_sha256] and updated["consumed_nonces"] == [*ledger["consumed_nonces"], token["nonce"]], "rollback next ledger append-only consumption drift")
    record = updated["records"][-1]
    require(record["predecessor_ledger_sha256"] == predecessor_ledger_sha and record["token_sha256"] == token_sha256 and record["nonce"] == token["nonce"] and record["prior_active_record_sha256"] == token["current_active_record_sha256"] and record["active_record_sha256"] == token["predecessor_record_sha256"] and record["active_tuple"] == token["target_tuple"], "rollback committed record token/active transition drift")
    validate_authoritative_rollback_ledger(updated, registry, plan)
    require(set(cas_receipt) == set(contract["cas_receipt_fields"]) and cas_receipt["schema"] == contract["cas_receipt_schema"] and cas_receipt["signer_id"] == "rollback-store-cas-authority", "rollback store CAS receipt schema/signer drift")
    require(cas_receipt["ledger_id"] == ledger["ledger_id"] and cas_receipt["store_id"] == ledger["store_id"] and cas_receipt["expected_predecessor_ledger_sha256"] == predecessor_ledger_sha and cas_receipt["expected_generation"] == expected_generation and cas_receipt["expected_high_water"] == expected_high_water, "rollback store CAS receipt predecessor/counter drift")
    require(cas_receipt["token_sha256"] == token_sha256 and cas_receipt["new_ledger_sha256"] == sha(canonical_json(updated).encode()) and cas_receipt["new_generation"] == generation and cas_receipt["new_high_water"] == high_water and cas_receipt["result"] == "APPLIED", "rollback store CAS receipt transition/result drift")
    require(isinstance(cas_receipt["operation_id"], str) and re.fullmatch(r"[A-Za-z0-9._:-]{16,128}", cas_receipt["operation_id"]) is not None, "rollback store CAS operation identity invalid")
    require(cas_receipt["operation_id"] not in authoritative_store_state["applied_operation_ids"], "rollback store CAS operation replay")
    verify_signed(cas_receipt, registry)
    authoritative_store_state.update(ledger_sha256=cas_receipt["new_ledger_sha256"], generation=generation, high_water=high_water)
    authoritative_store_state["applied_operation_ids"].append(cas_receipt["operation_id"])
    return record


def validate_rollback_boot_receipt(receipt: dict[str, Any], ledger: dict[str, Any], registry: dict[str, Any], plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_23_contracts"]["rollback"]
    require(set(receipt) == set(contract["boot_receipt_fields"]) and receipt["schema"] == contract["boot_receipt_schema"] and receipt["signer_id"] == "boot-migration-verifier", "rollback startup receipt schema/signer drift")
    require(receipt["ledger_id"] == ledger["ledger_id"] and receipt["store_id"] == ledger["store_id"] and receipt["ledger_generation"] == ledger["generation"] and receipt["active_record_sha256"] == ledger["active_record_sha256"] and receipt["active_tuple_sha256"] == sha(canonical_json(ledger["active_tuple"]).encode()), "rollback startup receipt active state drift")
    require(receipt["state_schema"] == ledger["active_tuple"]["state_schema"] and receipt["boot_result"] == receipt["migration_result"] == "PASS", "rollback startup boot/migration result drift")
    verify_signed(receipt, registry)


def validate_selected_profile_release_binding(value: dict[str, Any], expected: dict[str, Any], object_root: Path, registry: dict[str, Any], plan: dict[str, Any], now: datetime) -> str:
    contract = plan["terminal_repair_23_contracts"]["selected_profile_release_binding"]
    require(set(value) == set(contract["binding_fields"]) and value["schema"] == contract["schema"] and value["signer_id"] == contract["signer_id"], "selected-profile release binding schema/signer drift")
    for field in [name for name in contract["binding_fields"] if name not in {"schema", "receipt_objects", "receipt_set_sha256", "signer_id", "revocation_generation", "signature"}]:
        require(value[field] == expected[field], f"selected-profile joined release field drift: {field}")
    require(value["producer_issue"] == contract["output_issue"] and value["consumer_issue"] == contract["input_issue"], "selected-profile release issue ownership drift")
    require(COMMIT_RE.fullmatch(value["target_head_sha"]) is not None and HEX64_RE.fullmatch(value["loaded_profile_digest_sha256"]) is not None and isinstance(value["loaded_profile_version"], str) and value["loaded_profile_version"], "selected-profile direct HEAD/version/digest identity invalid")
    for field in contract["artifact_object_fields"]:
        validate_content_addressed_object(object_root, value[field], f"selected-profile joined artifact {field}")
    receipts = []
    for row in value["receipt_objects"]:
        require(set(row) == {"kind", "sha256"}, "selected-profile receipt object row drift")
        receipt, _ = parse_canonical_cas_json(object_root, row["sha256"], f"selected-profile {row['kind']} receipt")
        require(set(receipt) == set(contract["receipt_fields"]) and receipt["schema"] == contract["receipt_schema"] and receipt["receipt_kind"] == row["kind"] and receipt["signer_id"] == "selected-profile-receipt-runner", "selected-profile receipt schema/kind/signer drift")
        require(receipt["target_head_sha"] == expected["target_head_sha"] and receipt["loaded_profile_digest_sha256"] == expected["loaded_profile_digest_sha256"] and receipt["loaded_profile_version"] == expected["loaded_profile_version"] and receipt["status"] == "PASS", "selected-profile receipt head/profile/status drift")
        require(all(receipt[field] == expected[field] for field in ["endpoint_id", "downstream_id", "gateway", "model", "firmware", "map_issue"]), "selected-profile receipt endpoint/gateway identity drift")
        require(parse_utc(receipt["interval_start"]) < parse_utc(receipt["interval_end"]) and now - parse_utc(receipt["interval_end"]) <= timedelta(hours=1), "selected-profile receipt interval stale/invalid")
        require(receipt["work_root_sha256"] != receipt["cache_root_sha256"], "selected-profile receipt work/cache alias")
        report, _ = parse_canonical_cas_json(object_root, receipt["report_sha256"], f"selected-profile {row['kind']} report")
        require(report == {"schema": "selected-profile-runtime-report-v1", "receipt_kind": row["kind"], "target_head_sha": expected["target_head_sha"], "loaded_profile_version": expected["loaded_profile_version"], "loaded_profile_digest_sha256": expected["loaded_profile_digest_sha256"], "status": "PASS"}, "selected-profile receipt report bytes/binding drift")
        verify_signed(receipt, registry)
        receipts.append(receipt)
    require([row["kind"] for row in value["receipt_objects"]] == contract["receipt_kinds"] and value["receipt_set_sha256"] == sha(canonical_json(value["receipt_objects"]).encode()), "selected-profile receipt kind/set drift")
    for left, right in itertools.combinations(receipts, 2):
        require(all(left[field] != right[field] for field in contract["pairwise_independent_fields"]), "selected-profile receipt pairwise independence drift")
        require((left["host_id"], left["boot_id"], left["process_id"], left["container_id"]) != (right["host_id"], right["boot_id"], right["process_id"], right["container_id"]), "selected-profile duplicate runtime identity")
    verify_signed(value, registry)
    return sha(canonical_json(value).encode())


def render_predicate_operator_docs(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_15_contracts"]["predicate_operator_docs"]
    return "\n".join([
        contract["heading"], "", contract["begin_marker"],
        f"Predicate operators: `{canonical_json(contract['predicate_operators'])}`",
        f"Action operators: `{canonical_json(contract['action_operators'])}`",
        contract["end_marker"],
    ])


def validate_predicate_operator_docs(markdown: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_15_contracts"]["predicate_operator_docs"]
    markdown = markdown_without_generated_block(markdown, plan)
    begin, end = contract["begin_marker"], contract["end_marker"]
    require(markdown.count(contract["heading"]) == markdown.count(begin) == markdown.count(end) == 1, "predicate operator docs heading/marker cardinality drift")
    match = re.search(re.escape(contract["heading"]) + r".*?" + re.escape(end), markdown, re.DOTALL)
    require(match is not None and match.group(0) == render_predicate_operator_docs(plan), "predicate operator docs differ from generated machine schema")
    predicate_values = re.findall(r"(?m)^Predicate operators: `([^`]+)`$", match.group(0))
    action_values = re.findall(r"(?m)^Action operators: `([^`]+)`$", match.group(0))
    require(len(predicate_values) == len(action_values) == 1, "predicate operator docs list cardinality drift")
    require(json.loads(predicate_values[0]) == plan["predicate_action_schema"]["predicate_operators"], "predicate operator Markdown/schema parity drift")
    require(json.loads(action_values[0]) == plan["predicate_action_schema"]["action_operators"], "action operator Markdown/schema parity drift")


def render_terminal_repair_13_header(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_13_contracts"]["current_round"]
    labels = {"plan_state": "Plan state", "current_revision": "Current revision", "current_round": "Current round", "review_clean": "Review clean", "lock_ready": "Lock ready", "authoritative_plan_lock": "Authoritative PLAN_LOCK"}
    order = ["plan_state", "current_revision", "current_round", "review_clean", "lock_ready", "authoritative_plan_lock"]
    return "\n".join([contract["header_begin_marker"], *[f"{labels[key]}: `{contract['header_values'][key]}`" for key in order], contract["header_end_marker"]])


def render_terminal_repair_13_ledger(plan: dict[str, Any]) -> str:
    contract = plan["terminal_repair_13_contracts"]["current_round"]
    lines = [contract["ledger_begin_marker"], "## Terminal Repair 13 Closure Ledger", "", "| Finding | Executable closure | Mandatory check | Status |", "| --- | --- | --- | --- |"]
    lines.extend(f"| {row['finding']} | {row['closure']} | `{row['mandatory_check']}` | {row['status']} |" for row in contract["rows"])
    lines.append(contract["ledger_end_marker"])
    return "\n".join(lines)


def validate_terminal_repair_13_current_round(markdown: str, plan: dict[str, Any]) -> None:
    contract = plan["terminal_repair_13_contracts"]["current_round"]
    begin, end = contract["ledger_begin_marker"], contract["ledger_end_marker"]
    require(markdown.count(begin) == markdown.count(end) == 1, "Terminal Repair 13 ledger marker cardinality drift")
    match = re.search(re.escape(begin) + r".*?" + re.escape(end), markdown, re.DOTALL)
    require(match is not None and match.group(0) == render_terminal_repair_13_ledger(plan), "Terminal Repair 13 ledger differs from machine authority")
    status = plan["planning_status"]
    require(status.get("terminal_repair_13_findings") == plan["terminal_repair_13_contracts"]["finding_ids"] and status.get("terminal_repair_13_state") == plan["terminal_repair_13_contracts"]["state"], "Terminal Repair 13 planning status drift")


def validate_plan_lock_prerequisite_sequence(plan: dict[str, Any]) -> None:
    expected = ["PG-ARCHITECTURE-MAP-AMENDMENT", "PG-MODEL-ROUTING-POLICY-AMENDMENT", "PG-SKILL-ADAPTER-REGISTRY"]
    ordered_chain = [*expected, "PG-FRESH-TERMINAL-REVIEW", "PG-CRUISE-LOCK"]
    prose = " -> ".join(ordered_chain) + "."
    contract = plan["terminal_repair_12_contracts"]["plan_lock_chain"]
    require(contract == {"schema": "ordered-plan-lock-chain-v1", "external_prerequisite_count": 3, "external_prerequisite_ids": expected, "ordered_gate_chain": ordered_chain, "lock_prose": prose, "source": "planning_gates"}, "Terminal Repair 12 prerequisite chain contract drift")
    metadata = next(item for item in plan["external_planning_artifacts"] if item["id"] == "EXTERNAL-LOCK-METADATA-V1")
    require(metadata["schema"] == "external-lock-metadata-v5" and metadata["metadata_version"] == 5, "external lock metadata identity/version drift")
    require(metadata["required_fields"] == EXTERNAL_LOCK_METADATA_REQUIRED_FIELDS_V5 and not any("url" in field.lower() for field in metadata["required_fields"]), "external lock metadata exact field order or URL exclusion drift")
    gate_ids = [gate["id"] for gate in plan["planning_gates"]]
    require(gate_ids == ["PG-DRAFT-CURATION", *ordered_chain], "planning_gates prerequisite omission/extra/order drift")
    by_id = {gate["id"]: gate for gate in plan["planning_gates"]}
    predecessor = "PG-DRAFT-CURATION"
    for gate_id in ordered_chain:
        require(by_id[gate_id]["depends_on"] == [predecessor], f"ordered PLAN_LOCK dependency edge drift: {predecessor}->{gate_id}")
        predecessor = gate_id


def validate_outside_generated_assertions(markdown: str, plan: dict[str, Any], name: str) -> None:
    prose = markdown_without_generated_block(markdown, plan)
    prose_lower = prose.lower()
    stale = [
        "v1.2 Terminal Repair 8", "v1.2-draft-terminal-repair-8", "external-lock-metadata-v4",
        "PASS_OR_EXPLICIT_NA", "catalog/private execution", "full-catalog-and-private-row-execution-v1",
        "After FMB-08A fact classification, FMB-08A-INVENTORY", "display-only adjacency FMB-08A-SCOPE",
        "154 executable", "seven promoted", "9 promoted typed", "promoted-edge count 9",
        "external-lock-metadata-v5 with signed-transport-condition-context-v3",
        "14 phases", "eight components", "13 compatibility components", "seven compatibility phases",
        "helianthus-plan-validation-report-v2 is current", "content-addressed-authoritative-activation-record-v2 is current",
    ]
    require(not any(token in prose for token in stale), f"stale gate/count/execution assertion outside generated block: {name}")
    stale_lower = ["v1.4 terminal repair 10", "review url", "without sha, url", "real artifact url", "only pass supplies predecessor bytes", "fmb-07a/fmb-07b predecessor bytes"]
    require(not any(token in prose_lower for token in stale_lower), f"stale v1.4/gate/URL/eeBUS assertion outside generated block: {name}")
    allowed_lock_statements = canonical_normalized_statement_set(plan["terminal_repair_13_contracts"]["lock_prerequisites"])
    for paragraph in manual_lock_prerequisite_paragraphs(markdown, plan):
        require(paragraph in allowed_lock_statements, f"noncanonical sensitive manual PLAN_LOCK paragraph: {name}: {paragraph}")
    require(re.search(r"FMB-08EEBUS-A\s+(?:conditionally consumes|owns|selects|chooses)[^.]{0,180}(?:FMB-07B|extension|genesis)", prose, re.I) is None, f"eeBUS lineage choice is assigned to FMB-08EEBUS-A outside generated block: {name}")
    metric_lines = re.findall(r"(?m)^Plan-Metrics: `([^`]+)`$", prose)
    if name in {"01-index.md", "99-status.md"}:
        require(metric_lines == [plan_metrics_display_text(plan)], f"complete Plan-Metrics header drift: {name}")
    else:
        require(len(metric_lines) <= 1 and (not metric_lines or metric_lines[0] == plan_metrics_display_text(plan)), f"unexpected Plan-Metrics header drift: {name}")
    for match in re.finditer(r"\b(\d+)\s+(?:executable\s+)?issues?\b", prose, re.I):
        require(int(match.group(1)) == len(plan["milestones"]), f"contradictory executable issue count outside generated block: {name}")
    for pattern in [r"\b(\d+)\s+executable milestones?\b", r"\b(?:all\s+)?(\d+)\s+milestones?\b", r"\b(?:one of\s+)?(\d+)\s+intent rows?\b"]:
        for match in re.finditer(pattern, prose, re.I):
            require(int(match.group(1)) == len(plan["milestones"]), f"contradictory milestone/intent count outside generated block: {name}")
    for pattern in [r"\b(\d+)\s+unique cross-repository artifact edges?\b", r"\b(\d+)\s+direct gate edges?\b"]:
        for match in re.finditer(pattern, prose, re.I):
            require(int(match.group(1)) == plan["plan_metrics"]["cross_repo_artifact_edge_count"], f"contradictory cross-repository edge count outside generated block: {name}")
    for match in re.finditer(r"(?:promoted[^\n]{0,40}?\b(\d+)\b|\b(\d+)\b[^\n]{0,40}?promoted(?: typed)?(?: artifact)? edges?)", prose, re.I):
        value = next(int(group) for group in match.groups() if group is not None)
        require(value == len(promoted_edge_triplets()), f"contradictory promoted-edge count outside generated block: {name}")
    allowed_edges = artifact_edges(plan["milestones"]) | schedule_edges(plan["milestones"]) | lane_schedule_edges(plan)
    for source, target in re.findall(r"(FMB-[0-9A-Z]+(?:-[0-9A-Z]+)*)\s*->\s*(FMB-[0-9A-Z]+(?:-[0-9A-Z]+)*)", prose):
        require((source, target) in allowed_edges, f"contradictory executable order outside generated block: {name}:{source}->{target}")
    for match in re.finditer(r"\b(\d+)\s+compatibility components?\b", prose, re.I):
        require(int(match.group(1)) == 14, f"contradictory compatibility component count outside generated block: {name}")
    for match in re.finditer(r"\b(\d+)\s+compatibility phases?\b", prose, re.I):
        require(int(match.group(1)) == 8, f"contradictory compatibility phase count outside generated block: {name}")


def preflight_example_document(plan: dict[str, Any]) -> dict[str, Any]:
    zero = "0" * 64
    head = "a" * 40
    row_template = {
        "status": "GREEN", "repo": "helianthus-modbus", "milestone": "FMB-02A", "issue": "FMB-02A", "branch": "issue/1-fmb-02a",
        "batch_id": "batch-example", "target_object_id": head, "target_repo_head_sha": head,
        "dependency_closure_sha256": zero, "provider_query_id": "ROW_SPECIFIC_QUERY_ID", "semantic_result_sha256": zero,
        "evidence_artifact_type": plan["preflight_evidence_contract"]["schema"], "evidence_artifact_path": "/cruise-state/preflight/row.json", "evidence_artifact_sha256": zero,
    }
    rows = {name: {**row_template, "provider_query_id": plan["preflight_evidence_contract"]["provider_query_map"][name]} for name in plan["preflight_evidence_contract"]["row_types"]}
    authorization = {
        "schema": "signed-preflight-authorization-v1", "signer_id": "preflight-gate", "signed_at": "2026-07-11T12:00:00Z",
        "envelope_sha256": zero, "draft_payload_sha256": zero, "locked_payload_sha256": zero,
        "lock_transform_manifest_sha256": zero, "final_locked_commit_oid": head, "route_records": [],
        "route_records_sha256": zero, "pre_execution_intents_sha256": plan["pre_execution_intents_sha256"],
        "risk_classes": ["protocol"], "risk_classes_sha256": sha(canonical_json(["protocol"]).encode()),
        "revocation_generation": 1, "signature": "BASE64_ED25519_SIGNATURE",
    }
    return {"preflight": {"status": "green", "mode": "single", "rows": rows, "authorization": authorization}, "next_skill": "cruise-dev-supervise"}


def validate_hash_triplet(root: Path, plan: dict[str, Any]) -> None:
    require(plan["canonical_sha256"] == sha(normalized_markdown_bytes((root / plan["canonical_file"]).read_bytes())), "canonical_sha256 mismatch")
    require(plan["pre_execution_matrix_sha256"] == sha(normalized_markdown_bytes((root / plan["pre_execution_matrix"]).read_bytes())), "pre_execution_matrix_sha256 mismatch")
    require(plan["topology_edges_sha256"] == sha(topology_bytes(plan)), "topology_edges_sha256 mismatch")


def locate_mutation_target(value: Any, locator: str) -> tuple[Any, str | int]:
    parts = locator.split(".")
    current = value
    for part in parts[:-1]:
        current = current[int(part)] if isinstance(current, list) else current[part]
    leaf: str | int = int(parts[-1]) if isinstance(current, list) else parts[-1]
    return current, leaf


def apply_ta6_locator_mutation(plan: dict[str, Any], mutation: dict[str, Any]) -> None:
    parent, leaf = locate_mutation_target(plan, mutation["locator"])
    operation = mutation["operator"]
    if operation == "replace":
        parent[leaf] = copy.deepcopy(mutation["replacement"])
    elif operation == "delete":
        del parent[leaf]
    elif operation == "swap":
        left, right = mutation["replacement"]
        target = parent[leaf]
        require(isinstance(target, list), "TA6 swap locator did not resolve to a list")
        target[left], target[right] = target[right], target[left]
    else:
        raise ValidationError(f"unknown TA6 locator mutation operator: {operation}")


def validate_ta6_target(plan: dict[str, Any], target: str) -> None:
    c6 = plan["terminal_repair_6_contracts"]
    expected_domains = {"hvac", "dhw", "energy", "solar"}
    if target == "lock_digest_pair":
        require(c6["lock_digest_pair"]["pre_cas"] == "validate-complete-unreferenced-locked-tree-before-ref-advance", "TA6-lock-digest-pair")
    elif target == "profile_scope_decision":
        require(plan["topology_oracle_contract"]["live_rejects_fixture_only_inputs"] is True, "TA6-live-profile-override")
    elif target == "huawei_epoch":
        require(c6["huawei_live_binding"]["epoch_ledger"]["monotonic"] == "strictly-increasing-and-single-consumption", "TA6-Huawei-epoch-monotonic")
    elif target == "route_output":
        require(plan["execution_mode_contract"]["current_role_mismatch_matrix"]["planner"] == {"resolved_profile": "planner_primary", "resolved_model": "gpt-5.6-sol", "resolved_effort": "max", "mismatch": False}, "TA6-route-matrix")
    elif target == "tdd_consumption":
        require(c6["tdd_consumption"]["caller_bare_digest_or_epoch"] == "forbidden", "TA6-TDD-bare-digest")
    elif target == "provisioning":
        require(c6["provisioning"]["row_fields"] == ["repo", "visibility", "outcome", "provider_evidence_digest_sha256"], "TA6-provisioning-row-fields")
    elif target == "skill_harness":
        require(plan["terminal_repair_7_contracts"]["skill_compatibility"]["arbitrary_harness_result"] == "forbidden", "TA6-skill-harness")
    elif target == "architecture_semantics":
        require("rs485-modbus-assigned-to-sunspec" in c6["architecture_semantics"]["contradiction_classes"], "TA6-architecture-contradictions")
    elif target == "cas_receipt":
        require(c6["cas_receipt"]["signer_id"] == "cruise-state-sync", "TA6-CAS-signer")
    elif target == "runtime_registration":
        require({row["domain"] for row in plan["canonical_domain_inputs"]["runtime_registrations"]["entries"]} == expected_domains, "TA6-runtime-domain-equality")
    elif target == "domain_inventory":
        require({row["domain"] for row in plan["canonical_catalog_contract"]["rows"]} == expected_domains, "TA6-catalog-inventory")
    elif target == "release_wal":
        order = c6["release_wal"]["activation_order"]
        require(order == plan["terminal_repair_10_contracts"]["activation_wal"]["activation_order"] and order.index("atomic-publish-backup-record") < order.index("write-active-record-temp") and order.index("fsync-active-record-temp") < order.index("atomic-publish-active-record"), "TA6-WAL-order")
    elif target == "transport_intent":
        require(plan["transport_intents"]["FMB-02R-A"] == [{"family": "MODBUS_RTU", "when": "ALWAYS"}], "TA6-transport-condition")
    elif target == "issue_contract":
        try:
            validate_issue_execution_contract(plan, next(item for item in plan["milestones"] if item["id"] == "FMB-00D"), plan["issue_machine_contracts"]["contracts"]["FMB-00D"])
        except ValidationError:
            raise ValidationError("TA6-issue-contract")
    elif target == "mcdc":
        require(c6["mcdc_vectors"][0]["changed_condition"] == "fact_GO", "TA6-MCDC-vector")
    elif target == "preflight_evidence":
        require(c6["provisioning"]["schema"] and plan["preflight_evidence_contract"]["authority_kind_enum"][0] == "git-workflow-authority", "TA6-preflight-authority")
    elif target == "neutral_scope":
        require(all(row["fact_scope"] == "none" for row in plan["profile_candidate_inventory"]["rows"] if row["vendor"] != "Huawei"), "TA6-neutral-Huawei")
    elif target == "write_fsm":
        require(c6["write_fsm"]["partial_timeout_or_uncertain"].startswith("close-fence"), "TA6-write-fsm")
    else:
        raise ValidationError(f"unknown TA6 targeted validation: {target}")


def local_checkout_path(paths: dict[str, Path], repo: str) -> Path:
    local_name = "helianthus-org-github" if repo == "helianthus-org-github" else repo
    return (paths["workspace"] / local_name).resolve()


def signed_provider_verdict(path: Path, registry: dict[str, Any], signer: str, now: datetime) -> dict[str, Any]:
    require(path.is_file() and not path.is_symlink(), "preflight provider verdict artifact missing")
    value = json.loads(path.read_text())
    required = {"schema", "status", "repo", "milestone", "target_repo_head_sha", "result", "issued_at", "expiry", "signer_id", "revocation_generation", "signature"}
    require(set(value) == required and value["schema"] == "canonical-preflight-provider-verdict-v1" and value["signer_id"] == signer, "preflight provider verdict schema/signer drift")
    require(parse_utc(value["issued_at"]) <= now <= parse_utc(value["expiry"]), "preflight provider verdict stale or future")
    verify_signed(value, registry)
    return value


def replay_preflight_row(row_type: str, input_path: Path) -> bytes:
    value = json.loads(input_path.read_text())
    plan_root = Path(value.get("package_root", "")).resolve()
    plan = load_yaml((plan_root / "plan.yaml").read_text())
    contract = plan["terminal_repair_8_contracts"]["preflight"]
    require(set(value) == set(contract["replay_input_fields"]) and value["schema"] == contract["replay_input_schema"] and value["row_type"] == row_type, "preflight replay input fields drift")
    require(value["provider_query_id"] == plan["preflight_evidence_contract"]["provider_query_map"][row_type], "preflight provider query is not canonical")
    paths = derive_authority_paths(plan_root)
    require(Path(value["workspace_root"]).resolve() == paths["workspace"], "preflight alternate workspace root rejected")
    milestone = next((item for item in plan["milestones"] if item["id"] == value["milestone"]), None)
    require(milestone is not None and value["issue"] == milestone["id"] and milestone["repo"] == value["repo"] and COMMIT_RE.match(value["target_object_id"]) and COMMIT_RE.match(value["target_repo_head_sha"]), "preflight replay target drift")
    payload = value["authority_payload"]
    fixture_mode = isinstance(payload, dict) and payload.get("fixture_mode") == "draft_isolated"
    require(not fixture_mode or plan["state"] == "draft", "isolated preflight fixture mode forbidden for locked/live validation")
    target_repo = Path(payload["fixture_repo_path"]).resolve() if fixture_mode and "fixture_repo_path" in payload else local_checkout_path(paths, value["repo"])
    now, clock_mode = resolve_replay_clock(value["clock"], plan)
    semantic_status = "FAIL"
    result: dict[str, Any]
    if row_type == "routing":
        if set(payload) == {"provider_verdict_path", "registry_path", "fixture_mode", "fixture_repo_path"}:
            require(fixture_mode and clock_mode == "FIXTURE", "routing fixture authority is allowed only in deterministic fixture mode")
            registry = json.loads(Path(payload["registry_path"]).read_text())
            verdict = signed_provider_verdict(Path(payload["provider_verdict_path"]), registry, plan["preflight_evidence_contract"]["authority_signer_map"]["routing"], now)
            roles = verdict["result"].get("roles", [])
            required_roles = set(plan["execution_mode_contract"]["required_roles"])
            semantic_status = "PASS" if verdict["status"] == "PASS" and {row.get("role") for row in roles} == required_roles and all(row.get("vendor") == "openai" and row.get("model") == "gpt-5.6-sol" and row.get("effort") == "max" and row.get("fallback") is False for row in roles) else "FAIL"
            result = verdict["result"]
        else:
            require(set(payload) == set() or (fixture_mode and set(payload) <= {"fixture_mode", "fixture_repo_path"}), "routing replay payload drift")
            matrix, outputs = canonical_route_audit(plan, paths)
            semantic_status = "PASS" if not any(row["mismatch"] for row in matrix.values()) else "FAIL"
            result = {"matrix": matrix, "outputs_sha256": sha(canonical_json(outputs).encode()), "policy_sha256": sha(paths["model_policy"].read_bytes()), "resolver_sha256": sha(paths["model_resolver"].read_bytes())}
    elif row_type == "workflow":
        require(set(payload) <= {"fixture_mode", "fixture_repo_path"}, "workflow replay payload drift")
        if target_repo.is_dir():
            head_probe = subprocess.run(["git", "-C", str(target_repo), "rev-parse", "HEAD"], check=False, text=True, capture_output=True)
            status_probe = subprocess.run(["git", "-C", str(target_repo), "status", "--porcelain"], check=False, text=True, capture_output=True)
            observed_head = head_probe.stdout.strip() if head_probe.returncode == 0 else "MISSING"
            clean = status_probe.returncode == 0 and not status_probe.stdout.strip()
        else:
            observed_head, clean = "MISSING", False
        semantic_status = "PASS" if observed_head == value["target_repo_head_sha"] and clean else "FAIL"
        result = {"repository": str(target_repo), "observed_head": observed_head, "expected_head": value["target_repo_head_sha"], "clean": clean}
    elif row_type in {"doc_gate", "review", "deps"}:
        require(set(payload) == {"provider_verdict_path", "registry_path"}, f"{row_type} replay payload drift")
        registry = json.loads(Path(payload["registry_path"]).read_text())
        signer = plan["preflight_evidence_contract"]["authority_signer_map"][row_type]
        verdict = signed_provider_verdict(Path(payload["provider_verdict_path"]), registry, signer, now)
        semantic_status = "PASS" if verdict["status"] == "PASS" and verdict["repo"] == value["repo"] and verdict["milestone"] == value["milestone"] and verdict["target_repo_head_sha"] == value["target_repo_head_sha"] else "FAIL"
        if row_type == "review":
            semantic_status = "PASS" if semantic_status == "PASS" and verdict["result"].get("finding_count") == 0 else "FAIL"
        elif row_type == "deps":
            expected_dependencies = sorted(milestone["depends_on"] + [edge["source"] for edge in milestone["consumes_if"]])
            artifact_evidence = verdict["result"].get("artifact_evidence")
            try:
                validate_dependency_artifact_evidence(artifact_evidence, milestone, plan, registry, plan["state"] == "draft" and clock_mode == "FIXTURE")
                evidence_valid = True
                artifact_evidence_error = None
            except ValidationError as error:
                evidence_valid = False
                artifact_evidence_error = str(error)
            semantic_status = "PASS" if semantic_status == "PASS" and verdict["result"].get("satisfied_dependencies") == expected_dependencies and evidence_valid else "FAIL"
        elif row_type == "doc_gate":
            semantic_status = "PASS" if semantic_status == "PASS" and verdict["result"].get("required_artifacts_satisfied") is True else "FAIL"
        result = copy.deepcopy(verdict["result"])
        if row_type == "deps" and artifact_evidence_error is not None:
            result["artifact_evidence_validation_error"] = artifact_evidence_error
    elif row_type == "tdd":
        tdd_intent = plan["pre_execution_intents"][milestone["id"]]["tdd"]
        registry = json.loads(Path(payload["registry_path"]).read_text())
        if tdd_intent["mode"] == "planning-gate-exempt":
            require(set(payload) == {"exemption_path", "registry_path"}, "planning-gate TDD exemption replay payload drift")
            require(issue_behavior_class(milestone) == "planning_gate", "TDD exemption is restricted to planning_gate behavior")
            exemption = json.loads(Path(payload["exemption_path"]).read_text())
            required = {"schema", "repo", "issue", "branch", "target_head_sha", "behavior_class", "intent_mode", "expected_paths", "product_implementation", "reason", "issued_at", "expiry", "signer_id", "revocation_generation", "signature"}
            require(set(exemption) == required and exemption["schema"] == "planning-gate-tdd-exemption-v1", "planning-gate TDD exemption schema drift")
            require(exemption["repo"] == milestone["repo"] and exemption["issue"] == milestone["id"] and exemption["branch"] == value["branch"] and exemption["target_head_sha"] == value["target_repo_head_sha"], "planning-gate TDD exemption target drift")
            require(exemption["behavior_class"] == "planning_gate" and exemption["intent_mode"] == "planning-gate-exempt" and exemption["expected_paths"] == tdd_intent["expected_paths"], "planning-gate TDD exemption intent drift")
            require(exemption["product_implementation"] is False and exemption["reason"] == "plan-validation-and-external-attestation-only", "planning-gate TDD exemption widened to product implementation")
            require(parse_utc(exemption["issued_at"]) <= now <= parse_utc(exemption["expiry"]) and exemption["signer_id"] == "tdd-gate", "planning-gate TDD exemption authority/freshness drift")
            verify_signed(exemption, registry)
            semantic_status = "PASS"
            result = {"schema": "planning-gate-tdd-exemption-result-v1", "exemption_sha256": sha(canonical_json(exemption).encode()), "product_implementation": False, "scope": tdd_intent["expected_paths"]}
        elif tdd_intent["mode"] == "docs-exempt":
            require(set(payload) == {"exemption_path", "registry_path", "repo_path"}, "docs-only TDD exemption replay payload drift")
            require(issue_behavior_class(milestone) in {"docs_contract", "protocol_documentation"}, "docs-only TDD exemption used outside documentation behavior")
            repo_path = Path(payload["repo_path"]).resolve()
            require(repo_path.is_dir() and not repo_path.is_symlink(), "docs-only TDD repository missing")
            exemption = json.loads(Path(payload["exemption_path"]).read_text())
            required = {"schema", "repo", "issue", "branch", "target_head_sha", "base_sha", "intent_mode", "expected_paths", "changed_paths", "diff_sha256", "path_policy", "product_implementation", "issued_at", "expiry", "signer_id", "revocation_generation", "signature"}
            require(set(exemption) == required and exemption["schema"] == "docs-only-tdd-exemption-v1", "docs-only TDD exemption schema drift")
            require(exemption["repo"] == milestone["repo"] and exemption["issue"] == milestone["id"] and exemption["branch"] == value["branch"] and exemption["target_head_sha"] == value["target_repo_head_sha"], "docs-only TDD exemption target drift")
            require(exemption["intent_mode"] == "docs-exempt" and exemption["expected_paths"] == tdd_intent["expected_paths"] and exemption["product_implementation"] is False, "docs-only TDD exemption intent widened")
            require(exemption["signer_id"] == "docs-tdd-exemption-gate" and parse_utc(exemption["issued_at"]) <= now <= parse_utc(exemption["expiry"]), "docs-only TDD exemption authority/freshness drift")
            head = git_output(repo_path, "rev-parse", "HEAD")
            base = git_output(repo_path, "rev-parse", "HEAD^")
            changed_paths = git_output(repo_path, "diff", "--name-only", base, head).splitlines()
            diff_bytes = subprocess.run(["git", "-C", str(repo_path), "diff", "--binary", base, head], check=True, capture_output=True).stdout
            docs_path_re = re.compile(r"(?:^|/)(?:docs?/.*\.md|[^/]+\.md|LICENSE(?:\.[A-Za-z0-9.-]+)?)$")
            require(head == exemption["target_head_sha"] and base == exemption["base_sha"] and changed_paths == exemption["changed_paths"] and sha(diff_bytes) == exemption["diff_sha256"], "docs-only TDD Git evidence drift")
            require(changed_paths and all(docs_path_re.fullmatch(path) for path in changed_paths), "docs-only exemption includes executable/parser/generator/fixture/test path")
            require(exemption["path_policy"] == "markdown-or-license-only-v1", "docs-only TDD path policy drift")
            verify_signed(exemption, registry)
            semantic_status = "PASS"
            result = {"schema": "docs-only-tdd-exemption-result-v1", "exemption_sha256": sha(canonical_json(exemption).encode()), "changed_paths": changed_paths, "product_implementation": False}
        else:
            require(tdd_intent["mode"] == "strict", "unsupported TDD preflight mode")
            require(set(payload) == {"unlock_path", "registry_path", "repo_path", "issue_number"}, "strict TDD replay payload drift")
            unlock = json.loads(Path(payload["unlock_path"]).read_text())
            repo_path = Path(payload["repo_path"]).resolve()
            require(repo_path.is_dir() and not repo_path.is_symlink(), "strict TDD replay repository missing")

            def tdd_probe(base: str, red: str, target: str) -> dict[str, Any]:
                ancestry = subprocess.run(["git", "-C", str(repo_path), "merge-base", "--is-ancestor", base, red], check=False).returncode == 0 and subprocess.run(["git", "-C", str(repo_path), "merge-base", "--is-ancestor", red, target], check=False).returncode == 0
                changed_paths = git_output(repo_path, "diff", "--name-only", base, red).splitlines()
                diff_bytes = subprocess.run(["git", "-C", str(repo_path), "diff", "--binary", base, red], check=True, capture_output=True).stdout
                tests_only = bool(changed_paths) and all(re.search(r"(?:^|/)(?:tests?|testdata)/|(?:_test\.go|test_[^/]+\.py|[^/]+_test\.py)$", path) for path in changed_paths)
                return {"ancestry": ancestry, "changed_paths": changed_paths, "diff_bytes": diff_bytes, "no_implementation_before_unlock": target == red and tests_only}

            expected_unlock = {"repo": milestone["repo"], "issue": milestone["id"], "issue_number": payload["issue_number"], "branch": value["branch"], "target_head_sha": value["target_repo_head_sha"]}
            unlock_digest = validate_tdd_unlock(unlock, expected_unlock, plan, registry, now, tdd_probe)
            semantic_status = "PASS"
            result = {"schema": "strict-tdd-preflight-result-v1", "unlock_digest_sha256": unlock_digest, "red_commit_sha": unlock["red_commit_sha"], "ci_result_sha256": unlock["ci_result_sha256"], "git_ancestry_evidence_sha256": unlock["git_ancestry_evidence_sha256"], "tests_only": True, "bypass": "forbidden"}
    elif row_type == "transport_gate":
        require(set(payload) == {"context_path", "registry_path"}, "transport replay payload drift")
        registry = json.loads(Path(payload["registry_path"]).read_text())
        context = json.loads(Path(payload["context_path"]).read_text())
        try:
            derived_context = validate_transport_context(context, plan, registry, now, value["target_repo_head_sha"], value["repo"], value["milestone"], value["transport_validation_phase"])
            dispatch = [{"family": entry["family"], "when": entry["when"], "active": dispatch_transport_condition(entry["when"], derived_context, plan)} for entry in plan["transport_intents"][milestone["id"]]]
            semantic_status = "PASS"
            result = {"dispatch": dispatch, "derived_sets_sha256": derived_context["derived_sets_sha256"], "source_artifact_digests": derived_context["source_artifact_digests"]}
        except ValidationError as error:
            result = {"error": str(error)}
    elif row_type == "smoke":
        require(set(payload) <= {"fixture_mode", "fixture_repo_path", "fixture_smoke_argv"}, "smoke replay payload drift")
        machine = plan["issue_machine_contracts"]["contracts"][milestone["id"]]
        if milestone["smoke"] == "NO":
            semantic_status = "PASS"
            result = {"argv": [], "exit_status": 0, "stdout_sha256": sha(b""), "stderr_sha256": sha(b""), "required": False}
        else:
            argv = payload.get("fixture_smoke_argv", machine["exact_commands"][2])
            if "fixture_smoke_argv" in payload:
                require(fixture_mode and argv == [str((target_repo / "scripts" / "smoke_issue.sh").resolve()), milestone["id"], milestone["acceptance_artifact"]], "smoke fixture argv drift")
            completed = subprocess.run(argv, cwd=target_repo if target_repo.is_dir() else None, check=False, capture_output=True)
            semantic_status = "PASS" if completed.returncode == 0 else "FAIL"
            result = {"argv": argv, "exit_status": completed.returncode, "stdout_sha256": sha(completed.stdout), "stderr_sha256": sha(completed.stderr), "required": True}
    else:
        raise ValidationError(f"unknown preflight replay row: {row_type}")
    output = {
        "schema": "preflight-row-semantic-output-v1", "row_type": row_type, "repo": value["repo"], "milestone": value["milestone"], "issue": value["issue"],
        "branch": value["branch"], "target_object_id": value["target_object_id"], "target_repo_head_sha": value["target_repo_head_sha"],
        "dependency_closure_sha256": value["dependency_closure_sha256"], "provider_query_id": value["provider_query_id"],
        "semantic_status": semantic_status, "result": result,
    }
    require(set(output) == set(plan["preflight_evidence_contract"]["semantic_output_fields"]), "preflight semantic output fields drift")
    return (canonical_json(output) + "\n").encode()


def build_strict_tdd_unlock_fixture(plan: dict[str, Any], registry: dict[str, Any], target: dict[str, Any], repo_path: Path) -> dict[str, Any]:
    head = git_output(repo_path, "rev-parse", "HEAD")
    base = git_output(repo_path, "rev-parse", "HEAD^")
    require(head == target["target_repo_head_sha"], "strict TDD fixture target HEAD drift")
    changed_paths = git_output(repo_path, "diff", "--name-only", base, head).splitlines()
    diff_bytes = subprocess.run(["git", "-C", str(repo_path), "diff", "--binary", base, head], check=True, capture_output=True).stdout
    risks = sorted(target["risk_classes"])
    routes = [route_fixture(role, f"tdd-{target['milestone']}-{role}", registry, target["complexity"], risks, plan["execution_mode_contract"]["canonical_role_queries"][role]["task_kind"]) for role in ["developer", "tester", "gate"]]
    failure_id = f"{target['milestone']}-EXPECTED-RED"
    unsigned = {
        "schema": "tdd-unlock-v1", "repo": target["repo"], "issue": target["milestone"], "issue_number": target["issue_number"], "branch": target["branch"],
        "target_head_sha": head, "base_sha": base, "red_commit_sha": head, "red_parent_sha": base, "first_implementation_parent_sha": head,
        "changed_paths": changed_paths, "red_diff_sha256": sha(diff_bytes), "red_diff_bytes_b64": base64.b64encode(diff_bytes).decode(), "tests_only_policy_version": "tests-only-paths-v1",
        "ci_provider": "fixture-ci", "ci_run_id": f"run-{target['milestone']}", "ci_check_id": f"check-{target['milestone']}", "ci_workflow": "strict-tdd-red", "ci_job": "observe-red",
        "ci_logs_sha256": sha(f"logs:{target['milestone']}".encode()), "ci_result_sha256": sha(f"result:{target['milestone']}:RED".encode()), "ci_observed_red_at": "2026-07-11T10:30:00Z",
        "issued_at": "2026-07-11T11:00:00Z", "expiry": "2026-07-11T20:00:00Z", "expected_failure_id": failure_id, "observed_failure_id": failure_id,
        "git_ancestry_evidence_sha256": sha(canonical_json([base, head, head, changed_paths, sha(diff_bytes)]).encode()), "gate_version": "cruise-tdd-gate-v3", "route_records": routes, "signer_id": "tdd-gate",
    }
    return sign_fixture(unsigned, registry)


def build_planning_gate_tdd_exemption_fixture(plan: dict[str, Any], registry: dict[str, Any], target: dict[str, Any]) -> dict[str, Any]:
    milestone = next(item for item in plan["milestones"] if item["id"] == target["milestone"])
    intent = plan["pre_execution_intents"][milestone["id"]]["tdd"]
    require(issue_behavior_class(milestone) == "planning_gate" and intent["mode"] == "planning-gate-exempt", "planning-gate exemption requested outside exact planning gate")
    return sign_fixture({
        "schema": "planning-gate-tdd-exemption-v1", "repo": milestone["repo"], "issue": milestone["id"],
        "branch": target["branch"], "target_head_sha": target["target_repo_head_sha"], "behavior_class": "planning_gate",
        "intent_mode": intent["mode"], "expected_paths": intent["expected_paths"], "product_implementation": False,
        "reason": "plan-validation-and-external-attestation-only", "issued_at": "2026-07-11T11:00:00Z",
        "expiry": "2026-07-11T20:00:00Z", "signer_id": "tdd-gate",
    }, registry)


def build_docs_only_tdd_exemption_fixture(plan: dict[str, Any], registry: dict[str, Any], target: dict[str, Any], repo_path: Path) -> dict[str, Any]:
    milestone = next(item for item in plan["milestones"] if item["id"] == target["milestone"])
    intent = plan["pre_execution_intents"][milestone["id"]]["tdd"]
    require(issue_behavior_class(milestone) in {"docs_contract", "protocol_documentation"} and intent["mode"] == "docs-exempt", "docs-only exemption requested outside documentation contract")
    head = git_output(repo_path, "rev-parse", "HEAD")
    base = git_output(repo_path, "rev-parse", "HEAD^")
    changed_paths = git_output(repo_path, "diff", "--name-only", base, head).splitlines()
    diff_bytes = subprocess.run(["git", "-C", str(repo_path), "diff", "--binary", base, head], check=True, capture_output=True).stdout
    return sign_fixture({
        "schema": "docs-only-tdd-exemption-v1", "repo": milestone["repo"], "issue": milestone["id"],
        "branch": target["branch"], "target_head_sha": head, "base_sha": base,
        "intent_mode": "docs-exempt", "expected_paths": intent["expected_paths"], "changed_paths": changed_paths,
        "diff_sha256": sha(diff_bytes), "path_policy": "markdown-or-license-only-v1", "product_implementation": False,
        "issued_at": "2026-07-11T11:00:00Z", "expiry": "2026-07-11T20:00:00Z", "signer_id": "docs-tdd-exemption-gate",
    }, registry)


def build_preflight_receipt_rows(plan: dict[str, Any], plan_path: Path, registry: dict[str, Any], registry_path: Path, evidence_dir: Path, target: dict[str, Any], batch_id: str, workflow_repo: Path, review_path: Path, routing_commands: list[list[str]], transport_context_path: Path, transport_validation_phase: str = "RUNTIME_M8", use_fixture_routing_authority: bool = False) -> dict[str, Any]:
    require(not routing_commands, "caller-supplied or shadow routing commands are forbidden")
    plan_root = plan_path.resolve().parent
    paths = derive_authority_paths(plan_root)
    fixture_payload = {"fixture_mode": "draft_isolated", "fixture_repo_path": str(workflow_repo)} if plan["state"] == "draft" else {}
    fixed_now = validate_fixture_clock(fixture_clock_document(plan), plan)
    issued_at = (fixed_now - timedelta(hours=2)).strftime("%Y-%m-%dT%H:%M:%SZ")
    expiry = (fixed_now + timedelta(hours=8)).strftime("%Y-%m-%dT%H:%M:%SZ")
    dependencies = sorted(next(item for item in plan["milestones"] if item["id"] == target["milestone"])["depends_on"] + [edge["source"] for edge in next(item for item in plan["milestones"] if item["id"] == target["milestone"])["consumes_if"]])
    dependency_milestone = next(item for item in plan["milestones"] if item["id"] == target["milestone"])
    dependency_evidence = [deterministic_dependency_evidence(reference, registry) for reference in expected_issue_topology_fields(dependency_milestone, plan)["consumed_artifacts"]]
    provider_results = {
        "routing": {"roles": [{"role": role, "vendor": "openai", "model": "gpt-5.6-sol", "effort": "max", "fallback": False} for role in plan["execution_mode_contract"]["required_roles"]]},
        "doc_gate": {"required_artifacts_satisfied": True},
        "review": {"finding_count": 0},
        "deps": {"satisfied_dependencies": dependencies, "artifact_evidence": dependency_evidence},
    }
    provider_paths: dict[str, Path] = {}
    for row_name, result in provider_results.items():
        if row_name == "routing" and not use_fixture_routing_authority:
            continue
        signer = plan["preflight_evidence_contract"]["authority_signer_map"][row_name]
        verdict = sign_fixture({
            "schema": "canonical-preflight-provider-verdict-v1", "status": "PASS",
            "repo": target["repo"], "milestone": target["milestone"], "target_repo_head_sha": target["target_repo_head_sha"],
            "result": result, "issued_at": issued_at, "expiry": expiry, "signer_id": signer,
        }, registry)
        verdict_path = evidence_dir / f"{target['repo']}-{target['milestone']}-{row_name}-provider.json"
        atomic_write_bytes(verdict_path, (canonical_json(verdict) + "\n").encode())
        provider_paths[row_name] = verdict_path
    routing_payload = {**fixture_payload, "provider_verdict_path": str(provider_paths["routing"]), "registry_path": str(registry_path)} if use_fixture_routing_authority else {}
    tdd_mode = plan["pre_execution_intents"][target["milestone"]]["tdd"]["mode"]
    if tdd_mode == "strict":
        tdd_object = build_strict_tdd_unlock_fixture(plan, registry, target, workflow_repo)
        tdd_path = evidence_dir / f"{target['repo']}-{target['milestone']}-tdd-unlock.json"
        tdd_payload = {"unlock_path": str(tdd_path), "registry_path": str(registry_path), "repo_path": str(workflow_repo), "issue_number": target["issue_number"]}
    elif tdd_mode == "planning-gate-exempt":
        tdd_object = build_planning_gate_tdd_exemption_fixture(plan, registry, target)
        tdd_path = evidence_dir / f"{target['repo']}-{target['milestone']}-tdd-exemption.json"
        tdd_payload = {"exemption_path": str(tdd_path), "registry_path": str(registry_path)}
    else:
        require(tdd_mode == "docs-exempt", "unsupported preflight fixture TDD mode")
        tdd_object = build_docs_only_tdd_exemption_fixture(plan, registry, target, workflow_repo)
        tdd_path = evidence_dir / f"{target['repo']}-{target['milestone']}-docs-tdd-exemption.json"
        tdd_payload = {"exemption_path": str(tdd_path), "registry_path": str(registry_path), "repo_path": str(workflow_repo)}
    atomic_write_bytes(tdd_path, (canonical_json(tdd_object) + "\n").encode())
    payloads: dict[str, dict[str, Any]] = {
        "routing": routing_payload, "workflow": fixture_payload,
        "doc_gate": {"provider_verdict_path": str(provider_paths["doc_gate"]), "registry_path": str(registry_path)},
        "review": {"provider_verdict_path": str(provider_paths["review"]), "registry_path": str(registry_path)},
        "deps": {"provider_verdict_path": str(provider_paths["deps"]), "registry_path": str(registry_path)},
        "transport_gate": {"context_path": str(transport_context_path), "registry_path": str(registry_path)},
        "smoke": fixture_payload, "tdd": tdd_payload,
    }
    rows: dict[str, Any] = {}
    contract = plan["preflight_evidence_contract"]
    for row_name in contract["row_types"]:
        replay_input = {
            "schema": plan["terminal_repair_8_contracts"]["preflight"]["replay_input_schema"], "row_type": row_name,
            "package_root": str(plan_root), "workspace_root": str(paths["workspace"]), "repo": target["repo"], "milestone": target["milestone"],
            "issue": target["issue"], "branch": target["branch"], "target_object_id": target["target_object_id"], "target_repo_head_sha": target["target_repo_head_sha"],
            "dependency_closure_sha256": target["dependency_closure_sha256"], "provider_query_id": contract["provider_query_map"][row_name],
            "transport_validation_phase": transport_validation_phase,
            "clock": fixture_clock_document(plan),
            "authority_payload": payloads[row_name],
        }
        input_path = evidence_dir / f"{target['repo']}-{target['milestone']}-{row_name}-input.json"
        atomic_write_bytes(input_path, (canonical_json(replay_input) + "\n").encode())
        argv = [sys.executable, str(Path(__file__).resolve()), "--replay-preflight-row", row_name, "--replay-input", str(input_path)]
        completed = subprocess.run(argv, check=False, capture_output=True)
        require(completed.returncode == 0, f"preflight row replay process failed: {row_name}: {completed.stderr.decode(errors='replace').strip()}")
        semantic = json.loads(completed.stdout)
        require(semantic["semantic_status"] == "PASS", f"preflight row semantic result is not PASS: {row_name}: {canonical_json(semantic)}")
        signer = contract["authority_signer_map"][row_name]
        receipt = sign_fixture({
            "schema": contract["schema"], "row_type": row_name, "repo": target["repo"], "milestone": target["milestone"], "issue": target["issue"], "branch": target["branch"],
            "batch_id": batch_id, "target_object_id": target["target_object_id"], "target_repo_head_sha": target["target_repo_head_sha"], "dependency_closure_sha256": target["dependency_closure_sha256"],
            "provider_identity": contract["provider_identity_map"][row_name], "provider_public_key_id": signer, "provider_query_id": contract["provider_query_map"][row_name],
            "exact_command_argv": argv, "command_sha256": sha(canonical_json(argv).encode()), "input_artifact_path": str(input_path), "input_artifact_sha256": sha(input_path.read_bytes()),
            "exit_status": completed.returncode, "stdout_sha256": sha(completed.stdout), "stderr_sha256": sha(completed.stderr), "output_digest_sha256": sha(completed.stdout),
            "semantic_status": semantic["semantic_status"], "semantic_result_sha256": sha(canonical_json(semantic["result"]).encode()),
            "issued_at": "2026-07-11T10:00:00Z", "expiry": "2026-07-11T20:00:00Z", "signer_id": signer,
        }, registry)
        receipt_path = evidence_dir / f"{target['repo']}-{target['milestone']}-{row_name}-receipt.json"
        atomic_write_bytes(receipt_path, (canonical_json(receipt) + "\n").encode())
        rows[row_name] = {
            "status": "GREEN", "repo": target["repo"], "milestone": target["milestone"], "issue": target["issue"], "branch": target["branch"], "batch_id": batch_id,
            "target_object_id": target["target_object_id"], "target_repo_head_sha": target["target_repo_head_sha"], "dependency_closure_sha256": target["dependency_closure_sha256"],
            "provider_query_id": contract["provider_query_map"][row_name], "semantic_result_sha256": receipt["semantic_result_sha256"],
            "evidence_artifact_type": contract["schema"], "evidence_artifact_path": str(receipt_path), "evidence_artifact_sha256": sha(receipt_path.read_bytes()),
        }
    return rows


def validate_preflight_envelope(value: dict[str, Any], plan: dict[str, Any], registry: dict[str, Any], now: datetime, expected_targets: list[dict[str, Any]], expected_dependencies: list[Any], allow_fixture_clock: bool = False) -> None:
    schema = plan["planning_gates"][-1]["installed_preflight_success_schema"]
    require(set(value) == {"preflight", "next_skill"}, "preflight wrapper shape drift")
    require(value["next_skill"] == "cruise-dev-supervise", "attacker-controlled next_skill")
    preflight = value["preflight"]
    mode = preflight.get("mode")
    require(mode in {"single", "multi"}, "invalid preflight mode")
    branch = schema[mode]
    require(set(value) == set(branch["top_level_exact_fields"]) and set(preflight) == set(branch["preflight_exact_fields"]), "preflight wrapper/schema drift")
    require(preflight["status"] == "green", "preflight aggregate is not green")
    expected_by_identity = {(item["repo"], item["milestone"]): item for item in expected_targets}
    row_names = set(schema["single"]["row_fields"])
    row_fields = set(branch["row_result_exact_fields"])

    def rows_for_target(rows: dict[str, Any], repo: str, milestone: str, batch_id: str) -> dict[str, str]:
        expected = expected_by_identity.get((repo, milestone))
        require(expected is not None and set(rows) == row_names, "preflight target/row coverage drift")
        for row_name, row in rows.items():
            require(set(row) == row_fields and row["status"] == "GREEN", "preflight row result schema/state drift")
            for field in ["repo", "milestone", "issue", "branch", "target_object_id", "target_repo_head_sha", "dependency_closure_sha256"]:
                require(row[field] == expected[field], f"preflight row target binding drift: {row_name}/{field}")
            require(row["batch_id"] == batch_id and row["provider_query_id"] == plan["preflight_evidence_contract"]["provider_query_map"][row_name], "preflight row batch/provider query drift")
            evidence_path = Path(row["evidence_artifact_path"])
            require(evidence_path.is_file() and not evidence_path.is_symlink() and row["evidence_artifact_sha256"] == sha(evidence_path.read_bytes()), "preflight evidence artifact missing/altered")
            evidence = json.loads(evidence_path.read_text())
            contract = plan["preflight_evidence_contract"]
            require(set(evidence) == set(contract["evidence_fields"]) and evidence["schema"] == row["evidence_artifact_type"] == contract["schema"], "preflight receipt fields/schema drift")
            require(evidence["row_type"] == row_name and evidence["repo"] == repo and evidence["milestone"] == milestone and evidence["issue"] == expected["issue"] and evidence["target_object_id"] == expected["target_object_id"] and evidence["target_repo_head_sha"] == expected["target_repo_head_sha"] and evidence["dependency_closure_sha256"] == expected["dependency_closure_sha256"], "preflight receipt target binding drift")
            require(evidence["provider_query_id"] == row["provider_query_id"] and evidence["semantic_status"] == "PASS" and evidence["semantic_result_sha256"] == row["semantic_result_sha256"], "preflight receipt semantic PASS binding drift")
            require(parse_utc(evidence["issued_at"]) <= now <= parse_utc(evidence["expiry"]), "preflight receipt stale/future")
            verify_signed(evidence, registry)
            input_path = Path(evidence["input_artifact_path"])
            require(input_path.is_file() and not input_path.is_symlink(), "preflight replay input missing or symlinked")
            replay_input = json.loads(input_path.read_text())
            _, replay_clock_mode = resolve_replay_clock(replay_input["clock"], plan)
            require(replay_clock_mode == "LIVE" or allow_fixture_clock, "deterministic fixture clock is forbidden in live preflight")
            require(replay_input["transport_validation_phase"] == expected.get("transport_validation_phase", "RUNTIME_M8"), "preflight transport phase binding drift")
            expected_argv = [sys.executable, str(Path(__file__).resolve()), "--replay-preflight-row", row_name, "--replay-input", str(input_path)]
            require(evidence["exact_command_argv"] == expected_argv and evidence["command_sha256"] == sha(canonical_json(expected_argv).encode()) and evidence["input_artifact_sha256"] == sha(input_path.read_bytes()), "preflight replay command/input drift")
            completed = subprocess.run(expected_argv, check=False, capture_output=True)
            require(completed.returncode == evidence["exit_status"] == 0 and evidence["stdout_sha256"] == sha(completed.stdout) and evidence["stderr_sha256"] == sha(completed.stderr) and evidence["output_digest_sha256"] == sha(completed.stdout), "preflight replay transcript drift")
            semantic = json.loads(completed.stdout)
            validate_preflight_receipt_semantics(evidence, semantic, row_name)
        return {
            "rows_sha256": sha(canonical_json(rows).encode()),
            "workflow_semantic_result_sha256": rows["workflow"]["semantic_result_sha256"],
            "semantic_results_sha256": sha(canonical_json({name: rows[name]["semantic_result_sha256"] for name in sorted(rows)}).encode()),
            "evidence_set_sha256": sha(canonical_json({name: rows[name]["evidence_artifact_sha256"] for name in sorted(rows)}).encode()),
        }

    if mode == "single":
        require(len(expected_targets) == 1 and isinstance(preflight["rows"], dict), "single preflight target/cardinality drift")
        expected = expected_targets[0]
        rows_for_target(preflight["rows"], expected["repo"], expected["milestone"], next(iter(preflight["rows"].values()))["batch_id"])
    else:
        require(isinstance(preflight["per_repo"], list) and preflight["per_repo"] and isinstance(preflight["batch"], list) and preflight["batch"] and isinstance(preflight["batch_id"], str) and preflight["batch_id"], "multi preflight container drift")
        require(isinstance(preflight["max_parallel"], int) and 1 <= preflight["max_parallel"] <= min(3, len(preflight["batch"])), "multi preflight max_parallel drift")
        require(preflight["cross_repo_deps"] == expected_dependencies, "multi preflight cross-repo dependency drift")
        require(all(set(item) == set(branch["per_repo_item_exact_fields"]) for item in preflight["per_repo"]), "multi preflight per_repo fields drift")
        require(all(set(item) == set(branch["batch_item_exact_fields"]) for item in preflight["batch"]), "multi preflight batch item fields drift")
        preliminary_per_repo = {(item["repo"], item["milestone"]): item for item in preflight["per_repo"]}
        preliminary_batch = {(item["repo"], item["milestone"]): item for item in preflight["batch"]}
        require(len(preliminary_per_repo) == len(preflight["per_repo"]) and len(preliminary_batch) == len(preflight["batch"]), "multi preflight duplicate identity")
        require(set(preliminary_per_repo) == set(preliminary_batch) == set(expected_by_identity), "multi preflight preliminary exact target set drift")
        for identity, per_repo_item in preliminary_per_repo.items():
            expected = expected_by_identity[identity]
            batch_item = preliminary_batch[identity]
            for field in ["repo", "milestone", "issue", "issue_number", "branch", "target_object_id", "target_repo_head_sha", "dependency_closure_sha256"]:
                require(per_repo_item[field] == batch_item[field] == expected[field], f"multi preflight preliminary target binding drift: {identity}/{field}")
            require(batch_item["complexity"] == expected["complexity"] and batch_item["risk_classes"] == per_repo_item["risk_classes"] == expected["risk_classes"] and batch_item["pre_execution_intent_sha256"] == per_repo_item["pre_execution_intent_sha256"] == expected["pre_execution_intent_sha256"] and batch_item["acceptance_criteria"] == expected["acceptance_criteria"], f"multi preflight preliminary intent/acceptance drift: {identity}")
            rows_digest = sha(canonical_json(per_repo_item["rows"]).encode())
            workflow_digest = per_repo_item["rows"].get("workflow", {}).get("semantic_result_sha256")
            semantic_digest = sha(canonical_json({name: per_repo_item["rows"][name]["semantic_result_sha256"] for name in sorted(per_repo_item["rows"])}).encode())
            evidence_digest = sha(canonical_json({name: per_repo_item["rows"][name]["evidence_artifact_sha256"] for name in sorted(per_repo_item["rows"])}).encode())
            require(per_repo_item["batch_id"] == batch_item["batch_id"] == preflight["batch_id"] and per_repo_item["rows_sha256"] == batch_item["rows_sha256"] == rows_digest and per_repo_item["workflow_semantic_result_sha256"] == batch_item["workflow_semantic_result_sha256"] == workflow_digest and per_repo_item["semantic_results_sha256"] == batch_item["semantic_results_sha256"] == semantic_digest and per_repo_item["evidence_set_sha256"] == batch_item["evidence_set_sha256"] == evidence_digest, f"multi preflight preliminary row/workflow/evidence equality drift: {identity}")
        per_repo_rows: dict[tuple[str, str], dict[str, Any]] = {}
        for item in preflight["per_repo"]:
            require(set(item) == set(branch["per_repo_item_exact_fields"]), "multi preflight per_repo fields drift")
            identity = (item["repo"], item["milestone"])
            require(identity not in per_repo_rows, "duplicate multi preflight per_repo identity")
            expected = expected_by_identity.get(identity)
            require(expected is not None, "multi preflight per_repo target is not expected")
            row_binding = rows_for_target(item["rows"], item["repo"], item["milestone"], preflight["batch_id"])
            for field in ["repo", "milestone", "issue", "issue_number", "branch", "target_object_id", "target_repo_head_sha", "dependency_closure_sha256", "risk_classes", "pre_execution_intent_sha256"]:
                require(item[field] == expected[field], f"multi preflight per_repo target binding drift: {identity}/{field}")
            require(item["batch_id"] == preflight["batch_id"] and all(item[field] == row_binding[field] for field in ["rows_sha256", "workflow_semantic_result_sha256", "semantic_results_sha256", "evidence_set_sha256"]), f"multi preflight per_repo row/workflow/evidence binding drift: {identity}")
            per_repo_rows[identity] = item
        batch_rows: dict[tuple[str, str], dict[str, Any]] = {}
        for item in preflight["batch"]:
            require(set(item) == set(branch["batch_item_exact_fields"]), "multi preflight batch item fields drift")
            identity = (item["repo"], item["milestone"])
            require(identity not in batch_rows and identity in expected_by_identity, "multi preflight duplicate or unexpected batch identity")
            expected = expected_by_identity[identity]
            for field in ["repo", "milestone", "issue", "issue_number", "branch", "target_object_id", "target_repo_head_sha", "dependency_closure_sha256", "complexity", "risk_classes", "pre_execution_intent_sha256", "acceptance_criteria"]:
                require(item[field] == expected[field], f"multi preflight batch target binding drift: {identity}/{field}")
            require(item["batch_id"] == preflight["batch_id"], f"multi preflight batch ID drift: {identity}")
            require(all(item[field] == per_repo_rows.get(identity, {}).get(field) for field in ["rows_sha256", "workflow_semantic_result_sha256", "semantic_results_sha256", "evidence_set_sha256"]), f"multi preflight batch/per_repo row equality drift: {identity}")
            batch_rows[identity] = item
        require(set(per_repo_rows) == set(batch_rows) == set(expected_by_identity), "multi preflight batch/per_repo/expected exact target set drift")
    authorization = preflight["authorization"]
    require(set(authorization) == set(plan["planning_gates"][-1]["authorization_exact_fields"]), "preflight authorization fields drift")
    signed_at = parse_utc(authorization["signed_at"])
    require(authorization["schema"] == "signed-preflight-authorization-v1" and signed_at <= now and (now - signed_at).total_seconds() <= plan["attestation_trust_contract"]["maximum_attestation_age_seconds"], "preflight authorization schema/time drift")
    validate_route_records(authorization["route_records"], {"developer", "tester", "gate"}, plan, now, registry)
    require(authorization["route_records_sha256"] == sha(canonical_json(authorization["route_records"]).encode()), "preflight authorization route digest drift")
    expected_risks = sorted({risk for item in expected_targets for risk in item["risk_classes"]})
    require(authorization["pre_execution_intents_sha256"] == plan["pre_execution_intents_sha256"], "preflight intent authority digest drift")
    require(authorization["risk_classes"] == expected_risks and authorization["risk_classes_sha256"] == sha(canonical_json(expected_risks).encode()), "preflight exact risk-class binding drift")
    require(all(record["risks"] == expected_risks and record["complexity"] == max(item["complexity"] for item in expected_targets) for record in authorization["route_records"]), "route resolver input is not bound to exact pre-execution intent risk/complexity")
    unique = {(item["target_object_id"], item["draft_payload_sha256"], item["locked_payload_sha256"], item["lock_transform_manifest_sha256"]) for item in expected_targets}
    require(len(unique) == 1, "preflight authorization mixed lock targets")
    target_object, draft_payload, locked_payload, transform = next(iter(unique))
    require(authorization["final_locked_commit_oid"] == target_object and authorization["draft_payload_sha256"] == draft_payload and authorization["locked_payload_sha256"] == locked_payload and authorization["lock_transform_manifest_sha256"] == transform, "preflight authorization lock digest binding drift")
    unsigned = copy.deepcopy(value)
    unsigned["preflight"].pop("authorization")
    require(authorization["envelope_sha256"] == sha(canonical_json(unsigned).encode()), "preflight authorization envelope digest drift")
    verify_signed(authorization, registry)


def normalized_payload(root: Path, plan: dict[str, Any]) -> bytes:
    chunks: list[bytes] = []
    for name in plan["validation_payload"]["ordered_files"]:
        path = root / name
        require(path.is_file(), f"validation payload file missing: {name}")
        raw = path.read_bytes()
        if name == "plan.yaml":
            parsed = load_yaml(raw)
            parsed.pop(plan["validation_payload"]["plan_yaml_excluded_key"], None)
            parsed.get("terminal_repair_11_contracts", {}).get("display_hashes", {}).pop("values", None)
            parsed.get("terminal_repair_12_contracts", {}).get("rendered_mirrors", {}).pop("normalized_markdown_sha256", None)
            parsed.get("terminal_repair_13_contracts", {}).get("rendered_mirrors", {}).pop("normalized_markdown_sha256", None)
            parsed.get("terminal_repair_14_contracts", {}).get("rendered_mirrors", {}).pop("normalized_markdown_sha256", None)
            parsed.get("terminal_repair_15_contracts", {}).get("rendered_mirrors", {}).pop("normalized_markdown_sha256", None)
            raw = canonical_json(parsed).encode() + b"\n"
        elif name.endswith(".md"):
            raw = normalized_markdown_bytes(raw)
        chunks.extend([name.encode(), b"\0", str(len(raw)).encode(), b"\0", raw])
    return b"".join(chunks)


def validate(root: Path, strict_attestation: bool, external_metadata_path: Path | None, trusted_keys_path: Path | None, root_agents_path: Path | None = None, skill_root_path: Path | None = None, huawei_artifact_path: Path | None = None, model_policy_path: Path | None = None, model_route_path: Path | None = None, lock_phase: str | None = None, cas_receipt_path: Path | None = None, candidate_validation: bool = False, validation_mode: str | None = None) -> tuple[dict[str, Any], bytes]:
    validation_mode = validation_mode or ("candidate_locked" if candidate_validation else ("post_cas_locked" if lock_phase == "post-cas" else "draft"))
    require(validation_mode in {"draft", "candidate_locked", "post_cas_locked"}, "unknown validation mode")
    candidate_validation = validation_mode in {"candidate_locked", "post_cas_locked"}
    validator_path = Path(__file__).resolve()
    validator_start_bytes = validator_path.read_bytes()
    validator_start_stat = validator_path.stat()
    validator_start_identity = {
        "sha256": sha(validator_start_bytes),
        "size": validator_start_stat.st_size,
        "mtime_ns": validator_start_stat.st_mtime_ns,
    }
    checks: list[dict[str, str]] = []
    executed_harnesses: dict[str, str] = {}
    executed_fixture_sets: dict[str, Any] = {}

    def check(check_id: str, function: Any) -> None:
        require(check_id not in {item["id"] for item in checks}, f"duplicate check registration: {check_id}")
        harness_sha256 = callable_harness_sha256(function)
        execution_receipt = function()
        if execution_receipt is not None:
            require(check_id not in executed_fixture_sets and isinstance(execution_receipt, dict), f"invalid or duplicate executed fixture receipt: {check_id}")
            executed_fixture_sets[check_id] = execution_receipt
        executed_harnesses[check_id] = harness_sha256
        checks.append(completed_check_entry(check_id, harness_sha256))

    plan = load_yaml((root / "plan.yaml").read_text())
    validate_recursive_manifest(root, plan)
    raw_package_tree_start = package_tree_sha256(root)
    package_payload_tree_start = package_payload_tree_sha256(root, plan)
    validate_terminal_repair_12b_contract(plan)
    validate_terminal_repair_13_contract(plan)
    canonical_markdown = (root / plan["canonical_file"]).read_text()
    validate_terminal_repair_14_contract(plan, canonical_markdown)
    validate_terminal_repair_15_contract(plan)
    require(plan.get("terminal_repair_17_contracts") == expected_terminal_repair_17_contract(plan), "Terminal Repair 17 contract missing or stale")
    require(plan.get("terminal_repair_18_contracts") == expected_terminal_repair_18_contract(plan), "Terminal Repair 18 contract missing or stale")
    require(plan.get("terminal_repair_19_contracts") == expected_terminal_repair_19_contract(plan), "Terminal Repair 19 contract missing or stale")
    require(plan.get("terminal_repair_20_contracts") == expected_terminal_repair_20_contract(plan), "Terminal Repair 20 contract missing or stale")
    require(plan.get("terminal_repair_21_contracts") == expected_terminal_repair_21_contract(plan), "Terminal Repair 21 contract missing or stale")
    require(plan.get("terminal_repair_22_contracts") == expected_terminal_repair_22_contract(plan), "Terminal Repair 22 contract missing or stale")
    require(plan.get("terminal_repair_23_contracts") == expected_terminal_repair_23_contract(plan), "Terminal Repair 23 contract missing or stale")
    require(plan.get("public_release_license_contract") == expected_public_release_license_contract(), "public release SPDX/SBOM/license contract missing or stale")
    authority_paths = derive_authority_paths(root)
    for supplied, canonical, label in [
        (root_agents_path, authority_paths["root_agents"], "root AGENTS"),
        (skill_root_path, authority_paths["skill_root"], "installed skill root"),
        (model_policy_path, authority_paths["model_policy"], "routing policy"),
        (model_route_path, authority_paths["model_resolver"], "routing resolver"),
    ]:
        require(supplied is None or supplied.resolve() == canonical.resolve(), f"alternate {label} path rejected")
    milestones = plan["milestones"]
    ids_list = [m["id"] for m in milestones]
    ids = set(ids_list)
    by_id = {m["id"]: m for m in milestones}
    a_edges = artifact_edges(milestones)
    explicit_schedule_edges = schedule_edges(milestones)
    lane_edges = lane_schedule_edges(plan)
    s_edges = explicit_schedule_edges | lane_edges
    p_edges = predicate_edges(plan)
    all_edges = a_edges | s_edges | p_edges
    total_conditional_count = sum(len(m.get("consumes_if", [])) for m in milestones)
    internal_conditional_count = sum(len(internal_consumes(m, ids)) for m in milestones)
    cross_edges = {(a, b) for a, b in a_edges if by_id[a]["repo"] != by_id[b]["repo"]}
    topology_digest = sha(topology_bytes(plan))
    expected_state = "locked" if root.name.endswith(".locked") else "draft"

    def yaml_nodes_and_ast() -> None:
        require(root.name.endswith((".draft", ".locked")), "package path must end in .draft or .locked")
        require(plan["state"] == expected_state, f"package state/path mismatch: {plan['state']} vs {expected_state}")
        require(len(ids_list) == len(ids) and all(ISSUE_RE.match(node) for node in ids), "duplicate or malformed milestone ID")
        required = set(plan["authoritative_issue_contract"]["required_milestone_fields"])
        external_ids = {item["id"] for item in plan["external_planning_artifacts"]}
        source_ids = ids | external_ids | {"inventory-row-facts", "profile-fact-selection-settled", "scope-selected-profile-set-v1", "fact-cleared-profile-set-v1", "executable-profile-set-v1", "eebus-fresh-genesis-v1"}
        require(set(plan["selected_branch_predicates"]) == {m["selected_branch"] for m in milestones}, "selected_branch registry parity failure")
        selected_predicate_artifacts = {
            "docs-modbus-org-READY": "public-repo-readiness-v2",
            "modbus-org-READY": "public-repo-readiness-v2",
            "modbusreg-org-READY": "public-repo-readiness-v2",
            "eebus-org-READY": "eebus-private-repo-readiness-v2",
            "matter-org-READY": "matter-private-repo-readiness-v2",
            "HUAWEI-SMARTLOGGER-TCP-SELECTED": "huawei-fact-clearance-v1",
            "HUAWEI-SDONGLE-TCP-SELECTED": "huawei-fact-clearance-v1",
            "matching-Huawei-RTU-GO": "huawei-fact-clearance-v1",
        }
        for name, predicate in plan["selected_branch_predicates"].items():
            validate_ast(predicate, plan, ids)
            if "artifact_field_is" in canonical_json(predicate):
                require(name in selected_predicate_artifacts, f"selected predicate artifact schema authority missing: {name}")
                validate_artifact_predicate_paths(predicate, selected_predicate_artifacts[name], plan)
        for derived in plan["derived_node_sets"].values():
            validate_ast(derived["filter"], plan, ids)
        for milestone in milestones:
            require(set(milestone) == required or set(milestone) == required | {"produces"}, f"milestone fields drift: {milestone['id']}")
            require(milestone["repo"] in plan["target_repos"], f"unknown repo: {milestone['id']}")
            require(all(isinstance(milestone[field], str) and milestone[field] for field in ["what", "why", "branch_template", "provisioning_identity"]), f"issue prose/identity field empty: {milestone['id']}")
            require(isinstance(milestone["acceptance_criteria"], list) and len(milestone["acceptance_criteria"]) == 9 and all(isinstance(item, str) and item for item in milestone["acceptance_criteria"]), f"issue acceptance criteria invalid: {milestone['id']}")
            require(milestone["unit_tests"] == "required" and milestone["ci"] == "green" and milestone["smoke"] in {"YES", "NO"}, f"issue test/CI/smoke fields drift: {milestone['id']}")
            expected_dependencies = "Depends on: " + (", ".join(milestone["depends_on"] + [edge["source"] for edge in milestone["consumes_if"]]) or "none")
            machine = plan["issue_machine_contracts"]["contracts"][milestone["id"]]
            expected_criteria = expected_issue_acceptance_criteria(milestone, machine)
            expected_body = composed_issue_body(milestone, plan)
            require(milestone["dependencies_text"] == expected_dependencies and milestone["issue_body"] == expected_body and milestone["issue_body_sha256"] == sha(expected_body.encode()), f"authoritative issue body/template drift: {milestone['id']}")
            require(milestone["acceptance_criteria"] == machine["acceptance_criteria"] == expected_criteria and expected_criteria[-3:] == ["Unit tests cover the implemented code.", "CI green.", f"Smoke test required: {milestone['smoke']}."], f"issue-specific acceptance drift: {milestone['id']}")
            require(milestone["branch_template"] == f"issue/{{issue_number}}-{milestone['id'].lower()}" and milestone["provisioning_identity"] == "signed-post-provision-issue-map-v1", f"issue branch/provisioning contract drift: {milestone['id']}")
            require(len(milestone["depends_on"]) == len(set(milestone["depends_on"])) and len(milestone["schedule_after"]) == len(set(milestone["schedule_after"])), f"duplicate milestone edge: {milestone['id']}")
            require(set(milestone["allowed_terminal_outcomes"]) <= set(plan["predicate_action_schema"]["execution_outcomes"]), f"milestone uses non-execution state as outcome: {milestone['id']}")
            for source in milestone["depends_on"] + milestone["schedule_after"]:
                require(source in ids, f"unknown edge source {source} for {milestone['id']}")
            for edge in milestone["consumes_if"]:
                require(set(edge) >= {"source", "artifact", "when"}, f"invalid consumes_if: {milestone['id']}")
                require(edge["source"] in source_ids, f"unresolved consumes_if source: {edge['source']}")
                require(edge["artifact"] in known_artifacts(plan), f"unresolved consumes_if artifact: {edge['artifact']}")
                validate_ast(edge["when"], plan, ids)
                validate_artifact_predicate_paths(edge["when"], edge["artifact"], plan)
        require(plan["topology_contract"]["artifact_edge_fields"] == ["depends_on", "consumes_if"], "topology artifact edge source registry drift")
        canonical_triplets = {(edge["source"], edge["artifact"], milestone["id"]) for milestone in milestones for edge in milestone["consumes_if"]}
        require(promoted_edge_triplets() <= canonical_triplets, "one or more TA7 promoted edges is absent from canonical consumes_if")
        require(plan["terminal_repair_7_contracts"]["promoted_artifact_edges"]["supplemental_side_channel"] == "forbidden", "supplemental artifact side channel remains enabled")
        for rule in plan["outcome_rules"]:
            require(rule["source"]["kind"] in {"milestone", "milestone_artifact", "external", "derived"}, f"invalid rule source: {rule['id']}")
            require(rule["source"]["id"] in source_ids, f"unresolved rule source: {rule['id']}")
            for case in rule["cases"]:
                validate_ast(case["when"], plan, ids)
                for action in case["actions"]:
                    validate_action(action, plan, ids)
        require(set(plan["predicate_action_schema"]["derived_node_states"]).isdisjoint(plan["predicate_action_schema"]["execution_outcomes"]), "derived/execution state types overlap")
        expected_lane_edges = []
        exceptions = {(item["repo"], item["source"], item["target"]) for item in plan["lane_edge_contract"]["independence_exceptions"]}
        for repo, lane in plan["execution_lanes"].items():
            expected_lane_edges.extend({"repo": repo, "source": source, "target": target} for source, target in zip(lane, lane[1:]) if (repo, source, target) not in exceptions)
        require(plan["lane_edges"] == expected_lane_edges and plan["lane_edge_contract"]["exact_edge_count"] == len(expected_lane_edges), "first-class lane edge derivation drift")
        require(("FMB-08A", "FMB-08A-INVENTORY") not in lane_schedule_edges(plan), "neutral inventory serialized behind Huawei facts")
        f05c = by_id["FMB-05C"]
        require(f05c.get("produces") == ["canonical-pv-schema-v1", "canonical-domain-schema-declarations-v1"], "FMB-05C declaration artifact drift")
        f05h = by_id["FMB-05H"]
        require(any(edge["source"] == "FMB-05C" and edge["artifact"] == "canonical-domain-schema-declarations-v1" for edge in f05h["consumes_if"]), "FMB-05H lacks exact declaration artifact edge")

    check("yaml_milestone_predicate_action_schema", yaml_nodes_and_ast)

    def manifest_mutations() -> None:
        def make_root(base: Path) -> Path:
            package = base / "fixture.draft"
            package.mkdir()
            for name in plan["package_manifest"]["declared_files"]:
                (package / name).write_text("fixture\n")
            return package

        with tempfile.TemporaryDirectory() as directory:
            valid = make_root(Path(directory))
            validate_recursive_manifest(valid, plan)
        for kind in ["nested-file", "directory", "symlink", "hardlink", "edges"]:
            with tempfile.TemporaryDirectory() as directory:
                package = make_root(Path(directory))
                if kind == "nested-file":
                    (package / "nested").mkdir()
                    (package / "nested" / "extra.txt").write_text("x\n")
                elif kind == "directory":
                    (package / "empty").mkdir()
                elif kind == "symlink":
                    (package / "link").symlink_to(package / "plan.yaml")
                elif kind == "hardlink":
                    os.link(package / "plan.yaml", package / "hardlink")
                else:
                    (package / "edges.yaml").write_text("edges: []\n")
                try:
                    validate_recursive_manifest(package, plan)
                except ValidationError:
                    continue
                raise ValidationError(f"recursive manifest mutation accepted: {kind}")

    check("exact_recursive_manifest_and_negative_fixtures", manifest_mutations)
    check("artifact_dag", lambda: assert_dag(ids, a_edges, "artifact DAG"))
    check("combined_artifact_schedule_predicate_dag", lambda: assert_dag(ids, all_edges, "combined artifact/schedule/predicate DAG"))

    def predicate_ancestor_reachability() -> None:
        base = a_edges | s_edges
        for milestone in milestones:
            target = milestone["id"]
            predicates = [plan["selected_branch_predicates"][milestone["selected_branch"]]] + [edge["when"] for edge in milestone["consumes_if"]]
            for predicate in predicates:
                for source in ast_node_refs(predicate):
                    require(source != target and reachable(base, source, target), f"predicate source is not an independent ancestor: {source}->{target}")
        derived = plan["derived_node_sets"]["selected_rtu_profile_nodes"]
        require(not ast_node_refs(derived["filter"]), "RTU scope selection depends on milestone outcome")
        require(next(m for m in milestones if m["id"] == "FMB-08A-CUSTODY")["selected_branch"] == "always", "Huawei custody has downstream selector")

    check("predicate_ancestor_reachability", predicate_ancestor_reachability)

    def planning_gates() -> None:
        gates = {gate["id"]: gate for gate in plan["planning_gates"]}
        require(set(gates) == {"PG-DRAFT-CURATION", "PG-SKILL-ADAPTER-REGISTRY", "PG-ARCHITECTURE-MAP-AMENDMENT", "PG-MODEL-ROUTING-POLICY-AMENDMENT", "PG-FRESH-TERMINAL-REVIEW", "PG-CRUISE-LOCK"}, "planning gate set drift")
        components = set(next(item for item in plan["external_planning_artifacts"] if item["id"] == "SKILL-ADAPTER-REGISTRY-V1")["required_components"])
        required_components = {
            "cruise-plan", "cruise-resume", "cruise-state-sync", "cruise-preflight",
            "cruise-topology", "cruise-doc-gate", "cruise-transport-gate",
            "cruise-pr-review-loop", "cruise-by-design-reject",
            "fresh-adversarial-5round", "codex-fresh-reviewer", "cruise-merge-gate",
            "cruise-dev-supervise", "cruise-tdd-gate",
        }
        require(components == required_components, "skill adapter registry component drift")
        if expected_state == "draft":
            if lock_phase is None:
                require(external_metadata_path is None, "ordinary draft mode rejects --external-lock-metadata")
                require(trusted_keys_path is None, "ordinary draft mode rejects --trusted-attestation-keys")
                require(all(path is None for path in [root_agents_path, skill_root_path, huawei_artifact_path, model_policy_path, model_route_path, cas_receipt_path]), "ordinary draft mode rejects lock authority paths")
            else:
                require(lock_phase == "pre-cas" and cas_receipt_path is None, "draft lock validation is pre-CAS only and rejects receipt")
            require(gates["PG-SKILL-ADAPTER-REGISTRY"]["state"] == "pending_external_operator", "skill adapter gate state drift")
            require(gates["PG-ARCHITECTURE-MAP-AMENDMENT"]["state"] == "pending_external_operator", "architecture map gate state drift")
            require(gates["PG-MODEL-ROUTING-POLICY-AMENDMENT"]["state"] == "pending_external_operator", "model routing policy gate state drift")
            require(gates["PG-CRUISE-LOCK"]["state"] == "pending_unauthorized", "lock gate state drift")
        else:
            if validation_mode == "candidate_locked":
                require(lock_phase is None and cas_receipt_path is None and external_metadata_path is None and trusted_keys_path is None, "candidate locked validation rejects caller lock metadata paths")
                require(all(path is None for path in [root_agents_path, skill_root_path, huawei_artifact_path]), "candidate locked validation rejects external content authority paths")
                require(model_policy_path is not None and model_policy_path.is_file() and model_route_path is not None and model_route_path.is_file(), "candidate locked validation requires injected local routing authorities")
                validate_locked_plan_state(plan)
            elif validation_mode == "post_cas_locked":
                require(lock_phase == "post-cas" and cas_receipt_path is not None, "locked package validation requires post-CAS phase and receipt")
                require(external_metadata_path is not None, "locked mode requires --external-lock-metadata")
                require(trusted_keys_path is not None, "locked mode requires --trusted-attestation-keys")
                require(huawei_artifact_path is None, "PLAN_LOCK rejects future Huawei issue-owned artifacts")
                require(root_agents_path is not None and skill_root_path is not None and model_policy_path is not None and model_route_path is not None, "locked mode requires all real PLAN_LOCK authority paths")
                validate_locked_plan_state(plan)
            else:
                raise ValidationError("locked package requires candidate_locked or post_cas_locked validation mode")
        computed_initial = sorted(m["id"] for m in milestones if not m["depends_on"] and not internal_consumes(m, ids) and not m["schedule_after"])
        require(computed_initial == ["FMB-00D"] == plan["topology_contract"]["initial_wave_after_lock"], "initial wave drift")

    check("planning_gates_and_lock_dry_run", planning_gates)

    def locked_state_fixtures() -> None:
        locked = copy.deepcopy(plan)
        locked["state"] = "locked"
        states = {"PG-DRAFT-CURATION": "complete", "PG-SKILL-ADAPTER-REGISTRY": "complete_verified", "PG-ARCHITECTURE-MAP-AMENDMENT": "complete_verified", "PG-MODEL-ROUTING-POLICY-AMENDMENT": "complete_verified", "PG-FRESH-TERMINAL-REVIEW": "complete_no_findings", "PG-CRUISE-LOCK": "complete_authorized"}
        for gate in locked["planning_gates"]:
            gate["state"] = states[gate["id"]]
        locked["planning_status"].update(review_clean=True, lock_ready=True, terminal_review="complete", terminal_verdict="NO_FINDINGS", terminal_audit="complete", plan_lock="authorized_locked")
        validate_locked_plan_state(locked)
        mutations: list[dict[str, Any]] = []
        for gate_id in ["PG-SKILL-ADAPTER-REGISTRY", "PG-ARCHITECTURE-MAP-AMENDMENT", "PG-MODEL-ROUTING-POLICY-AMENDMENT", "PG-FRESH-TERMINAL-REVIEW", "PG-CRUISE-LOCK"]:
            value = copy.deepcopy(locked)
            next(gate for gate in value["planning_gates"] if gate["id"] == gate_id)["state"] = "pending"
            mutations.append(value)
        for key, replacement in [("review_clean", False), ("lock_ready", False), ("terminal_review", "pending"), ("terminal_verdict", "pending"), ("terminal_audit", "pending"), ("plan_lock", "pending_unauthorized")]:
            value = copy.deepcopy(locked)
            value["planning_status"][key] = replacement
            mutations.append(value)
        unlocked = copy.deepcopy(locked)
        unlocked["state"] = "draft"
        mutations.append(unlocked)
        for value in mutations:
            try:
                validate_locked_plan_state(value)
            except ValidationError:
                continue
            raise ValidationError("pending/stale locked state mutation accepted")

    check("locked_state_and_gate_negative_fixtures", locked_state_fixtures)

    def mirrors() -> None:
        declared = plan["execution_lanes"]
        flattened = [node for lane in declared.values() for node in lane]
        require(len(flattened) == len(set(flattened)) == len(ids) and set(flattened) == ids, "lane parity failure")
        require(all(all(by_id[node]["repo"] == repo for node in lane) for repo, lane in declared.items()), "lane repo mismatch")
        require(parse_lane_table((root / "90-issue-map.md").read_text()) == declared, "90 lane mirror drift")
        require(parse_bullet_lanes((root / "91-milestone-map.md").read_text()) == declared, "91 lane mirror drift")
        require(parse_bullet_lanes((root / "13-roadmap-issues-risks.md").read_text()) == declared, "13 lane mirror drift")
        rows = parse_issue_table((root / "90-issue-map.md").read_text())
        require(set(rows) == ids, "90 issue set drift")
        require(all(len(cells) == plan["authoritative_issue_contract"]["exact_markdown_issue_columns"] for cells in rows.values()), "90 issue table column drift")
        for node, milestone in by_id.items():
            cells = rows[node]
            require(cells[1] == milestone["repo"] and cells[2] == milestone["milestone"], f"90 repo/milestone mismatch: {node}")
            require(cells[4] == (", ".join(milestone["depends_on"]) or "none"), f"90 depends_on mismatch: {node}")
            require(cells[5] == (", ".join(edge["source"] for edge in milestone["consumes_if"]) or "none"), f"90 consumes_if mismatch: {node}")
            require(cells[6] == (", ".join(milestone["schedule_after"]) or "none"), f"90 schedule mismatch: {node}")
            require(cells[7] == ", ".join(milestone["allowed_terminal_outcomes"]), f"90 outcomes mismatch: {node}")
            require(cells[8] == milestone["acceptance_artifact"] and cells[9] == milestone["scope"], f"90 artifact/scope mismatch: {node}")
        expected_groups: dict[str, list[str]] = {}
        for milestone in milestones:
            expected_groups.setdefault(milestone["milestone"], []).append(milestone["id"])
        require(parse_milestone_groups((root / "91-milestone-map.md").read_text()) == expected_groups, "91 milestone drift")
        require(parse_milestone_groups((root / "13-roadmap-issues-risks.md").read_text()) == expected_groups, "13 milestone drift")
        generated_block = generated_ta9_model_block(plan)
        begin_marker = plan["terminal_repair_8_contracts"]["generated_mirrors"]["begin_marker"]
        end_marker = plan["terminal_repair_8_contracts"]["generated_mirrors"]["end_marker"]
        markdown_names = [name for name in plan["package_manifest"]["declared_files"] if name.endswith(".md")]
        require(len(markdown_names) == 11, "markdown mirror manifest cardinality drift")
        forbidden_huawei_predecessor = re.compile(r"FMB-08A(?:-CUSTODY)?\s*->\s*FMB-08A-(?:INVENTORY|SCOPE)")
        for name in markdown_names:
            text = (root / name).read_text()
            require(text.count(begin_marker) == text.count(end_marker) == 1 and generated_block in text, f"generated topology/route mirror drift: {name}")
            require(forbidden_huawei_predecessor.search(text) is None, f"Huawei predecessor assertion survived: {name}")
        neutral = plan["terminal_repair_7_contracts"]["neutral_parallelism"]
        require(neutral["neutral_lane"] == ["FMB-08A-INVENTORY", "FMB-08A-SCOPE"] and neutral["huawei_lane"] == ["FMB-08A-CUSTODY", "FMB-08A"] and neutral["cross_lane_predecessor_edges"] == "forbidden", "neutral/Huawei machine parallelism drift")

    check("issue_lane_milestone_mirror_parity", mirrors)

    def preflight_and_transport() -> None:
        text = (root / "93-pre-execution-matrix.md").read_text()
        rows = parse_issue_table(text)
        require(set(rows) == ids, "93 intent issue set drift")
        validate_pre_execution_intent_authority(plan, parse_pre_execution_intents(text))
        typed_mirror: dict[str, Any] = {}
        for match in re.finditer(r"^\| (FMB-[0-9A-Z-]+) \| `([^`]+)` \|$", text, re.MULTILINE):
            typed_mirror[match.group(1)] = json.loads(match.group(2))
        require(typed_mirror == plan["transport_intents"], "93 typed per-family transport mirror drift")
        for node, cells in rows.items():
            intent = plan["pre_execution_intents"][node]
            require(cells[1] == by_id[node]["repo"] and int(cells[2]) == intent["complexity"], f"93 identity/complexity drift: {node}")
            companion = re.search(r"companion=([^;]+)", cells[4])
            require(companion is not None, f"missing companion: {node}")
            if companion.group(1) not in {"none", "self"}:
                for source in companion.group(1).split(","):
                    require(source in ids and reachable(a_edges, source, node), f"doc companion is not ancestor: {source}->{node}")
            transport = cells[5]
            families = re.search(r"families=\[([^]]+)\]", transport)
            condition = re.search(r"condition=([^;]+)", transport)
            baseline = re.search(r"baseline=([^;]+)", transport)
            verify = re.search(r"verify=([^;]+)", transport)
            require(families and condition and baseline and verify, f"transport intent incomplete: {node}")
            concrete = families.group(1).split(",")
            require(all(item in plan["transport_intent_contract"]["families"] for item in concrete), f"unknown/freeform transport family: {node}")
            require(condition.group(1) in plan["transport_intent_contract"]["conditional_expressions"], f"unknown transport condition: {node}")
            if concrete == ["NONE"]:
                require(condition.group(1) == "ALWAYS" and baseline.group(1) == "N/A" and verify.group(1) == "N/A", f"NONE transport row is not exact N/A: {node}")
            else:
                require("NONE" not in concrete and baseline.group(1) != "N/A" and verify.group(1) != "N/A", f"vacuous concrete transport evidence: {node}")
                suffix = {"MODBUS_PDU": "PDU", "MODBUS_TCP": "TCP", "MODBUS_RTU": "RTU", "MODBUS_REPLAY": "REPLAY", "EBUS_T01_T88": "T01..T88"}
                explicit = [suffix[item] for item in concrete]
                same_family = "GENESIS_ABSENT" in baseline.group(1) or "family" in baseline.group(1) or all(token in baseline.group(1) for token in explicit)
                require(same_family, f"same-family baseline missing: {node}")
        require("baseline=repo+milestone+RTU+exact-HEAD" in rows["FMB-02R-A"][5], "FMB-02R-A baseline is not exact RTU family")
        require("PDU+exact-HEAD" not in rows["FMB-02R-A"][5], "PDU baseline improperly satisfies RTU")
        require("families=[MODBUS_TCP]" in rows["FMB-04A"][5] and "baseline=repo+milestone+TCP+exact-HEAD" in rows["FMB-04A"][5], "FMB-04A lacks explicit TCP same-family baseline")
        closed_families = set(plan["transport_intent_contract"]["families"])
        for mutant in [[], ["MODBUS_TCP+MODBUS_RTU"], ["TCP"], ["UNKNOWN"], ["MODBUS_TCP", "prose"]]:
            try:
                require(bool(mutant) and all(token in closed_families for token in mutant), "invalid transport enum mutation")
            except ValidationError:
                continue
            raise ValidationError(f"unknown/combined/prose transport family accepted: {mutant}")
        registry = fixture_key_registry()
        now = validate_fixture_clock(fixture_clock_document(plan), plan)
        evidence_dir = Path(tempfile.mkdtemp(prefix="helianthus-preflight-evidence-"))
        try:
            workflow_repo = evidence_dir / "workflow-repo"
            workflow_repo.mkdir()
            subprocess.run(["git", "-C", str(workflow_repo), "init", "-q", "-b", "main"], check=True)
            subprocess.run(["git", "-C", str(workflow_repo), "config", "user.email", "fixture@example.invalid"], check=True)
            subprocess.run(["git", "-C", str(workflow_repo), "config", "user.name", "Fixture"], check=True)
            (workflow_repo / "README.md").write_text("preflight fixture\n")
            subprocess.run(["git", "-C", str(workflow_repo), "add", "."], check=True)
            subprocess.run(["git", "-C", str(workflow_repo), "commit", "-q", "-m", "fixture base"], check=True)
            (workflow_repo / "tests").mkdir()
            (workflow_repo / "tests" / "test_red.py").write_text("def test_expected_red():\n    assert False\n")
            subprocess.run(["git", "-C", str(workflow_repo), "add", "."], check=True)
            subprocess.run(["git", "-C", str(workflow_repo), "commit", "-q", "-m", "RED tests only"], check=True)
            head = git_output(workflow_repo, "rev-parse", "HEAD")

            def make_target(issue: str, issue_number: int) -> dict[str, Any]:
                milestone = by_id[issue]
                return {
                    "repo": milestone["repo"], "milestone": issue, "issue": issue, "issue_number": issue_number,
                    "branch": milestone["branch_template"].replace("{issue_number}", str(issue_number)),
                    "target_object_id": head, "target_repo_head_sha": head,
                    "dependency_closure_sha256": sha(canonical_json({"depends_on": milestone["depends_on"], "consumes_if": milestone["consumes_if"]}).encode()),
                    "acceptance_criteria": milestone["acceptance_criteria"],
                    "complexity": plan["pre_execution_intents"][issue]["complexity"],
                    "risk_classes": plan["pre_execution_intents"][issue]["risk_classes"],
                    "pre_execution_intent_sha256": plan["pre_execution_intents"][issue]["intent_sha256"],
                    "draft_payload_sha256": "d" * 64, "locked_payload_sha256": "e" * 64,
                    "lock_transform_manifest_sha256": "f" * 64, "transport_validation_phase": "RUNTIME_M8",
                }

            targets = [make_target("FMB-02A", 2), make_target("FMB-03A", 3)]
            registry_path = evidence_dir / "trusted-keys.json"
            registry_path.write_text(canonical_json(registry) + "\n")
            review_path = evidence_dir / "review.json"
            review_path.write_text(canonical_json({"head_sha": head, "findings": []}) + "\n")
            rows_by_identity: dict[tuple[str, str], dict[str, Any]] = {}
            for index, target in enumerate(targets, 1):
                context = build_transport_context_fixture(
                    plan, registry, f"preflight-{target['milestone'].lower()}", ["SUNSPEC-GENERIC-TCP-DIRECT-V1"], [], [], "GO", "GO", head,
                    consumer_repo=target["repo"], consumer_issue=target["milestone"], source_heads={"inventory": f"{index}" * 40, "scope": f"{index + 2}" * 40, "huawei": f"{index + 4}" * 40},
                )
                context_path = evidence_dir / f"{target['milestone']}-transport-context.json"
                context_path.write_text(canonical_json(context) + "\n")
                rows_by_identity[(target["repo"], target["milestone"])] = build_preflight_receipt_rows(
                    plan, root / "plan.yaml", registry, registry_path, evidence_dir, target, "batch-1", workflow_repo,
                    review_path, [], context_path, use_fixture_routing_authority=True,
                )

            def authorize(wrapper: dict[str, Any]) -> dict[str, Any]:
                value = copy.deepcopy(wrapper)
                selected_identities = (
                    [(item["repo"], item["milestone"]) for item in value["preflight"].get("batch", [])]
                    or [(targets[0]["repo"], targets[0]["milestone"])]
                )
                expected_target_map = {(item["repo"], item["milestone"]): item for item in targets}
                selected_targets = [expected_target_map[identity] for identity in selected_identities if identity in expected_target_map]
                if not selected_targets:
                    selected_targets = [targets[0]]
                risk_classes = sorted({risk for target in selected_targets for risk in target["risk_classes"]})
                route_complexity = max(target["complexity"] for target in selected_targets)
                routes = [
                    route_fixture("developer", "ctx-developer", registry, route_complexity, risk_classes),
                    route_fixture("tester", "ctx-tester", registry, route_complexity, risk_classes),
                    route_fixture("gate", "ctx-gate", registry, route_complexity, risk_classes),
                ]
                unsigned = copy.deepcopy(value)
                unsigned["preflight"].pop("authorization", None)
                authorization = {"schema": "signed-preflight-authorization-v1", "signer_id": "preflight-gate", "signed_at": "2026-07-11T11:00:00Z", "envelope_sha256": sha(canonical_json(unsigned).encode()), "draft_payload_sha256": targets[0]["draft_payload_sha256"], "locked_payload_sha256": targets[0]["locked_payload_sha256"], "lock_transform_manifest_sha256": targets[0]["lock_transform_manifest_sha256"], "final_locked_commit_oid": targets[0]["target_object_id"], "route_records": routes, "route_records_sha256": sha(canonical_json(routes).encode()), "pre_execution_intents_sha256": plan["pre_execution_intents_sha256"], "risk_classes": risk_classes, "risk_classes_sha256": sha(canonical_json(risk_classes).encode())}
                value["preflight"]["authorization"] = sign_fixture(authorization, registry)
                return value

            first = targets[0]
            first_rows = rows_by_identity[(first["repo"], first["milestone"])]
            single = authorize({"preflight": {"status": "green", "mode": "single", "rows": copy.deepcopy(first_rows)}, "next_skill": "cruise-dev-supervise"})

            per_repo = []
            batch = []
            for target in targets:
                target_rows = rows_by_identity[(target["repo"], target["milestone"])]
                binding = {
                    "rows_sha256": sha(canonical_json(target_rows).encode()),
                    "workflow_semantic_result_sha256": target_rows["workflow"]["semantic_result_sha256"],
                    "semantic_results_sha256": sha(canonical_json({name: target_rows[name]["semantic_result_sha256"] for name in sorted(target_rows)}).encode()),
                    "evidence_set_sha256": sha(canonical_json({name: target_rows[name]["evidence_artifact_sha256"] for name in sorted(target_rows)}).encode()),
                }
                common = {field: target[field] for field in ["repo", "milestone", "issue", "issue_number", "branch", "target_object_id", "target_repo_head_sha", "dependency_closure_sha256"]}
                intent_binding = {field: target[field] for field in ["risk_classes", "pre_execution_intent_sha256"]}
                per_repo.append({**common, "batch_id": "batch-1", **intent_binding, **binding, "rows": copy.deepcopy(target_rows)})
                batch.append({**common, "batch_id": "batch-1", "complexity": target["complexity"], **intent_binding, "acceptance_criteria": target["acceptance_criteria"], **binding})
            multi = authorize({"preflight": {"status": "green", "mode": "multi", "batch_id": "batch-1", "per_repo": per_repo, "batch": batch, "max_parallel": 2, "cross_repo_deps": []}, "next_skill": "cruise-dev-supervise"})
            validate_preflight_envelope(single, plan, registry, now, [first], [], allow_fixture_clock=True)
            validate_preflight_envelope(multi, plan, registry, now, targets, [], allow_fixture_clock=True)

            mutations: list[tuple[dict[str, Any], list[dict[str, Any]]]] = []
            for label, mutate in [
                ("extra-batch", lambda value: value["preflight"]["batch"].append({**copy.deepcopy(value["preflight"]["batch"][0]), "repo": "attacker"})),
                ("missing-batch", lambda value: value["preflight"]["batch"].pop()),
                ("duplicate-per-repo", lambda value: value["preflight"]["per_repo"].append(copy.deepcopy(value["preflight"]["per_repo"][0]))),
                ("unknown-field", lambda value: value["preflight"]["batch"][0].update({"unknown": True})),
                ("branch-drift", lambda value: value["preflight"]["batch"][0].update({"branch": "issue/999-attacker"})),
                ("head-drift", lambda value: value["preflight"]["per_repo"][0].update({"target_repo_head_sha": "b" * 40})),
                ("workflow-drift", lambda value: value["preflight"]["batch"][0].update({"workflow_semantic_result_sha256": "0" * 64})),
                ("rows-drift", lambda value: value["preflight"]["per_repo"][0].update({"rows_sha256": "0" * 64})),
            ]:
                changed = copy.deepcopy(multi)
                mutate(changed)
                mutations.append((authorize(changed), targets))
            fail_row = copy.deepcopy(single)
            fail_row["preflight"]["rows"]["routing"]["status"] = "FAIL"
            mutations.append((authorize(fail_row), [first]))
            old_object = copy.deepcopy(single)
            old_object["preflight"]["rows"]["routing"]["target_object_id"] = "b" * 40
            mutations.append((authorize(old_object), [first]))
            attacker_next = authorize({"preflight": {key: copy.deepcopy(item) for key, item in single["preflight"].items() if key != "authorization"}, "next_skill": "attacker-skill"})
            mutations.append((attacker_next, [first]))
            for mutation, expected_targets in mutations:
                try:
                    validate_preflight_envelope(mutation, plan, registry, now, expected_targets, [], allow_fixture_clock=True)
                except ValidationError:
                    continue
                raise ValidationError("re-signed malformed multi/single preflight envelope was accepted")
        finally:
            shutil.rmtree(evidence_dir)

    if not candidate_validation:
        check("preflight_and_transport", preflight_and_transport)

    def plan_lock_genesis_transport_boundary() -> None:
        registry = fixture_key_registry()
        now = validate_fixture_clock(fixture_clock_document(plan), plan)
        consumer_head = "a" * 40
        genesis = build_genesis_transport_context_fixture(plan, registry, "plan-lock-genesis", "helianthus-execution-plans", "FMB-00D", consumer_head)
        result = validate_transport_context(genesis, plan, registry, now, consumer_head, "helianthus-execution-plans", "FMB-00D", "PLAN_LOCK")
        require(result["validation_phase"] == "PLAN_LOCK" and all(result[name] == [] for name in plan["transport_intent_contract"]["derived_sets"]), "PLAN_LOCK genesis transport did not remain empty")

        runtime = build_transport_context_fixture(
            plan, registry, "runtime-m8", ["SUNSPEC-GENERIC-TCP-DIRECT-V1"], [], [], "GO", "GO", consumer_head,
            consumer_repo="helianthus-modbusreg", consumer_issue="FMB-08B",
            source_heads={"inventory": "1" * 40, "scope": "2" * 40, "huawei": "3" * 40},
        )
        runtime_result = validate_transport_context(runtime, plan, registry, now, consumer_head, "helianthus-modbusreg", "FMB-08B", "RUNTIME_M8")
        require([row["source_head_sha"] for row in runtime_result["source_artifact_bindings"]] == ["1" * 40, "2" * 40, "3" * 40] and all(row["source_head_sha"] != consumer_head for row in runtime_result["source_artifact_bindings"]), "runtime transport sources were forced to the consumer HEAD")
        for wrong_value, phase in [(runtime, "PLAN_LOCK"), (genesis, "RUNTIME_M8")]:
            try:
                validate_transport_context(wrong_value, plan, registry, now, consumer_head, validation_phase=phase)
            except ValidationError:
                pass
            else:
                raise ValidationError("schedule-inverted transport context crossed the PLAN_LOCK/M8 boundary")
        for substitute in [
            {"wrapper": runtime["inventory_artifact"]},
            {"payload": {"renamed": runtime["profile_scope_artifact"]}},
            {"nested": [{"copy": runtime["huawei_scope_artifact"]}]},
        ]:
            try:
                reject_post_lock_transport_substitutes(substitute, plan)
            except ValidationError:
                continue
            raise ValidationError("transitive issue-owned post-lock transport substitute was accepted")
        for kind, field, replacement in [("inventory", "producer_repo", "attacker-repo"), ("scope", "producer_issue", "FMB-08A"), ("huawei", "authority_id", "attacker-authority")]:
            changed = copy.deepcopy(runtime)
            artifact_key = {"inventory": "inventory_artifact", "scope": "profile_scope_artifact", "huawei": "huawei_scope_artifact"}[kind]
            artifact = changed[artifact_key]
            artifact[field] = replacement
            changed[artifact_key] = sign_fixture({key: item for key, item in artifact.items() if key not in {"signature", "revocation_generation"}}, registry)
            index = {"inventory": 0, "scope": 1, "huawei": 2}[kind]
            changed["source_bindings"][index] = transport_source_binding(kind, changed[artifact_key])
            changed = sign_fixture({key: item for key, item in changed.items() if key not in {"signature", "revocation_generation"}}, registry)
            try:
                validate_transport_context(changed, plan, registry, now, consumer_head, "helianthus-modbusreg", "FMB-08B", "RUNTIME_M8")
            except ValidationError:
                continue
            raise ValidationError(f"runtime transport accepted wrong source producer binding: {kind}/{field}")

    check("plan_lock_genesis_transport_boundary", plan_lock_genesis_transport_boundary)

    def deterministic_fixture_clock_and_live_separation() -> None:
        registry = fixture_key_registry()
        clock = fixture_clock_document(plan)
        fixed = validate_fixture_clock(clock, plan)
        genesis = build_genesis_transport_context_fixture(plan, registry, "clock-boundary", "helianthus-execution-plans", "FMB-00D", "a" * 40)
        issued = parse_utc(genesis["issued_at"])
        expiry = parse_utc(genesis["expiry"])
        for instant in [issued, expiry, fixed]:
            validate_transport_context(genesis, plan, registry, instant, "a" * 40, "helianthus-execution-plans", "FMB-00D", "PLAN_LOCK")
        for instant in [issued - timedelta(seconds=1), expiry + timedelta(seconds=1)]:
            try:
                validate_transport_context(genesis, plan, registry, instant, "a" * 40, "helianthus-execution-plans", "FMB-00D", "PLAN_LOCK")
            except ValidationError:
                continue
            raise ValidationError("transport freshness accepted before-issued or after-expiry fixture time")
        changed = dict(clock, provenance_id="attacker-clock")
        changed["provenance_sha256"] = sha(canonical_json({key: item for key, item in changed.items() if key != "provenance_sha256"}).encode())
        try:
            validate_fixture_clock(changed, plan)
        except ValidationError:
            pass
        else:
            raise ValidationError("untrusted fixture clock provenance accepted")
        contract = plan["terminal_repair_10_contracts"]["deterministic_clock"]
        require(contract["live_path"] == "external-lock-and-live-preflight-use-system-utc-outside-report-digest" and contract["report_digest_includes_live_time"] is False, "live freshness path is not explicitly separated from deterministic report execution")

    check("deterministic_fixture_clock_and_live_freshness_separation", deterministic_fixture_clock_and_live_separation)

    def huawei_fact_id_scope_affinity() -> None:
        registry = fixture_key_registry()
        now = validate_fixture_clock(fixture_clock_document(plan), plan)
        desired = {scope: "GO" for scope in plan["architecture"]["huawei_fact_outcome_scopes"]}
        desired["emma.direct"] = desired["emma.downstream"] = "DEFER"
        packet = build_huawei_fixture_packet(plan, registry, desired, "FACT-AFFINITY")
        result = validate_huawei_provenance_packet(packet, plan, registry, now)
        require(len(result["fact_mapping"]) == len(packet["observations"]) and HEX64_RE.match(result["fact_binding_root_sha256"]) is not None, "Huawei fact mapping/root coverage drift")
        smartlogger = next(row for row in packet["observations"] if row["scope"] == "smartlogger.gateway")
        s_dongle = next(row for row in packet["observations"] if row["scope"] == "s_dongle.gateway")
        reused = copy.deepcopy(packet)
        next(row for row in reused["observations"] if row["observation_id"] == s_dongle["observation_id"])["fact_id"] = smartlogger["fact_id"]
        reused = resign_huawei_fixture_packet(reused, registry)
        conflicting = copy.deepcopy(packet)
        target = next(row for row in conflicting["observations"] if row["scope"] == "s_dongle.gateway")
        target["fact_id"] = smartlogger["fact_id"]
        target["observation_outcome"] = "NO_GO"
        conflicting = resign_huawei_fixture_packet(conflicting, registry)
        for label, mutation in [("cross-SmartLogger-S-Dongle-reuse", reused), ("conflicting-conclusion", conflicting)]:
            try:
                validate_huawei_provenance_packet(mutation, plan, registry, now)
            except ValidationError:
                continue
            raise ValidationError(f"validly re-signed Huawei packet accepted fact_id affinity violation: {label}")

    check("huawei_fact_id_scope_affinity", huawei_fact_id_scope_affinity)

    def local_route_resolver() -> None:
        if candidate_validation:
            require(model_policy_path is not None and model_policy_path.is_file() and model_route_path is not None and model_route_path.is_file(), "candidate route authorities missing")
            require(sha(model_policy_path.read_bytes()) == plan["execution_mode_contract"]["model_routing_policy_sha256"] and sha(model_route_path.read_bytes()) == plan["execution_mode_contract"]["resolver_script_sha256"], "candidate route authority bytes drift")
            for role in plan["execution_mode_contract"]["required_roles"]:
                output = json.loads(subprocess.run(canonical_route_command(plan, role, model_route_path), check=True, text=True, capture_output=True).stdout)
                require(output.get("vendor") == "openai" and output.get("model") == "gpt-5.6-sol" and output.get("reasoning_effort") == "max" and not output.get("fallback_used", output.get("fallback", False)) and output.get("capability_degraded") is False, f"candidate route below lock minimum: {role}")
            return
        paths = derive_authority_paths(root)
        policy, resolver = paths["model_policy"], paths["model_resolver"]
        if model_policy_path is not None:
            require(model_policy_path.resolve() == policy, "alternate routing policy path rejected")
        if model_route_path is not None:
            require(model_route_path.resolve() == resolver, "alternate routing resolver path rejected")
        observed, outputs = canonical_route_audit(plan, paths)
        require(all(row["argv"][1] == str(resolver) for row in outputs), "canonical route audit used a shadow resolver")
        mismatches = [role for role, row in observed.items() if row["mismatch"]]
        require(observed == plan["execution_mode_contract"]["current_role_mismatch_matrix"], "live resolver mismatch matrix is incomplete or stale")
        require(mismatches == ["gate"] and mismatches == plan["terminal_repair_7_contracts"]["model_route_gate"]["mismatched_roles"], "current resolver gaps are not exhaustively enumerated")
        required_gate_state = "complete_verified" if expected_state == "locked" else "pending_external_operator"
        require(next(item for item in plan["planning_gates"] if item["id"] == "PG-MODEL-ROUTING-POLICY-AMENDMENT")["state"] == required_gate_state, "PG-MODEL state does not match package state")

    if not candidate_validation:
        check("local_model_route_policy_and_resolver_replay", local_route_resolver)

    def inventory_and_aggregation() -> None:
        rows = plan["profile_candidate_inventory"]["rows"]
        required = {"id", "aggregation_key", "fact_scope", "standard", "vendor", "family", "transport", "attachment", "gateway", "consumer", "profile_artifact"}
        require(len(rows) == 10 and len({row["id"] for row in rows}) == 10, "inventory completeness drift")
        require(all(set(row) == required and row["consumer"] in ids for row in rows), "inventory row schema drift")
        groups = plan["profile_family_aggregations"]["groups"]
        grouped = [row_id for group in groups for row_id in group["rows"]]
        require(sorted(grouped) == sorted(row["id"] for row in rows), "aggregation does not cover inventory exactly once")
        for group in groups:
            matching = [row for row in rows if row["id"] in group["rows"]]
            require(all(row["aggregation_key"] == group["key"] and row["consumer"] == group["consumer"] and row["profile_artifact"] == group["artifact"] for row in matching), f"aggregation identity drift: {group['key']}")
        require(plan["derived_node_sets"]["selected_rtu_profile_nodes"]["projection"] == "row.consumer", "RTU projection drift")
        inventory_node = by_id["FMB-08A-INVENTORY"]
        require("FMB-08A" not in inventory_node["depends_on"] + inventory_node["schedule_after"] and "FMB-08A-CUSTODY" not in inventory_node["depends_on"] + inventory_node["schedule_after"], "neutral inventory depends on Huawei custody/facts")
        for node in ["FMB-08B", "FMB-08C", "FMB-08D", "FMB-08E"]:
            require(all(edge["source"] not in {"FMB-08A", "FMB-08A-CUSTODY"} for edge in by_id[node]["consumes_if"]), f"neutral profile consumes Huawei artifact: {node}")
        for scenario_id in ["custody-no-go", "custody-defer-neutral-release", "huawei-fact-defer-neutral-release"]:
            scenario = next(item for item in plan["topology_simulations"] if item["id"] == scenario_id)
            require(scenario["expected"]["node_states"]["FMB-08Q"] == "PASS", f"neutral release decoupling oracle missing: {scenario_id}")

    check("inventory_family_aggregation_and_rtu_derivation", inventory_and_aggregation)

    def ta5_machine_contracts() -> None:
        domain_inputs = plan["canonical_domain_inputs"]
        input_names = ["static_declarations", "runtime_registrations", "generated_catalog_input"]
        normalized_sets = []
        owners = set()
        for name in input_names:
            item = domain_inputs[name]
            require(item["owner"] not in owners and item["artifact"] in known_artifacts(plan), f"domain input owner/artifact drift: {name}")
            owners.add(item["owner"])
            entries = item["entries"]
            require(entries and all(set(entry) == set(domain_inputs["normalized_entry_fields"]) for entry in entries), f"domain input schema drift: {name}")
            normalized = sorted(entries, key=lambda entry: (entry["domain"], entry["capability"], entry["major"]))
            require(len(normalized) == len({(entry["domain"], entry["capability"], entry["major"]) for entry in normalized}), f"duplicate domain key: {name}")
            require(item["digest_sha256"] == sha(canonical_json(normalized).encode()), f"domain input digest drift: {name}")
            normalized_sets.append(normalized)
        require(normalized_sets[0] == normalized_sets[1] == normalized_sets[2], "static/runtime/generated domain input mismatch")
        require({entry["domain"] for entry in normalized_sets[0]} == {"hvac", "dhw", "energy", "solar"}, "entire canonical domain omitted")
        require(all(entry["state"] in domain_inputs["allowed_states"] for entry in normalized_sets[0]), "canonical domain state drift")
        require({(entry["domain"], entry["capability"], entry["state"]) for entry in normalized_sets[0]} >= {("hvac", "zones", "not_enabled"), ("dhw", "hot_water", "not_enabled"), ("energy", "cumulative", "supported"), ("solar", "pv_generation", "supported")}, "full HVAC/DHW/energy/solar inventory drift")
        require(domain_inputs["runtime_registrations"]["availability"] == "AVAILABLE-required-for-catalog-and-private-manifests", "runtime registrations not required AVAILABLE")
        require(domain_inputs["private_manifest_inputs"]["required_digest_sha256"] == domain_inputs["static_declarations"]["digest_sha256"] and domain_inputs["private_manifest_inputs"]["required_full_rows"] is True, "private manifests do not bind full domain inventory")
        oracle = plan["topology_oracle_contract"]
        required_expected = set(oracle["required_expected_fields"])
        require(all(set(scenario["expected"]) == required_expected for scenario in plan["topology_simulations"]), "oracle fixture is partial or opaque")
        require(all(len(scenario["expected"]["node_states"]) == len(ids) and set(scenario["expected"]["artifacts"]) == known_artifacts(plan) for scenario in plan["topology_simulations"]), "oracle node/artifact closure incomplete")
        observed_terminal = {(node, state) for scenario in plan["topology_simulations"] for node, state in scenario["expected"]["node_states"].items()}
        declared_terminal = {(milestone["id"], outcome) for milestone in milestones for outcome in milestone["allowed_terminal_outcomes"]}
        typed_terminal = plan["terminal_repair_7_contracts"]["huawei_observations"]["typed_milestone_path"]
        typed_coverage = {(typed_terminal["milestone"], typed_terminal["terminal_outcome"])}
        require(declared_terminal <= observed_terminal | typed_coverage, "MC/DC omits declared terminal branch")
        coverage = plan["mcdc_coverage"]
        require(set(coverage["predicate_operators"]) == set(plan["predicate_action_schema"]["predicate_operators"]) and all(coverage["predicate_operators"].values()), "predicate MC/DC coverage drift")
        require(set(coverage["action_operators"]) == set(plan["predicate_action_schema"]["action_operators"]) and all(coverage["action_operators"].values()), "action MC/DC coverage drift")
        require(set(coverage["milestone_terminal_outcomes"]) == {f"{node}:{state}" for node, state in declared_terminal}, "terminal MC/DC table drift")
        require(set(coverage["outcome_rule_cases"]) == {f"{rule['id']}#{index}" for rule in plan["outcome_rules"] for index, _ in enumerate(rule["cases"])}, "outcome-rule MC/DC table drift")
        scope_only = next(item for item in plan["topology_simulations"] if item["id"] == "m2r-na-with-rtu-go")["expected"]
        require("SUNSPEC-GENERIC-RTU-DIRECT-V1" in scope_only["scope_selected_inventory_rows"] and "SUNSPEC-GENERIC-RTU-DIRECT-V1" in scope_only["fact_cleared_inventory_rows"] and "SUNSPEC-GENERIC-RTU-DIRECT-V1" not in scope_only["executable_inventory_rows"], "M2R changed immutable inventory/fact selection")
        huawei_defer = next(item for item in plan["topology_simulations"] if item["id"] == "smartlogger-downstream-scope-without-fact")["expected"]
