        require(route_gate["state"] == required_route_gate_state and contract["model_route_gate"]["mismatched_roles"] == ["gate"] and contract["model_route_gate"]["matching_roles"] == ["planner", "adversary", "developer", "reviewer-primary", "reviewer-secondary", "tester"], "PG-MODEL exhaustive mismatch/gate drift")

