    evaluated: dict[str, dict[str, Any]] = {}

    def evaluator() -> None:
        for scenario in plan["topology_simulations"]:
            result = evaluate_scenario(plan, scenario)
            result["plan_node_sets"] = plan["node_sets"]
            assert_result_semantics(plan, result)
            compare_expected(result, scenario["expected"], plan)
            trace = result["transition_trace"]
            require([item["seq"] for item in trace] == list(range(1, len(trace) + 1)) and all(set(item) == set(plan["execution_state_model"]["transition_trace_fields"]) for item in trace), f"transition trace schema/order drift: {scenario['id']}")
            terminal_seen: dict[str, str] = {}
            for item in trace:
                require(item["node"] not in terminal_seen, f"terminal transition was not immutable: {scenario['id']}/{item['node']}")
                if item["to"] in plan["topology_evaluator"]["terminal_states"]:
                    terminal_seen[item["node"]] = item["to"]
            require(len({(item["node"], item["from"], item["to"], item["cause"]) for item in trace}) == len(trace), f"transition oscillation/repetition: {scenario['id']}")
            reverse = evaluate_scenario(plan, scenario, reverse_inputs=True)
            reverse["plan_node_sets"] = plan["node_sets"]
            require(canonical_json(result) == canonical_json(reverse), f"order-dependent evaluator result: {scenario['id']}")
            evaluated[scenario["id"]] = result
        required = {"initial-after-lock", "initial-missing-skill-adapter", "initial-altered-architecture-map", "initial-revoked-skill-adapter", "expansion-empty", "single-sunspec-tcp", "single-sunspec-rtu", "single-growatt-tcp", "single-growatt-rtu", "single-smartlogger", "single-s-dongle", "single-huawei-rtu-direct", "single-huawei-rtu-downstream", "mixed-tcp-rtu", "m2r-na-with-rtu-go", "m2r-pass-no-rtu-selected", "smartlogger-asymmetric-gateway-go-downstream-defer", "smartlogger-gateway-only", "smartlogger-downstream-only", "smartlogger-downstream-scope-without-fact", "s-dongle-gateway-only", "s-dongle-downstream-only", "s-dongle-gateway-scope-without-fact", "runtime-gap-without-unlock", "runtime-gap-valid-unlock"}
        require(required <= set(evaluated), "required evaluator scenario missing")

