    def ta8_external_authority_probe() -> None:
        paths = derive_authority_paths(root)
        require(paths == authority_paths and paths["root_agents"] == paths["workspace"] / "AGENTS.md", "canonical authority topology drift")
        matrix, outputs = canonical_route_audit(plan, paths)
        require(matrix == plan["execution_mode_contract"]["current_role_mismatch_matrix"] and [role for role, row in matrix.items() if row["mismatch"]] == ["gate"], "current canonical routing mismatch matrix drift")
        require(all(row["argv"] == canonical_route_command(plan, row["role"], paths["model_resolver"]) for row in outputs), "routing audit used a non-canonical query or shadow resolver")
        blockers = plan["terminal_repair_8_contracts"]["current_external_blockers"]
        missing_adapters = current_skill_adapter_blockers(plan, paths["skill_root"])
        require(set(missing_adapters) == set(blockers["skill_adapters"]), "current real skill adapter blockers are stale")
        require(current_skill_semantic_blockers(paths["skill_root"]) == sorted(blockers["skill_semantics"]), "current review-skill semantic blockers are stale")
        parsed = parse_root_architecture_authority(paths["root_agents"].read_text(), plan)
        require("structured-authority-block-missing" in parsed["contradictions"] and all(any(key in item for item in parsed["contradictions"]) for key in next(item for item in plan["external_planning_artifacts"] if item["id"] == "ARCHITECTURE-MAP-AMENDMENT-V1")["required_additive_checkout_map"]), "current root architecture blockers are not executable facts")
        require(any(item in parsed["contradictions"] for item in ["separate-protocol-repository-rule", "protocol-repository-naming-rule", "sunspec-repository-row"]), "current root architecture conflict was hidden")
        require({"structured-invariant-authority-block-missing", "unchanged-root-invariant-1-no-parallel-merge-streams", "unchanged-root-invariant-6-dual-ai-review"} <= set(parsed["contradictions"]), "current root invariant conflicts were hidden")
        require({"planned-cross-repo-parallelism-conflicts-with-root-invariant-1", "operator-openai-only-mode-conflicts-with-root-invariant-6"} <= set(blockers["root_architecture"]), "pending root invariant amendment blocker inventory drift")
        git_probe = subprocess.run(["git", "-C", str(paths["workspace"]), "rev-parse", "--show-toplevel"], check=False, text=True, capture_output=True)
        require(git_probe.returncode != 0 and blockers["routing"] == ["gate-resolves-gpt-5.6-luna-medium-not-gpt-5.6-sol-max"], "current root/routing blockers are not truthful")
        require(expected_state == "draft" and all(next(item for item in plan["planning_gates"] if item["id"] == gate)["state"] == "pending_external_operator" for gate in ["PG-SKILL-ADAPTER-REGISTRY", "PG-ARCHITECTURE-MAP-AMENDMENT", "PG-MODEL-ROUTING-POLICY-AMENDMENT"]), "incompatible external authorities did not block lock readiness")

