        def validate_mapping(fact: str, applicability: str, scope: str) -> None:
            require(applicability in {"APPLICABLE", "NOT_APPLICABLE"}, "invalid Huawei applicability outcome")
            expected = "N/A" if applicability == "NOT_APPLICABLE" else mapping["fact_to_scope"][fact]
            require(scope == expected, "Huawei fact-to-scope executable mapping drift")
        for fact, expected in mapping["fact_to_scope"].items():
            validate_mapping(fact, "APPLICABLE", expected)
            for wrong in {"GO", "NO_GO", "DEFER", "N/A"} - {expected}:
                try:
                    validate_mapping(fact, "APPLICABLE", wrong)
                except ValidationError:
                    continue
                raise ValidationError(f"wrong Huawei scope mapping accepted: {fact}->{wrong}")
        validate_mapping("GO", "NOT_APPLICABLE", "N/A")
        try:
            validate_mapping("GO", "APPLICABLE", "N/A")
        except ValidationError:
            pass
        else:
            raise ValidationError("Huawei N/A accepted without separate applicability evidence")

