    def ta9_lock_boundary() -> None:
        metadata = next(item for item in plan["external_planning_artifacts"] if item["id"] == "EXTERNAL-LOCK-METADATA-V1")
        boundary = plan["terminal_repair_9_contracts"]["plan_lock_boundary"]
        require(metadata["schema"] == boundary["external_metadata_schema"] == "external-lock-metadata-v5" and metadata["metadata_version"] == 5, "PLAN_LOCK external metadata schema drift")
        require(not (set(metadata["required_fields"]) & set(boundary["forbidden_fields"])), "PLAN_LOCK still requires future Huawei issue state")
        require(not any("Huawei" in surface or "huawei" in surface for surface in plan["terminal_repair_7_contracts"]["complete_lock_validation"]["required_surfaces"]), "complete PLAN_LOCK validation still contains Huawei issue result surface")
        require(by_id["FMB-08A-SCOPE"].get("produces") == ["scope-selected-profile-set-v1"], "scope authorization issue still fabricates fact-cleared or executable issue results")
        require(set(by_id["FMB-08G-CLOSE"].get("produces", [])) == {"scope-selected-profile-set-v1", "fact-cleared-profile-set-v1", "executable-profile-set-v1", "selected-rtu-profile-set-v1"}, "post-FMB-08A closure does not own derived executable sets")
        huawei_consumers = ["FMB-08F", "FMB-08F-SD", "FMB-08G-RED"]
        for issue in huawei_consumers:
            milestone = by_id[issue]
            sources = set(milestone["depends_on"]) | {edge["source"] for edge in milestone["consumes_if"]}
            require("FMB-08A" in sources, f"Huawei consumer lacks FMB-08A issue-owned fact dependency: {issue}")
        closure_sources = {edge["source"] for edge in by_id["FMB-08G-CLOSE"]["consumes_if"]}
        require({"FMB-08F", "FMB-08F-SD", "FMB-08G-RED"} <= closure_sources, "profile closure bypasses FMB-08A-gated Huawei producers")
        for issue in ["FMB-08I", "FMB-08J", "FMB-08K", "FMB-08O", "FMB-08Q"]:
            require(any(edge["source"] == "FMB-08G-CLOSE" and edge["artifact"] in {"fact-cleared-profile-set-v1", "executable-profile-set-v1", "selected-rtu-profile-set-v1"} for edge in by_id[issue]["consumes_if"]), f"downstream profile consumer bypasses FMB-08A-enforced closure: {issue}")

