    def ta8_private_manifest_lineage() -> None:
        contract = plan["terminal_repair_8_contracts"]["private_manifest_inputs"]
        for issue in ["FMB-07A", "FMB-08EEBUS-A", "FMB-09A"]:
            milestone = by_id[issue]
            observed_sources = milestone["depends_on"] + [edge["source"] for edge in milestone["consumes_if"]]
            require(set(observed_sources) == set(contract[issue]) and not (set(observed_sources) & set(contract["forbidden_artifact_sources"])), f"private manifest source drift: {issue}")
        require(contract["signed_manifest_source"] == "FMB-07A" and by_id["FMB-07B"]["depends_on"][0] == "FMB-07A" and "FMB-07A" in by_id["FMB-08EEBUS-A"]["depends_on"], "FMB-08EEBUS-A signed FMB-07A manifest lineage drift")
        require(contract["schedule_only_predecessor"] == "FMB-07B" and by_id["FMB-08EEBUS-A"]["schedule_after"] == ["FMB-07B"] and "FMB-07B" not in by_id["FMB-08EEBUS-A"]["depends_on"] and all(edge["source"] != "FMB-07B" for edge in by_id["FMB-08EEBUS-A"]["consumes_if"]), "FMB-07B supplied more than schedule ordering to FMB-08EEBUS-A")
        manifest_reference = next(row for row in plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS-A"]["consumed_artifacts"] if row["source"] == "FMB-07A")
        require(manifest_reference == consumed_artifact_reference("FMB-07A", "eebus-base-feature-manifest-v1", "depends_on", {"op": "always"}, plan), "FMB-08EEBUS-A producer envelope does not bind full FMB-07A identity")
        choice = expected_eebus_successor_lineage_choice(plan)
        require(plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS"]["successor_lineage_choice"] == choice and plan["fresh_genesis_contract"]["owner"] == "FMB-08EEBUS", "eeBUS extension/genesis choice is not owned by FMB-08EEBUS")
        predecessor_rule = next(rule for rule in plan["outcome_rules"] if rule["id"] == "OR-EEBUS-PREDECESSOR")
        require(all(all(action.get("target", "FMB-08EEBUS") == "FMB-08EEBUS" for action in case["actions"] if action["op"] == "emit_fresh_genesis") for case in predecessor_rule["cases"]), "fresh eeBUS genesis still targets the successor manifest issue")
        require(("FMB-07B", "FMB-08EEBUS") in predicate_edges(plan), "eeBUS lineage choice is absent from the evaluator/DAG")
        for issue, forbidden in itertools.product(["FMB-07A", "FMB-08EEBUS-A", "FMB-09A"], contract["forbidden_artifact_sources"]):
            mutant = copy.deepcopy(by_id[issue])
            mutant["consumes_if"].append({"source": forbidden, "artifact": by_id[forbidden]["acceptance_artifact"], "when": {"op": "always"}})
            sources = mutant["depends_on"] + [edge["source"] for edge in mutant["consumes_if"]]
            try:
                require(not (set(sources) & set(contract["forbidden_artifact_sources"])), "forbidden-private-source")
            except ValidationError:
                continue
            raise ValidationError(f"forbidden private source mutation survived: {forbidden}->{issue}")

    check("private_manifest_lineage_and_schedule_only", ta8_private_manifest_lineage)
