        require(contract["base_fixture_binding"] == expected_eebus_base_fixture_binding(plan) and contract["composition_schema"] == "fmb-08eebus-executable-fixture-composition-v1", "eeBUS canonical fixture composition binding drift")
        require([item["predecessor_outcome"] for item in fixtures] == contract["covered_predecessor_outcomes"] == by_id["FMB-07B"]["allowed_terminal_outcomes"], "eeBUS selected producer fixture branch coverage drift")
        manifest_inputs = plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS-A"]["consumed_artifacts"]
        require(any(item == consumed_artifact_reference("FMB-07A", "eebus-base-feature-manifest-v1", "depends_on", {"op": "always"}, plan) for item in manifest_inputs), "FMB-08EEBUS-A executable inputs do not consume the signed FMB-07A manifest")
        require(by_id["FMB-08EEBUS-A"]["schedule_after"] == ["FMB-07B"] and "FMB-07B" not in by_id["FMB-08EEBUS-A"]["depends_on"] and all(item["source"] != "FMB-07B" for item in by_id["FMB-08EEBUS-A"]["consumes_if"]), "FMB-07B is not schedule-only for FMB-08EEBUS-A")
        require(plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS"]["successor_lineage_choice"] == expected_eebus_successor_lineage_choice(plan), "extension/genesis selection escaped FMB-08EEBUS ownership")

        registry = fixture_key_registry()
        executions = [validate_eebus_selected_producer_fixture(fixture, plan, registry) for fixture in fixtures]
        expected_report = expected_eebus_fixture_execution_report(plan)
        report = {
            "schema": expected_report["schema"],
            "fixture_schema": expected_report["fixture_schema"],
            "composition_schema": expected_report["composition_schema"],
            "fixture_ids": [item["fixture_id"] for item in executions],
            "executions": executions,
        }
        report["fixture_set_sha256"] = sha(canonical_json(report).encode())
        require(report == expected_report, "eeBUS fixture executions did not produce the deterministic report receipt set")

        base = fixtures[0]
        choice = expected_eebus_successor_lineage_choice(plan)
        mutations: list[tuple[str, dict[str, Any]]] = []
        changed = copy.deepcopy(base); changed["selected_producer_envelopes"] = []; mutations.append(("zero-selected", changed))
        changed = copy.deepcopy(base); other = choice["producer_envelopes"][1]; changed["selected_producer_envelopes"].append({"reference": copy.deepcopy(other), "evidence_payload": deterministic_dependency_evidence_payload(other)}); mutations.append(("both-selected", changed))
        changed = copy.deepcopy(base); changed["selected_producer_envelopes"][0]["reference"]["producer_issue"] = "ATTACKER-PRODUCER"; changed["selected_producer_envelopes"][0]["evidence_payload"]["producer_issue"] = "ATTACKER-PRODUCER"; mutations.append(("wrong-producer", changed))
        changed = copy.deepcopy(base); changed["selected_producer_envelopes"][0]["reference"]["condition_ast"] = {"op": "outcome_is", "node": "FMB-07B", "outcome": "NO_GO"}; mutations.append(("wrong-condition", changed))
        changed = copy.deepcopy(base); changed["selected_producer_envelopes"][0]["evidence_payload"]["producer_head_oid"] = "f" * 40; mutations.append(("stale-identity", changed))
        changed = copy.deepcopy(base); changed["selected_producer_envelopes"][0].pop("evidence_payload"); mutations.append(("envelope-omission", changed))
        require([label for label, _ in mutations] == contract["mutation_classes"], "eeBUS selected producer mutation class coverage drift")
        for label, mutation in mutations:
            try:
                validate_eebus_selected_producer_fixture(mutation, plan, registry)
            except ValidationError:
                continue
            raise ValidationError(f"eeBUS selected producer mutation accepted: {label}")

        composition_mutations: list[tuple[str, dict[str, Any]]] = []
        changed_plan = copy.deepcopy(plan)
        machine = changed_plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS"]
        machine["fixture_matrix"] = [row for row in machine["fixture_matrix"] if row["fixture_id"] != contract["base_fixture_id"]]
        composition_mutations.append(("base-fixture-omission", changed_plan))
        changed_plan = copy.deepcopy(plan)
        machine = changed_plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS"]
        next(row for row in machine["fixture_matrix"] if row["fixture_id"] == contract["base_fixture_id"])["input"]["source_head"] = "STALE"
        composition_mutations.append(("base-fixture-drift", changed_plan))
        changed_plan = copy.deepcopy(plan)
        machine = changed_plan["issue_machine_contracts"]["contracts"]["FMB-08EEBUS"]
        machine["test_ids"].remove(contract["base_fixture_id"])
        composition_mutations.append(("base-test-id-omission", changed_plan))
        require([label for label, _ in composition_mutations] == contract["composition_mutation_classes"], "eeBUS canonical fixture composition mutation coverage drift")
        for label, mutation_plan in composition_mutations:
            try:
                validate_eebus_selected_producer_fixture(base, mutation_plan, registry)
            except ValidationError:
                continue
            raise ValidationError(f"eeBUS canonical fixture composition mutation accepted: {label}")
        return report

