    def ta9_all_issue_commitments() -> None:
        contracts = plan["issue_machine_contracts"]["contracts"]
        required_fields = plan["terminal_repair_8_contracts"]["issue_execution"]["commitment_fields"]
        require(len(contracts) == len(milestones), "issue expected-behavior contract cardinality drift")
        for milestone in milestones:
            machine = contracts[milestone["id"]]
            validate_issue_execution_contract(plan, milestone, machine)
            require(milestone["acceptance_criteria"] == [line[6:] for line in milestone["issue_body"].splitlines() if line.startswith("- [ ] ")], f"issue acceptance/body mirror drift: {milestone['id']}")
            for field in required_fields:
                mutant = dict(machine)
                del mutant[field]
                try:
                    validate_issue_execution_contract(plan, milestone, mutant)
                except ValidationError:
                    continue
                raise ValidationError(f"issue commitment mutation accepted: {milestone['id']}/{field}")
            noop = copy.deepcopy(machine)
            noop["behavior_contract"]["operation"] = "NO_OP"
            try:
                validate_issue_execution_contract(plan, milestone, noop)
            except ValidationError:
                pass
            else:
                raise ValidationError(f"no-op generic issue validator mutant survived: {milestone['id']}")
            limit_mutant = copy.deepcopy(machine)
            limit_field = expected_issue_limit_mutation_target(milestone).removeprefix("exact_limits.")
            limit_mutant["exact_limits"][limit_field] += 1
            try:
                validate_issue_execution_contract(plan, milestone, limit_mutant)
            except ValidationError:
                pass
            else:
                raise ValidationError(f"issue-specific normative limit mutant survived: {milestone['id']}/{limit_field}")
        validate_issue_commitment_authority(plan)

        changed = copy.deepcopy(plan)
        machine = changed["issue_machine_contracts"]["contracts"]["FMB-02A"]
        old_error = machine["behavior_contract"]["failure_outcomes"][0]["error_code"]
        machine["behavior_contract"]["failure_outcomes"][0]["error_code"] = "FMB-02A_ACCEPT_OVERSIZE_PDU"
        fixture = next(row for row in machine["fixture_matrix"] if row["expected_failure"] == old_error)
        fixture["expected_failure"] = "FMB-02A_ACCEPT_OVERSIZE_PDU"
        fixture["oracle_sha256"] = sha(canonical_json({key: item for key, item in fixture.items() if key != "oracle_sha256"}).encode())
        unsigned_machine = {key: item for key, item in machine.items() if key != "oracle_commitment_sha256"}
        machine["oracle_commitment_sha256"] = sha(canonical_json(unsigned_machine).encode())
        local_row = next(row for row in changed["terminal_repair_9_contracts"]["issue_oracles"]["rows"] if row["issue"] == "FMB-02A")
        local_row.update({
            "behavior_sha256": sha(canonical_json(machine["behavior_contract"]).encode()),
            "evidence_authority_sha256": sha(canonical_json(machine["evidence_authority"]).encode()),
            "applicability_authority_sha256": sha(canonical_json(machine["applicability_authority"]).encode()),
            "commands_sha256": sha(canonical_json(machine["exact_commands"]).encode()),
            "limits_sha256": sha(canonical_json(machine["exact_limits"]).encode()),
            "critical_oracle_sha256": sha(canonical_json(machine["critical_oracle"]).encode()),
            "fixtures_sha256": sha(canonical_json(machine["fixture_matrix"]).encode()),
            "protocols_sha256": sha(canonical_json(machine["protocol_cases"]).encode()),
            "rollback_sha256": sha(canonical_json(machine["rollback_pins"]).encode()),
            "acceptance_criteria_sha256": sha(canonical_json(machine["acceptance_criteria"]).encode()),
            "full_contract_sha256": machine["oracle_commitment_sha256"],
        })
        try:
            validate_issue_commitment_authority(changed)
        except ValidationError:
            pass
        else:
            raise ValidationError("changed failure expectations with recomputed adjacent hashes escaped the pinned external issue commitment")

        resigned = copy.deepcopy(changed)
        artifact = resigned["terminal_repair_10_contracts"]["issue_behavior_authority"]["commitment_artifact"]
        artifact["leaves"] = [{"issue": issue, "commitment_sha256": issue_commitment_leaf(resigned["issue_machine_contracts"]["contracts"][issue])} for issue in sorted(resigned["issue_machine_contracts"]["contracts"])]
        artifact["merkle_root_sha256"] = merkle_root([merkle_leaf(row) for row in artifact["leaves"]])
        payload = {key: item for key, item in artifact.items() if key not in {"signature_b64", "signed_payload_sha256"}}
        artifact["signed_payload_sha256"] = sha(canonical_json(payload).encode())
        try:
            validate_issue_commitment_authority(resigned)
        except ValidationError:
            pass
        else:
            raise ValidationError("locally recomputed issue commitment root was accepted without the external authority signature")

    check("concrete_issue_oracle_commitments", ta9_all_issue_commitments)

    def tr11_all_issue_acceptance_criteria() -> None:
        contracts = plan["issue_machine_contracts"]["contracts"]
        require(len(contracts) == len(milestones) and all(len(contracts[item["id"]]["acceptance_criteria"]) == 9 for item in milestones), "all-issue semantic acceptance criteria coverage drift")
        for milestone in milestones:
            machine = contracts[milestone["id"]]
            require(machine["acceptance_criteria"] == expected_issue_acceptance_criteria(milestone, machine) == milestone["acceptance_criteria"], f"behavior-derived acceptance criteria drift: {milestone['id']}")
            require([line[6:] for line in milestone["issue_body"].splitlines() if line.startswith("- [ ] ")] == milestone["acceptance_criteria"], f"issue body acceptance criteria drift: {milestone['id']}")
        for issue in ["FMB-03D", "FMB-02A", "FMB-06C", "FMB-08A", "FMB-09B", "FMB-00D"]:
            milestone = next(item for item in milestones if item["id"] == issue)
            changed = copy.deepcopy(contracts[issue])
            changed["acceptance_criteria"][0] = f"Generic wrapper accepted for {issue}."
            try:
                validate_issue_execution_contract(plan, milestone, changed)
            except ValidationError:
                continue
            raise ValidationError(f"cross-domain generic acceptance mutation accepted: {issue}")

        changed_plan = copy.deepcopy(plan)
        changed_machine = changed_plan["issue_machine_contracts"]["contracts"]["FMB-03D"]
        changed_machine["acceptance_criteria"][1] = "Run an interpolated issue ID wrapper without behavior-specific commands."
        unsigned = {key: item for key, item in changed_machine.items() if key != "oracle_commitment_sha256"}
        changed_machine["oracle_commitment_sha256"] = sha(canonical_json(unsigned).encode())
        local_row = next(row for row in changed_plan["terminal_repair_9_contracts"]["issue_oracles"]["rows"] if row["issue"] == "FMB-03D")
        local_row["acceptance_criteria_sha256"] = sha(canonical_json(changed_machine["acceptance_criteria"]).encode())
        local_row["full_contract_sha256"] = changed_machine["oracle_commitment_sha256"]
        artifact = changed_plan["terminal_repair_10_contracts"]["issue_behavior_authority"]["commitment_artifact"]
        artifact["leaves"] = [{"issue": issue, "commitment_sha256": issue_commitment_leaf(changed_plan["issue_machine_contracts"]["contracts"][issue])} for issue in sorted(changed_plan["issue_machine_contracts"]["contracts"])]
        artifact["merkle_root_sha256"] = merkle_root([merkle_leaf(row) for row in artifact["leaves"]])
        payload = {key: item for key, item in artifact.items() if key not in {"signature_b64", "signed_payload_sha256"}}
        artifact["signed_payload_sha256"] = sha(canonical_json(payload).encode())
        try:
            validate_issue_commitment_authority(changed_plan)
        except ValidationError:
            pass
        else:
            raise ValidationError("FMB-03D acceptance mutation escaped independent behavior commitment authority")

    check("terminal_repair_11_all_issue_acceptance_criteria", tr11_all_issue_acceptance_criteria)

    def ta12_issue_execution_class_audit() -> None:
        require(set(ISSUE_BEHAVIOR_CLASS_BY_ID) == ids and len(ISSUE_BEHAVIOR_CLASS_BY_ID) == len(milestones), "explicit issue behavior class authority does not cover exactly all issues")
        contracts = plan["issue_machine_contracts"]["contracts"]
        for milestone in milestones:
            expected = expected_issue_execution_class(milestone)
            require(milestone["execution_class"] == contracts[milestone["id"]]["execution_class"] == expected, f"issue execution class mirror drift: {milestone['id']}")
            for field, replacement in [("behavior_class", "attacker_class"), ("test_class", "attacker_test"), ("toolchain", "attacker_toolchain")]:
                changed = copy.deepcopy(contracts[milestone["id"]])
                changed["execution_class"][field] = replacement
                try:
                    validate_issue_execution_contract(plan, milestone, changed)
                except ValidationError:
                    continue
                raise ValidationError(f"issue execution class mutation accepted: {milestone['id']}/{field}")
        addon = next(item for item in milestones if item["id"] == "FMB-08O")
        addon_commands = expected_issue_commands(addon)
        command_bytes = canonical_json(addon_commands)
        require(addon["execution_class"] == {"schema": "explicit-issue-execution-class-v1", "repository_owner": "helianthus-ha-addon", "behavior_class": "release_activation", "test_class": "ha-addon-release-activation", "toolchain": "posix-shell+ha-cli"}, "FMB-08O execution class drift")
        require("go" not in {command[0] for command in addon_commands} and "./rtu" not in command_bytes and all(token in command_bytes for token in ["exact_addon_image", "staged_validation_wal", "smoke_live_addon_candidate"]), "FMB-08O still uses RTU tests or lacks exact-image/staged-WAL/live-candidate checks")

    check("terminal_repair_12_issue_execution_class_audit", ta12_issue_execution_class_audit)

    def ta12_failure_fixture_exact_set() -> None:
        for milestone in milestones:
            machine = plan["issue_machine_contracts"]["contracts"][milestone["id"]]
            declared = [row["error_code"] for row in machine["behavior_contract"]["failure_outcomes"]]
            observed = [row["expected_failure"] for row in machine["fixture_matrix"] if row["expected_failure"] is not None]
            expected_multiplicity = expected_failure_fixture_multiplicity(milestone)
            observed_multiplicity = {code: observed.count(code) for code in set(observed)}
            require(
                len(declared) == len(set(declared))
                and set(declared) == set(observed)
                and observed_multiplicity == expected_multiplicity,
                f"all-failure fixture coverage drift: {milestone['id']}",
            )
            failure_index = next(index for index, row in enumerate(machine["fixture_matrix"]) if row["expected_failure"] is not None)
            mutations: list[tuple[str, dict[str, Any]]] = []
            changed = copy.deepcopy(machine); changed["fixture_matrix"].pop(failure_index); mutations.append(("omission", changed))
            changed = copy.deepcopy(machine); changed["fixture_matrix"].append(copy.deepcopy(changed["fixture_matrix"][failure_index])); mutations.append(("duplicate", changed))
            changed = copy.deepcopy(machine); extra = copy.deepcopy(changed["fixture_matrix"][failure_index]); extra["fixture_id"] += "-EXTRA"; extra["expected_failure"] = milestone["id"] + "_EXTRA"; extra["oracle_sha256"] = sha(canonical_json({key: item for key, item in extra.items() if key != "oracle_sha256"}).encode()); changed["fixture_matrix"].append(extra); mutations.append(("extra", changed))
            changed = copy.deepcopy(machine); changed["fixture_matrix"][failure_index]["expected_failure"] = milestone["id"] + "_WRONG"; fixture = changed["fixture_matrix"][failure_index]; fixture["oracle_sha256"] = sha(canonical_json({key: item for key, item in fixture.items() if key != "oracle_sha256"}).encode()); mutations.append(("wrong-code", changed))
            for label, changed in mutations:
                changed["test_ids"] = [row["fixture_id"] for row in changed["fixture_matrix"]]
                try:
                    validate_issue_execution_contract(plan, milestone, changed)
                except ValidationError:
                    continue
                raise ValidationError(f"failure fixture {label} mutation accepted: {milestone['id']}")

    check("terminal_repair_12_all_failure_fixtures", ta12_failure_fixture_exact_set)

    def tr11_consumed_artifact_lineage() -> None:
        registry = fixture_key_registry()
        total = 0
        expected_reference_fields = set(plan["terminal_repair_11_contracts"]["consumed_artifacts"]["reference_fields"])
        for milestone in milestones:
            expected = expected_issue_topology_fields(milestone, plan)["consumed_artifacts"]
            machine = plan["issue_machine_contracts"]["contracts"][milestone["id"]]
            require(machine["consumed_artifacts"] == machine["behavior_contract"]["input_artifacts"] == expected, f"all-edge consumed artifact lineage drift: {milestone['id']}")
            require(all(set(row) == expected_reference_fields for row in expected), f"consumed artifact reference field set drift: {milestone['id']}")
            total += len(expected)
        require(total == sum(len(item["depends_on"]) + len(item["consumes_if"]) for item in milestones), "consumed artifact lineage does not cover every direct/conditional edge")

        target = next(item for item in milestones if item["id"] == "FMB-03D")
        reference = expected_issue_topology_fields(target, plan)["consumed_artifacts"][0]
        valid = deterministic_dependency_evidence(reference, registry)
        validate_dependency_artifact_evidence([valid], target, plan, registry, True)
        mutations = {
            "wrong-repo": {"producer_repo": "attacker-repo"},
            "stale-head": {"producer_head_oid": "a" * 40},
            "stale-tree": {"producer_tree_oid": "b" * 40},
            "wrong-schema": {"artifact_schema": "attacker-schema-v9"},
            "wrong-version": {"artifact_version": 999},
            "same-name-substitute": {"producer_issue": "FMB-03B"},
            "digest-mutation": {"content_digest_sha256": "c" * 64},
            "authority-mutation": {"producer_authority_id": "attacker-authority"},
        }
        for label, replacement in mutations.items():
            changed = {**valid, **replacement}
            changed = sign_fixture({key: item for key, item in changed.items() if key not in {"signature", "revocation_generation"}}, registry)
            try:
                validate_dependency_artifact_evidence([changed], target, plan, registry, True)
            except ValidationError:
                continue
            raise ValidationError(f"consumed artifact {label} mutation accepted")

    check("terminal_repair_11_consumed_artifact_lineage", tr11_consumed_artifact_lineage)

    def tr11_huawei_lineage_fact_identity() -> None:
        registry = fixture_key_registry()
        desired = {scope: "DEFER" for scope in plan["architecture"]["huawei_fact_outcome_scopes"]}
        desired["smartlogger.gateway"] = "GO"
        packet = build_huawei_fixture_packet(plan, registry, desired, "TR11-LINEAGE")
        packet_result = validate_huawei_provenance_packet(packet, plan, registry)
        manifest = packet["corpus"]["fact_binding_manifest"]
        require(packet_result["fact_mapping_sha256"] == manifest["mapping_sha256"] and all("evidence_root_sha256" in item for item in packet_result["fact_mapping"].values()), "Huawei packet/custody mapping hash surface drift")
        require(all(commitment["fact_mapping_sha256"] == manifest["mapping_sha256"] and commitment["immutable_evidence_root_sha256"] == packet_result["immutable_evidence_root_sha256"] for commitment in packet_result["scope_commitments"].values()), "Huawei downstream scope decision omitted lineage mapping hash")

        base_mapping = [{"fact_id": fact_id, **binding} for fact_id, binding in sorted(packet_result["fact_mapping"].items())]
        predecessor = "GENESIS"
        records: list[dict[str, Any]] = []
        for sequence in [1, 2]:
            mapping = [
                {**item, "fact_id": f"{item['fact_id']}-E{sequence}", "observation_id": f"{item['observation_id']}-E{sequence}"}
                for item in base_mapping
            ]
            mapping_hash = sha(canonical_json(mapping).encode())
            record = sign_fixture({
                "schema": plan["terminal_repair_7_contracts"]["huawei_replay_state"]["schema"], "sequence": sequence,
                "predecessor_record_sha256": predecessor, "lineage_id": "huawei-tancabesti",
                "corpus_policy_sha256": packet_result["corpus_policy_sha256"], "packet_digest_sha256": sha(f"lineage-packet-{sequence}".encode()),
                "epoch": sequence, "genesis_digest_sha256": packet_result["genesis_digest_sha256"],
                "fact_mapping": mapping, "fact_mapping_sha256": mapping_hash,
                "fact_binding_root_sha256": packet_result["fact_binding_root_sha256"], "immutable_evidence_root_sha256": packet_result["immutable_evidence_root_sha256"],
                "scope_decisions_sha256": sha(canonical_json({"outcomes": packet_result["outcomes"], "fact_mapping_sha256": mapping_hash}).encode()),
                "target_object_id": f"{sequence}" * 40, "consumed_at": f"2026-07-11T14:0{sequence}:00Z", "signer_id": "cruise-state-sync",
            }, registry)
            records.append(record)
            predecessor = sha(canonical_json(record).encode())
        ledger = huawei_replay_ledger(records, plan, registry)
        expected_mapping = sorted([item for record in records for item in record["fact_mapping"]], key=lambda item: item["fact_id"])
        require(ledger["lineage_fact_mapping"] == expected_mapping and ledger["lineage_fact_mapping_sha256"] == sha(canonical_json(expected_mapping).encode()), "Huawei durable generation omitted globally unique fact/observation mapping")
        for field in ["fact_id", "observation_id"]:
            changed_records = copy.deepcopy(records)
            changed_mapping = copy.deepcopy(changed_records[1]["fact_mapping"])
            changed_mapping[0][field] = changed_records[0]["fact_mapping"][0][field]
            changed_records[1]["fact_mapping"] = changed_mapping
            changed_records[1]["fact_mapping_sha256"] = sha(canonical_json(changed_mapping).encode())
            changed_records[1] = sign_fixture({key: item for key, item in changed_records[1].items() if key not in {"signature", "revocation_generation"}}, registry)
            try:
                validate_huawei_replay_chain(changed_records, plan, registry)
            except ValidationError:
                continue
            raise ValidationError(f"Huawei cross-epoch global identity reuse accepted: {field}")

    check("terminal_repair_11_huawei_lineage_fact_identity", tr11_huawei_lineage_fact_identity)
    check("terminal_repair_12_globally_unique_huawei_facts", tr11_huawei_lineage_fact_identity)

    def ta8_durable_generation_store() -> None:
        registry = fixture_key_registry()
        with tempfile.TemporaryDirectory(prefix="helianthus-ta8-durable-") as directory:
            base = Path(directory)
            huawei_contract = plan["terminal_repair_7_contracts"]["huawei_replay_state"]
            tdd_ledgers: list[dict[str, Any]] = []
            prior_tdd: dict[str, Any] | None = None
            for sequence in range(1, 6):
                object_id = f"{sequence:x}" * 40
                unlock = sign_fixture({"schema": "tdd-unlock-v1", "repo": "helianthus-modbus", "issue": "FMB-08H", "branch": "issue/808-fmb-08h", "target_head_sha": object_id, "red_commit_sha": object_id, "first_implementation_parent_sha": object_id, "signer_id": "tdd-gate"}, registry)
                digest = sha(canonical_json(unlock).encode())
                prior_tdd = next_tdd_consumption_ledger(prior_tdd, plan, unlock, digest, object_id, datetime(2026, 7, 11, 12, sequence, tzinfo=timezone.utc), registry)
                tdd_ledgers.append(prior_tdd)

            huawei_ledgers: list[dict[str, Any]] = []
            records: list[dict[str, Any]] = []
            predecessor = "GENESIS"
            for sequence in range(1, 6):
                mapping = [{"fact_id": f"HUA-FACT-{sequence:03d}", "claim_id": f"HUA-CLAIM-{sequence:03d}", "claim_definition_sha256": sha(f"HUA-CLAIM-DEFINITION-{sequence:03d}".encode()), "observation_id": f"HUA-OBS-{sequence:03d}", "scope": "smartlogger.gateway", "conclusion": "GO", "evidence_root_sha256": "d" * 64}]
                mapping_hash = sha(canonical_json(mapping).encode())
                record = sign_fixture({
                    "schema": huawei_contract["schema"], "sequence": sequence, "predecessor_record_sha256": predecessor,
                    "lineage_id": "huawei-tancabesti", "corpus_policy_sha256": "b" * 64, "packet_digest_sha256": sha(f"packet-{sequence}".encode()),
                    "epoch": sequence, "genesis_digest_sha256": "c" * 64, "fact_mapping": mapping, "fact_mapping_sha256": mapping_hash,
                    "fact_binding_root_sha256": sha(f"fact-root-{sequence}".encode()), "immutable_evidence_root_sha256": "d" * 64,
                    "scope_decisions_sha256": sha(canonical_json({"smartlogger.gateway": "GO", "mapping_sha256": mapping_hash}).encode()),
                    "target_object_id": f"{sequence}" * 40, "consumed_at": f"2026-07-11T12:0{sequence}:00Z", "signer_id": "cruise-state-sync",
                }, registry)
                records.append(record)
                predecessor = sha(canonical_json(record).encode())
                huawei_ledgers.append(huawei_replay_ledger(records, plan, registry))

            def publish_tdd(store: Path, generation: int, crash_after: str | None = None) -> None:
                ledger = tdd_ledgers[generation - 1]
                predecessor_binding = current_generation_binding(store, plan, registry, "tdd-consumption")
                head, high = generation_documents(
                    ledger, ledger["head_record_sha256"], "tdd-consumption", generation,
                    ledger["consumed_digest_set_sha256"], registry, f"2026-07-11T12:0{generation}:00Z",
                    *predecessor_binding,
                )
                publish_generation_bundle(store, ledger, head, high, plan, registry, "tdd-consumption", crash_after)

            def publish_huawei(store: Path, generation: int, crash_after: str | None = None) -> None:
                ledger = huawei_ledgers[generation - 1]
                chain_head = validate_huawei_replay_chain(ledger["records"], plan, registry)
                predecessor_binding = current_generation_binding(store, plan, registry, "huawei-replay")
                head, high = generation_documents(
                    ledger, chain_head, "huawei-replay", generation,
                    ledger["lineage_fact_mapping_sha256"], registry, f"2026-07-11T13:0{generation}:00Z",
                    *predecessor_binding,
                )
                publish_generation_bundle(store, ledger, head, high, plan, registry, "huawei-replay", crash_after)

            full_revalidate = lambda unlock: sha(canonical_json(unlock).encode())
            stores = [("tdd", base / "tdd-store", publish_tdd, lambda store: recover_tdd_generation_store(store, plan, registry, full_revalidate)), ("huawei", base / "huawei-store", publish_huawei, lambda store: recover_huawei_generation_store(store, plan, registry))]
            boundaries = plan["terminal_repair_11_contracts"]["durable_generation_store"]["publish_boundaries"]
            require(boundaries == ["create-generation-temp-directory", "write-ledger-file", "fsync-ledger-file", "write-head-file", "fsync-head-file", "write-high-water-file", "fsync-high-water-file", "fsync-generation-temp-directory", "rename-generation-directory", "fsync-generations-directory", "write-pointer-file", "fsync-pointer-file", "rename-pointer-switch", "fsync-store-directory"], "generation crash boundary inventory drift")

            def inject_divergent_successor(store: Path, kind: str) -> dict[str, Any]:
                contract = plan["terminal_repair_11_contracts"]["durable_generation_store"]
                lineage_id = "tdd-consumption" if kind == "tdd" else "huawei-replay"
                predecessor_binding = current_generation_binding(store, plan, registry, lineage_id)
                generation = predecessor_binding[0] + 1
                ledger = copy.deepcopy(tdd_ledgers[0] if kind == "tdd" else huawei_ledgers[0])
                chain_head = ledger["head_record_sha256"] if kind == "tdd" else validate_huawei_replay_chain(ledger["records"], plan, registry)
                lineage_state = ledger["consumed_digest_set_sha256"] if kind == "tdd" else ledger["lineage_fact_mapping_sha256"]
                head, high_water = generation_documents(
                    ledger, chain_head, lineage_id, generation, lineage_state, registry,
                    f"2026-07-11T15:0{generation}:00Z", *predecessor_binding,
                )
                raw_by_name = {
                    contract["bundle_files"]["ledger"]: (canonical_json(ledger) + "\n").encode(),
                    contract["bundle_files"]["head"]: (canonical_json(head) + "\n").encode(),
                    contract["bundle_files"]["high_water"]: (canonical_json(high_water) + "\n").encode(),
                }
                directory = store / "generations" / f"{generation:020d}"
                directory.mkdir()
                for name, raw in raw_by_name.items():
                    atomic_write_bytes(directory / name, raw)
                return {
                    "ledger": ledger,
                    "head": head,
                    "high_water": high_water,
                    "generation": generation,
                    "bundle_sha256": generation_bundle_digest(raw_by_name),
                }

            for kind, store, publisher, recoverer in stores:
                for generation in [1, 2, 3]:
                    publisher(store, generation)
                    require(recoverer(store)["generation"] == generation, f"{kind} clean generation restart drift")
                for boundary in boundaries:
                    state = base / f"{kind}-{sha(boundary.encode())[:12]}"
                    shutil.copytree(store, state)
                    try:
                        publisher(state, 4, boundary)
                    except SimulatedGenerationCrash:
                        pass
                    else:
                        raise ValidationError(f"{kind} generation crash boundary did not interrupt: {boundary}")
                    complete_pending = boundaries.index(boundary) >= boundaries.index("rename-generation-directory")
                    expected_generation = 4 if complete_pending else 3
                    recovered = recoverer(state)
                    require(recovered["generation"] == expected_generation, f"{kind} crash recovery selected wrong complete generation: {boundary}")
                    require((state / "generations" / f"{max(1, expected_generation - 1):020d}").is_dir(), f"{kind} immediate prior complete generation was not retained")
                    successor_generation = expected_generation + 1
                    publisher(state, successor_generation)
                    require(recoverer(state)["generation"] == successor_generation, f"{kind} successor publication did not derive from repaired effective generation: {boundary}")
                    if boundaries.index(boundary) < boundaries.index("rename-pointer-switch"):
                        recovery_records = sorted((state / plan["terminal_repair_12_contracts"]["generation_recovery"]["record_directory"]).glob("*.json"))
                        require(recovery_records, f"{kind} pre-pointer recovery omitted signed recovery record: {boundary}")
                        recovery_record = json.loads(recovery_records[-1].read_text())
                        verify_signed(recovery_record, registry)
                        require(recovery_record["selected_generation"] == expected_generation and recovery_record["reason_code"] in {"remove-incomplete-orphan-generation", "resume-validated-pending-bundle"}, f"{kind} recovery record does not bind selected generation/reason: {boundary}")

                pending_divergent = base / f"{kind}-divergent-pending"
                shutil.copytree(store, pending_divergent)
                divergent = inject_divergent_successor(pending_divergent, kind)
                require(recoverer(pending_divergent)["generation"] == 3, f"{kind} resumed a validly signed divergent pending successor")
                require(not (pending_divergent / "generations" / f"{divergent['generation']:020d}").exists(), f"{kind} did not remove divergent pending generation")
                pending_record = json.loads(sorted((pending_divergent / plan["terminal_repair_12_contracts"]["generation_recovery"]["record_directory"]).glob("*.json"))[-1].read_text())
                verify_signed(pending_record, registry)
                require(pending_record["reason_code"] == "remove-invalid-or-divergent-orphan-generation" and pending_record["selected_generation"] == 3, f"{kind} divergent pending removal record drift")
                publisher(pending_divergent, 4)
                require(recoverer(pending_divergent)["generation"] == 4, f"{kind} failed successor publication after divergent pending removal")

                switched_divergent = base / f"{kind}-divergent-switched"
                shutil.copytree(store, switched_divergent)
                divergent = inject_divergent_successor(switched_divergent, kind)
                lineage_id = "tdd-consumption" if kind == "tdd" else "huawei-replay"
                active_generation, active_digest, _ = current_generation_binding(switched_divergent, plan, registry, lineage_id)
                switched_pointer = generation_pointer(
                    divergent["generation"], divergent["bundle_sha256"], active_generation, active_digest,
                    lineage_id, divergent["head"]["committed_at"], registry,
                )
                atomic_write_bytes(switched_divergent / plan["terminal_repair_11_contracts"]["durable_generation_store"]["pointer_filename"], (canonical_json(switched_pointer) + "\n").encode())
                require(recoverer(switched_divergent)["generation"] == 3, f"{kind} retained a validly signed divergent active successor")
                switched_record = json.loads(sorted((switched_divergent / plan["terminal_repair_12_contracts"]["generation_recovery"]["record_directory"]).glob("*.json"))[-1].read_text())
                verify_signed(switched_record, registry)
                require(switched_record["reason_code"] == "fallback-to-validated-generation" and switched_record["selected_generation"] == 3, f"{kind} divergent active fallback record drift")
                publisher(switched_divergent, 4)
                require(recoverer(switched_divergent)["generation"] == 4, f"{kind} failed successor publication after divergent active fallback")

                mixed = base / f"{kind}-mixed-generation"
                shutil.copytree(store, mixed)
