    def ta8_exact_cas() -> None:
        registry = fixture_key_registry()
        with tempfile.TemporaryDirectory(prefix="helianthus-ta8-cas-") as directory:
            repo = Path(directory) / "repo"
            repo.mkdir()
            subprocess.run(["git", "-C", str(repo), "init", "-q", "-b", "main"], check=True)
            subprocess.run(["git", "-C", str(repo), "config", "user.email", "fixture@example.invalid"], check=True)
            subprocess.run(["git", "-C", str(repo), "config", "user.name", "Fixture"], check=True)
            atomic_write_bytes(repo / "value", b"old\n")
            subprocess.run(["git", "-C", str(repo), "add", "."], check=True)
            subprocess.run(["git", "-C", str(repo), "commit", "-q", "-m", "old"], check=True)
            old = git_output(repo, "rev-parse", "HEAD")
            atomic_write_bytes(repo / "value", b"new\n")
            subprocess.run(["git", "-C", str(repo), "add", "."], check=True)
            tree = git_output(repo, "write-tree")
            new = subprocess.run(["git", "-C", str(repo), "commit-tree", tree, "-p", old], input="new\n", check=True, text=True, capture_output=True).stdout.strip()
            ref = "refs/heads/main"
            argv = ["git", "-C", str(repo.resolve()), "update-ref", ref, new, old]
            observed_old = git_output(repo, "rev-parse", ref)
            completed = subprocess.run(argv, check=False, capture_output=True)
            post_ref = git_output(repo, "rev-parse", ref)
            invocation_id = "ta8-cas-invocation-001"
            invocation = {"repository_path": str(repo.resolve()), "argv": argv, "expected_old_ref": old, "observed_old_ref": observed_old, "exit_status": completed.returncode, "stdout_sha256": sha(completed.stdout), "stderr_sha256": sha(completed.stderr), "post_ref": post_ref, "invocation_id": invocation_id}
            receipt = sign_fixture({
                "schema": "signed-cas-receipt-v1", "repository_path": str(repo.resolve()), "intended_ref": ref, "old_object_id": old,
                "new_object_id": new, "final_tree_id": tree, "executed_at": "2026-07-11T12:00:00Z", "result": "CAS_APPLIED", "executor_id": "cruise-state-sync",
                "cas_argv": argv, "expected_old_ref": old, "observed_old_ref": observed_old, "exit_status": completed.returncode,
                "stdout_b64": base64.b64encode(completed.stdout).decode(), "stderr_b64": base64.b64encode(completed.stderr).decode(),
                "stdout_sha256": sha(completed.stdout), "stderr_sha256": sha(completed.stderr), "post_ref": post_ref, "invocation_id": invocation_id,
                "invocation_evidence_sha256": sha(canonical_json(invocation).encode()), "metadata_digest_sha256": "d" * 64, "signer_id": "cruise-state-sync",
            }, registry)
            validate_cas_receipt(receipt, plan, registry, repo, ref, old, new, tree)
            force_ref = "refs/heads/force-fixture"
            subprocess.run(["git", "-C", str(repo), "update-ref", force_ref, old], check=True)
            force = subprocess.run(["git", "-C", str(repo), "update-ref", force_ref, new], check=False, capture_output=True)
            require(force.returncode == 0, "force-update negative fixture did not execute")
            forged_force = copy.deepcopy(receipt)
            forged_force["cas_argv"] = ["git", "-C", str(repo.resolve()), "update-ref", force_ref, new]
            forged_force = sign_fixture({key: item for key, item in forged_force.items() if key not in {"signature", "revocation_generation"}}, registry)
            try:
                validate_cas_receipt(forged_force, plan, registry, repo, ref, old, new, tree)
            except ValidationError:
                pass
            else:
                raise ValidationError("force update without expected old ref accepted as CAS evidence")
            third = subprocess.run(["git", "-C", str(repo), "commit-tree", tree, "-p", old], input="concurrent\n", check=True, text=True, capture_output=True).stdout.strip()
            concurrent_ref = "refs/heads/concurrent-fixture"
            subprocess.run(["git", "-C", str(repo), "update-ref", concurrent_ref, old], check=True)
            subprocess.run(["git", "-C", str(repo), "update-ref", concurrent_ref, third], check=True)
            concurrent = subprocess.run(["git", "-C", str(repo), "update-ref", concurrent_ref, new, old], check=False, capture_output=True)
            require(concurrent.returncode != 0 and git_output(repo, "rev-parse", concurrent_ref) == third, "concurrent ref move did not fail closed")
            for field in ["observed_old_ref", "post_ref", "exit_status", "stdout_sha256", "stderr_sha256", "invocation_evidence_sha256"]:
                mutant = copy.deepcopy(receipt)
                mutant[field] = 1 if field == "exit_status" else "0" * 64
                mutant = sign_fixture({key: item for key, item in mutant.items() if key not in {"signature", "revocation_generation"}}, registry)
                try:
                    validate_cas_receipt(mutant, plan, registry, repo, ref, old, new, tree)
                except ValidationError:
                    continue
                raise ValidationError(f"CAS transcript mutation accepted: {field}")

    check("exact_git_update_ref_cas_invocation", ta8_exact_cas)

    def ta8_wal_fault_harness() -> None:
        registry = fixture_key_registry()
        boundaries = plan["terminal_repair_10_contracts"]["activation_wal"]["activation_order"]
        require(boundaries == plan["terminal_repair_6_contracts"]["release_wal"]["activation_order"] == plan["terminal_repair_6_contracts"]["release_wal"]["crash_boundaries"], "WAL crash boundary list is not every v3 syscall boundary")

        def make_record(generation: int, package_payload: bytes, migration_payload: bytes, predecessor_raw: bytes | None) -> dict[str, Any]:
            predecessor = json.loads(predecessor_raw) if predecessor_raw is not None else None
            return sign_fixture({
                "schema": ACTIVATION_RECORD_SCHEMA, "generation": generation, "active_pointer": f"package-g{generation}",
                "package_object_sha256": sha(package_payload), "migration_object_sha256": sha(migration_payload),
                "predecessor_generation": generation - 1,
                "predecessor_record_sha256": sha(predecessor_raw) if predecessor_raw is not None else "GENESIS",
                "predecessor_package_object_sha256": predecessor["package_object_sha256"] if predecessor is not None else "GENESIS",
                "predecessor_migration_object_sha256": predecessor["migration_object_sha256"] if predecessor is not None else "GENESIS",
                "committed_at": f"2026-07-11T1{generation}:00:00Z", "signer_id": "cruise-state-sync",
            }, registry)

        def initialize(path: Path) -> bytes:
            atomic_write_bytes(path / "trusted-keys.json", (canonical_json(registry) + "\n").encode())
            package, migration = b"package-v1", b"migration-v1"
            atomic_write_bytes(path / "objects" / "package" / sha(package), package)
            atomic_write_bytes(path / "objects" / "migration" / sha(migration), migration)
            raw = activation_record_bytes(make_record(1, package, migration, None))
            for name in ["active-record.json", "active-record.backup.json", "active-record.head.json"]:
                atomic_write_bytes(path / name, raw)
            return raw

        def stage(path: Path, generation: int) -> bytes:
            previous = (path / "active-record.json").read_bytes()
            package, migration = f"package-v{generation}".encode(), f"migration-v{generation}".encode()
            raw = activation_record_bytes(make_record(generation, package, migration, previous))
            atomic_write_bytes(path / "next-package.payload", package)
            atomic_write_bytes(path / "next-migration.payload", migration)
            atomic_write_bytes(path / "next-record.json", raw)
            return raw

        def activate(path: Path, fault: str | None = None) -> subprocess.CompletedProcess[bytes]:
            argv = [sys.executable, str(Path(__file__).resolve()), "--wal-worker-state", str(path)]
            if fault is not None:
                argv.extend(["--wal-fault", fault])
            return subprocess.run(argv, check=False, capture_output=True, timeout=10)

        with tempfile.TemporaryDirectory(prefix="helianthus-ta10-wal-base-") as directory:
            base = Path(directory)
            generation1 = initialize(base)
            generation2 = stage(base, 2)
            require(activate(base).returncode == 0 and recover_wal_bytes(base) == generation2 and (base / "active-record.backup.json").read_bytes() == generation1, "second-generation activation/backup drift")
            generation3 = stage(base, 3)
            require(activate(base).returncode == 0 and recover_wal_bytes(base) == generation3 and (base / "active-record.backup.json").read_bytes() == generation2, "third-generation activation did not rotate exact immediate predecessor")

            for boundary in boundaries:
                state = base.parent / f"wal-boundary-{sha(boundary.encode())[:12]}"
                shutil.copytree(base, state)
                try:
                    generation4 = stage(state, 4)
                    process = subprocess.Popen([sys.executable, str(Path(__file__).resolve()), "--wal-worker-state", str(state), "--wal-pause-after", boundary], stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True)
                    try:
                        observed: list[str] = []
                        while True:
                            line = process.stdout.readline()
                            require(line != "", f"WAL worker exited before boundary: {boundary}")
                            observed.append(line.strip())
                            if line.strip() == boundary:
                                break
                        process.kill()
                        process.wait(timeout=5)
                    finally:
                        if process.poll() is None:
                            process.kill()
                            process.wait(timeout=5)
                    atomic_write_bytes(state / "active-record.json", b"{torn-active")
                    backup_rotated = boundaries.index(boundary) >= boundaries.index("atomic-publish-backup-record")
                    expected_predecessor = generation3 if backup_rotated else generation2
                    require(recover_wal_bytes(state) == expected_predecessor and boundary in observed, f"WAL crash/corruption did not recover exact immediate predecessor: {boundary}")
                    require(generation4 != expected_predecessor, "WAL boundary fixture did not distinguish pending generation")
                finally:
                    shutil.rmtree(state)

            fault_expectations = {
                "ENOSPC-package-write": generation2, "ENOSPC-migration-write": generation2,
                "ENOSPC-backup-write": generation2, "ENOSPC-active-write": generation3,
                "ENOSPC-head-write": generation3,
            }
            for fault, expected_predecessor in fault_expectations.items():
                state = base.parent / f"wal-fault-{fault}"
                shutil.copytree(base, state)
                try:
                    stage(state, 4)
                    require(activate(state, fault).returncode != 0, f"WAL injected fault unexpectedly completed: {fault}")
                    atomic_write_bytes(state / "active-record.json", b"{torn-active")
                    require(recover_wal_bytes(state) == expected_predecessor, f"WAL fault did not recover exact immediate predecessor: {fault}")
                finally:
                    shutil.rmtree(state)

            successor = stage(base, 4)
            previous = generation3
            valid_successor = json.loads(successor)
            record_mutations = [
                {**valid_successor, "extra": True},
                {**valid_successor, "predecessor_generation": 1},
                {**valid_successor, "predecessor_record_sha256": "0" * 64},
                {**valid_successor, "predecessor_package_object_sha256": "f" * 64},
                {**valid_successor, "signature": "A" * 88},
            ]
            for mutation in record_mutations:
                try:
                    validate_activation_successor(previous, activation_record_bytes(mutation), registry, base)
                except ValidationError:
                    continue
                raise ValidationError("malformed or predecessor-detached signed activation record accepted")
            require(activate(base).returncode == 0 and recover_wal_bytes(base) == successor and (base / "active-record.backup.json").read_bytes() == generation3, "fourth-generation activation did not preserve generation three as immediate backup")
            active = json.loads((base / "active-record.json").read_text())
            (base / "objects" / "package" / active["package_object_sha256"]).unlink()
            require(recover_wal_bytes(base) == generation3, "active object corruption did not recover exactly the immediate durable predecessor")

    check("content_addressed_activation_wal", ta8_wal_fault_harness)

    def ta8_locator_mutants() -> None:
        mutations = plan["terminal_repair_6_contracts"]["mutation_dispatch"]
