    def ta8_additive_architecture() -> None:
        architecture_contract = next(item for item in plan["external_planning_artifacts"] if item["id"] == "ARCHITECTURE-MAP-AMENDMENT-V1")
        begin_marker, end_marker = architecture_contract["structured_block_markers"]
        invariant_begin, invariant_end = architecture_contract["invariant_block_markers"]
        invariant_model = expected_root_invariant_model(plan)
        def render(model: dict[str, Any], prose: str = "", invariant_prose: str = "") -> str:
            return (
                "## 1.2 Repository Dependency Chain (fixture)\n\n" + prose
                + f"\n<!-- {begin_marker} -->\n```yaml\n" + yaml.safe_dump(model, sort_keys=True)
                + f"```\n<!-- {end_marker} -->\n\n## 1.2A Workspace Checkout Map (fixture)\n\nStructured authority above.\n\n"
                + "## 12. INVARIANTS (ALWAYS TRUE)\n\n" + invariant_prose
                + f"\n<!-- {invariant_begin} -->\n```yaml\n" + yaml.safe_dump(invariant_model, sort_keys=True)
                + f"```\n<!-- {invariant_end} -->\n\n## 13. End\n"
            )
        extra = {"Project-Helianthus/future-addon": "future-addon"}
        model = expected_architecture_model(plan, extra)
        parsed = parse_root_architecture_authority(render(model), plan)
        require(parsed["model"] == model and parsed["invariant_model"] == invariant_model and not parsed["contradictions"] and parsed["model"]["checkout_map"]["Project-Helianthus/helianthus-execution-plans"] == "helianthus-execution-plans", "additive root architecture/invariant fixture failed or lost existing mappings")
        required_maps = {**architecture_contract["existing_checkout_map"], **architecture_contract["required_additive_checkout_map"]}
        for checkout in required_maps:
            mutant = copy.deepcopy(model)
            del mutant["checkout_map"][checkout]
            contradictions = parse_root_architecture_authority(render(mutant), plan)["contradictions"]
            require(any(checkout in item for item in contradictions), f"missing architecture checkout row accepted: {checkout}")
        forbidden = [
            "Every wire protocol requires a distinct codebase.",
            "A distinct codebase is required for every wire protocol.",
            "Protocol adapters must be separate repos.",
            "The planned helianthus-sunspec repository owns RS-485/Modbus.",
        ]
        for assertion in forbidden:
            require(parse_root_architecture_authority(render(model, assertion), plan)["contradictions"], f"forbidden architecture paraphrase accepted: {assertion}")
        self_reported = render(model, '{"contradictions": false, "all_rows_preserved": true}')
        require(parse_root_architecture_authority(self_reported, plan)["model"] == model, "self-reported booleans altered structured authority parsing")

    check("additive_structured_root_architecture", ta8_additive_architecture)

    def ta12_root_invariant_authority() -> None:
        authority = next(item for item in plan["external_planning_artifacts"] if item["id"] == "ARCHITECTURE-MAP-AMENDMENT-V1")
        begin, end = authority["structured_block_markers"]
        invariant_begin, invariant_end = authority["invariant_block_markers"]
        architecture_model = expected_architecture_model(plan)
        invariant_model = expected_root_invariant_model(plan)

        def render(invariants: dict[str, Any], invariant_prose: str = "") -> str:
            return (
                "## 1.2 Repository Dependency Chain\n\n"
                f"<!-- {begin} -->\n```yaml\n{yaml.safe_dump(architecture_model, sort_keys=True)}```\n<!-- {end} -->\n\n"
                "## 1.2A Workspace Checkout Map\n\nStructured authority above.\n\n"
                "## 12. INVARIANTS (ALWAYS TRUE)\n\n" + invariant_prose + "\n"
                f"<!-- {invariant_begin} -->\n```yaml\n{yaml.safe_dump(invariants, sort_keys=True)}```\n<!-- {invariant_end} -->\n\n"
                "## 13. End\n"
            )

        def validate_fixture(raw: str) -> None:
            parsed = parse_root_architecture_authority(raw, plan)
            require(not parsed["contradictions"] and parsed["model"] == architecture_model and parsed["invariant_model"] == invariant_model, "root invariant authority fixture mismatch")

        validate_fixture(render(invariant_model))
        for amendment_id in sorted(invariant_model["amendments"]):
            mutant = copy.deepcopy(invariant_model)
            del mutant["amendments"][amendment_id]
            try:
                validate_fixture(render(mutant))
            except ValidationError:
                pass
            else:
                raise ValidationError(f"root invariant amendment omission accepted: {amendment_id}")
            mutant = copy.deepcopy(invariant_model)
            mutant["amendments"][amendment_id]["normalized_rule"] = "Semantically similar wording without the exact authority contract."
            try:
                validate_fixture(render(mutant))
            except ValidationError:
                pass
            else:
                raise ValidationError(f"root invariant amendment paraphrase accepted: {amendment_id}")
        for unchanged in ["No parallel merge streams.", "Both AIs review every PR. Double-approve to merge."]:
            try:
                validate_fixture(render(invariant_model, unchanged))
            except ValidationError:
                continue
            raise ValidationError(f"unchanged conflicting root invariant accepted: {unchanged}")

