    def ta13_root_authority_singular_metadata() -> None:
        authority = next(item for item in plan["external_planning_artifacts"] if item["id"] == "ARCHITECTURE-MAP-AMENDMENT-V1")
        contract = plan["terminal_repair_13_contracts"]["root_authority_singularities"]
        require(authority["required_root_governance"] == contract["required_governance"], "root architecture singular governance authority drift")
        blockers = plan["terminal_repair_8_contracts"]["current_external_blockers"]["root_architecture"]
        require(all(conflict in blockers for conflict in contract["current_external_conflicts"]), "current root version/wave conflicts missing from explicit blocker inventory")
        architecture_gate = next(gate for gate in plan["planning_gates"] if gate["id"] == "PG-ARCHITECTURE-MAP-AMENDMENT")
        if expected_state == "draft":
            require(architecture_gate["state"] == "pending_external_operator", "conflicting root authority incorrectly permits PG-ARCHITECTURE-MAP-AMENDMENT to pass")
        begin, end = authority["structured_block_markers"]
        invariant_begin, invariant_end = authority["invariant_block_markers"]
        architecture_model = expected_architecture_model(plan)
        expected_invariants = expected_root_invariant_model(plan)

        def render(invariants: dict[str, Any], prefix: str = "", suffix: str = "") -> str:
            return (
                prefix + "## 1.2 Repository Dependency Chain\n\n"
                f"<!-- {begin} -->\n```yaml\n{yaml.safe_dump(architecture_model, sort_keys=True)}```\n<!-- {end} -->\n\n"
                "## 1.2A Workspace Checkout Map\n\nStructured authority above.\n\n"
                "## 12. INVARIANTS (ALWAYS TRUE)\n\n"
                f"<!-- {invariant_begin} -->\n```yaml\n{yaml.safe_dump(invariants, sort_keys=True)}```\n<!-- {invariant_end} -->\n\n"
                + suffix + "## 13. End\n"
            )

        parsed = parse_root_architecture_authority(render(expected_invariants), plan)
        require(not parsed["contradictions"] and parsed["invariant_model"] == expected_invariants, "singular root governance positive fixture drift")
        unchanged = render(
            expected_invariants,
            prefix="> **Version:** 2.5 - current\n\n",
            suffix="### Wave 1.5 scope\n- `cruise-transport-gate` owns T01..T88.\n\n| Runtime concern | Owner |\n| --- | --- |\n| Transport gate | `cruise-transport-gate` (Wave 2) |\n\n*Version 2.4 - legacy footer*\n\n",
        )
        unchanged_conflicts = parse_root_architecture_authority(unchanged, plan)["contradictions"]
        require(all(conflict in unchanged_conflicts for conflict in contract["current_external_conflicts"]), "unchanged current root version/wave conflicts were accepted")
        dual_model = copy.deepcopy(expected_invariants)
        dual_model["governance"]["root_version_metadata"]["value"] = ["2.5", "2.4"]
        dual_model["governance"]["transport_gate_wave_ownership"]["value"] = ["Wave 1.5", "Wave 2"]
        paraphrase = render(
            expected_invariants,
            suffix="Version two point four remains authoritative, and cruise-transport-gate remains assigned to the second wave.\n\n",
        )
        paraphrase_conflicts = parse_root_architecture_authority(paraphrase, plan)["contradictions"]
        require(all(conflict in paraphrase_conflicts for conflict in contract["current_external_conflicts"]), "word-alias root version/wave conflicts were accepted")
        mutations = [("paraphrase", paraphrase), ("dual-value", render(dual_model))]
        require(["unchanged", *[label for label, _ in mutations]] == contract["mutation_classes"], "root singularity mutation class drift")
        reviewer_cases = [
            ("version-v-alias", "Version v2.4 remains authoritative.\n\n", "root-version-metadata-conflict-v2.5-v2.4"),
            ("version-hyphen-word-alias", "Version two-point-four remains authoritative.\n\n", "root-version-metadata-conflict-v2.5-v2.4"),
            ("root-release-alias", "Root authority release 2.4 remains current.\n\n", "root-version-metadata-conflict-v2.5-v2.4"),
            ("transport-gate-wave-2", "The transport gate remains assigned to Wave 2.\n\n", "transport-gate-wave-ownership-conflict-wave-2-vs-wave-1.5"),
            ("cruise-transport-gate-wave-2", "The cruise transport gate remains assigned to Wave 2.\n\n", "transport-gate-wave-ownership-conflict-wave-2-vs-wave-1.5"),
            ("structured-plus-prose-version-duplicate", "Prose **Version 2.5** duplicates the structured authority.\n\n", "root-version-metadata-not-singular-authority"),
            ("structured-plus-prose-wave-duplicate", "Prose `cruise-transport-gate` **Wave 1.5** ownership duplicates the structured authority.\n\n", "transport-gate-wave-ownership-not-singular-authority"),
        ]
        reviewer_mutations = []
        for label, suffix, expected_contradiction in reviewer_cases:
            mutation = render(expected_invariants, suffix=suffix)
            parsed_case = parse_root_architecture_authority(mutation, plan)
            require(expected_contradiction in parsed_case["contradictions"], f"root singular authority reviewer mutation accepted: {label}")
            reviewer_mutations.append((label, mutation))
        for label, mutation in [*mutations, *reviewer_mutations]:
            parsed_mutation = parse_root_architecture_authority(mutation, plan)
            try:
                require(not parsed_mutation["contradictions"] and parsed_mutation["invariant_model"] == expected_invariants, "root singular authority fixture mismatch")
            except ValidationError:
                continue
            raise ValidationError(f"root singular authority {label} mutation accepted")

    check("terminal_repair_13_root_authority_singular_metadata", ta13_root_authority_singular_metadata)

