    def ta14_canonical_coverage_ranges() -> None:
        contract = plan["terminal_repair_14_contracts"]["canonical_coverage_ranges"]
        observed = canonical_coverage_authority(canonical_markdown)
        require(observed == contract["authority"], "canonical invariant/AD range authority drift")
        mirror = markdown_without_generated_block((root / contract["mirror_file"]).read_text(), plan)
        begin, end = contract["begin_marker"], contract["end_marker"]
        require(mirror.count(begin) == mirror.count(end) == 1, "canonical coverage mirror marker cardinality drift")
        match = re.search(re.escape(begin) + r".*?" + re.escape(end), mirror, re.DOTALL)
        require(match is not None and match.group(0) == render_canonical_coverage_block(plan), "canonical coverage mirror differs from generated authority")
        rendered = render_canonical_coverage_block(plan)
        authority = contract["authority"]
        mutations = [
            ("stale-invariant-last", rendered.replace(f'"last":{authority["invariants"]["last"]}', f'"last":{authority["invariants"]["last"] - 1}', 1)),
            ("stale-invariant-count", rendered.replace(f'"count":{authority["invariants"]["count"]}', f'"count":{authority["invariants"]["count"] - 1}', 1)),
            ("stale-ad-last", rendered.replace(f'"last":"{authority["architecture_decisions"]["last"]}"', '"last":"AD85"', 1)),
            ("stale-ad-count", rendered.replace(f'"count":{authority["architecture_decisions"]["count"]}', f'"count":{authority["architecture_decisions"]["count"] - 1}', 1)),
        ]
        require([label for label, _ in mutations] == contract["mutation_classes"], "canonical coverage mutation fixture set drift")
        for label, mutation in mutations:
            changed = mirror.replace(rendered, mutation, 1)
            changed_match = re.search(re.escape(begin) + r".*?" + re.escape(end), changed, re.DOTALL)
            try:
                require(changed_match is not None and changed_match.group(0) == render_canonical_coverage_block(plan), "canonical coverage mirror mutation")
            except ValidationError:
                continue
            raise ValidationError(f"canonical coverage stale mutation accepted: {label}")

