    def ta15_read_only_v1() -> None:
        contract = plan["terminal_repair_15_contracts"]["read_only_v1"]

        def assert_read_only(candidate: dict[str, Any]) -> None:
            fmb = candidate["issue_machine_contracts"]["contracts"][contract["fmb_02a_issue"]]
            limits = fmb["exact_limits"]
            require(limits["supported_function_codes_hex"] == contract["supported_function_codes_hex"], "FMB-02A read-only function allowlist drift")
            require(not set(contract["forbidden_write_quantity_limit_fields"]) & set(limits), "FMB-02A write quantity limit survived read-only v1")
            require(limits.get("write_supported") is False, "FMB-02A write support escaped read-only v1")
            pdu_unsupported = [row for row in fmb["behavior_contract"]["failure_outcomes"] if row["error_code"] == "FMB-02A_UNSUPPORTED"]
            require(not pdu_unsupported, "issue-prefixed FMB-02A write outcome survived exact UNSUPPORTED contract")
            for milestone in candidate["milestones"]:
                validate_modbus_operation_descriptor(milestone, candidate)
            observed_raw_issues = [milestone["id"] for milestone in candidate["milestones"] if issue_exposes_raw_modbus(milestone)]
            artifact_derived_issues = {
                milestone["id"] for milestone in candidate["milestones"]
                if milestone["acceptance_artifact"] in EXPECTED_MODBUS_OPERATION_ARTIFACTS
            }
            require(
                observed_raw_issues == contract["modbus_operation_capable_issues"] == contract["raw_modbus_issues"]
                and set(observed_raw_issues) == artifact_derived_issues == EXPECTED_MODBUS_OPERATION_CAPABLE_ISSUES,
                "typed transport-derived Modbus operation-capable read-only issue inventory drift",
            )
            commitment_leaves = {
                row["issue"]: row["commitment_sha256"]
                for row in candidate["terminal_repair_10_contracts"]["issue_behavior_authority"]["commitment_artifact"]["leaves"]
            }
            for issue in observed_raw_issues:
                milestone = next(item for item in candidate["milestones"] if item["id"] == issue)
                machine = candidate["issue_machine_contracts"]["contracts"][issue]
                surface_limits = machine["exact_limits"]
                require(
                    all(surface_limits.get(key) == value for key, value in raw_write_rejection_limits(milestone).items()),
                    f"raw write pre-transport limit contract drift: {issue}",
                )
                require(
                    surface_limits["declared_modbus_operation_function_codes_hex"] == contract["read_function_codes_by_issue"][issue] == milestone["modbus_operation_descriptor"]["read_function_codes_hex"],
                    f"Modbus operation descriptor function allowlist drift: {issue}",
                )
                unsupported = [row for row in machine["behavior_contract"]["failure_outcomes"] if row["error_code"] == "UNSUPPORTED"]
                require(len(unsupported) == 1 and unsupported[0]["artifact_state"] == "ABSENT" and "write" in unsupported[0]["trigger"], f"raw write exact failure contract drift: {issue}")
                observed_write_fixtures = [row for row in machine["fixture_matrix"] if row["expected_receipt"] is not None and row["expected_receipt"].get("schema") == contract["receipt_schema"]]
                expected_write_fixtures = [
                    {**row, "oracle_sha256": sha(canonical_json(row).encode())}
                    for row in expected_raw_write_fixtures(milestone, machine["evidence_authority"]["provider_id"])
                ]
                require(observed_write_fixtures == expected_write_fixtures and len(observed_write_fixtures) == contract["fixtures_per_issue"], f"raw write executable fixture exact-set drift: {issue}")
                require(
                    all(
                        row["expected_failure"] == "UNSUPPORTED"
                        and row["expected_output"] is None
                        and row["expected_receipt"]["decision_stage"] == contract["rejection_stage"]
                        and row["expected_receipt"]["transport_accessed"] is False
                        and row["expected_receipt"]["transport_call_count"] == contract["transport_call_count"]
                        and row["expected_receipt"]["write_transport_call_count"] == contract["transport_call_count"]
                        and row["expected_receipt"]["signer_role"] == contract["receipt_signer_role"]
                        for row in observed_write_fixtures
                    ),
                    f"raw write rejection receipt semantics drift: {issue}",
                )
                observed_pairs = [
                    (row["input"]["raw_modbus_request"]["request_kind"], row["input"]["raw_modbus_request"]["authorization_state"])
                    for row in observed_write_fixtures
                ]
                expected_pairs = [(kind, authorization) for kind, _ in RAW_MODBUS_WRITE_REQUESTS for authorization in RAW_MODBUS_AUTHORIZATION_STATES]
                require(observed_pairs == expected_pairs, f"raw write request/authorization coverage drift: {issue}")
                require(all(operator in {row["operator"] for row in machine["mutation_cases"]} for operator in contract["per_issue_mutation_operators"]), f"raw write issue mutation commitments missing: {issue}")
                require("exact UNSUPPORTED before transport access" in machine["acceptance_criteria"][3], f"raw write acceptance criterion missing: {issue}")
                require(commitment_leaves.get(issue) == issue_commitment_leaf(machine), f"raw write independent commitment leaf drift: {issue}")

        assert_read_only(plan)
        require(contract["future_write_scope"] == "explicit-future-milestone-only-out-of-scope-for-v1", "future write capability leaked into v1")
        for name in contract["manual_files"]:
            require(markdown_without_generated_block((root / name).read_text(), plan).count(contract["canonical_prose"]) == 1, f"read-only v1 canonical prose parity drift: {name}")
        mutations: list[tuple[str, dict[str, Any]]] = []
        for label, code in [("add-fc05", "05"), ("add-fc06", "06"), ("add-fc0f", "0F"), ("add-fc10", "10")]:
            changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"]["FMB-02A"]["exact_limits"]["supported_function_codes_hex"].append(code); mutations.append((label, changed))
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"]["FMB-02A"]["exact_limits"]["max_write_coils_fc0f"] = 1968; mutations.append(("add-fc0f-write-limit", changed))
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"]["FMB-02A"]["exact_limits"]["max_write_registers_fc10"] = 123; mutations.append(("add-fc10-write-limit", changed))
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"]["FMB-02A"]["exact_limits"]["write_supported"] = True; mutations.append(("pdu-write-enabled", changed))
        api_issue = next(issue for issue in contract["gateway_surface_issues"] if issue_behavior_class(by_id[issue]) == "gateway_api")
        runtime_issue = next(issue for issue in contract["gateway_surface_issues"] if issue_behavior_class(by_id[issue]) == "gateway_runtime")
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"][api_issue]["exact_limits"]["raw_write_supported"] = True; mutations.append(("gateway-api-write-enabled", changed))
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"][runtime_issue]["exact_limits"]["raw_write_supported"] = True; mutations.append(("gateway-runtime-write-enabled", changed))
        changed = copy.deepcopy(plan); changed["issue_machine_contracts"]["contracts"][api_issue]["exact_limits"]["write_authorization_effect"] = "ALLOW"; mutations.append(("authorization-bypass", changed))
        general_mutation_classes = contract["mutation_classes"][:-4]
        require([label for label, _ in mutations] == general_mutation_classes, "Targeted Terminal Repair 15b general read-only mutation class drift")
        for label, mutation in mutations:
            try:
                assert_read_only(mutation)
            except ValidationError:
                continue
            raise ValidationError(f"Terminal Repair 15 read-only mutation accepted: {label}")
        per_issue_classes = contract["mutation_classes"][-4:]
        require(per_issue_classes == ["authorized-write-accepted", "write-reaches-transport", "wrong-write-outcome", "omitted-write-fixture"], "Targeted Terminal Repair 15b per-issue mutation class drift")
        for issue in contract["raw_modbus_issues"]:
            issue_mutations: list[tuple[str, dict[str, Any]]] = []
            changed = copy.deepcopy(plan)
            machine = changed["issue_machine_contracts"]["contracts"][issue]
            fixture = next(row for row in machine["fixture_matrix"] if row["fixture_id"].endswith("FC05-AUTHORIZED"))
            fixture["expected_failure"] = None
            fixture["expected_output"] = machine["behavior_contract"]["expected_output"]
            fixture["expected_receipt"]["outcome"] = "ACCEPTED"
            issue_mutations.append(("authorized-write-accepted", changed))
            changed = copy.deepcopy(plan)
            fixture = next(row for row in changed["issue_machine_contracts"]["contracts"][issue]["fixture_matrix"] if row["fixture_id"].endswith("FC06-UNAUTHORIZED"))
            fixture["expected_receipt"]["transport_accessed"] = True
            fixture["expected_receipt"]["transport_call_count"] = 1
            fixture["expected_receipt"]["write_transport_call_count"] = 1
            issue_mutations.append(("write-reaches-transport", changed))
            changed = copy.deepcopy(plan)
            fixture = next(row for row in changed["issue_machine_contracts"]["contracts"][issue]["fixture_matrix"] if row["fixture_id"].endswith("FC10-AUTHORIZED"))
            fixture["expected_failure"] = "DENIED"
            fixture["expected_receipt"]["outcome"] = "DENIED"
            issue_mutations.append(("wrong-write-outcome", changed))
            changed = copy.deepcopy(plan)
            machine = changed["issue_machine_contracts"]["contracts"][issue]
            omitted_index = next(index for index, row in enumerate(machine["fixture_matrix"]) if row["fixture_id"].endswith("GENERIC_WRITE-UNAUTHORIZED"))
            machine["fixture_matrix"].pop(omitted_index)
            machine["test_ids"].pop(omitted_index)
            issue_mutations.append(("omitted-write-fixture", changed))
            require([label for label, _ in issue_mutations] == per_issue_classes, f"raw write mutation fixture order drift: {issue}")
            for label, mutation in issue_mutations:
                try:
                    assert_read_only(mutation)
                except ValidationError:
                    continue
                raise ValidationError(f"Targeted Terminal Repair 15b raw write mutation accepted: {issue}/{label}")
            descriptor_operators = contract["per_issue_mutation_operators"][-4:]
            require(
                descriptor_operators == [
                    "replace-descriptor-with-fc05", "replace-descriptor-with-fc06",
                    "replace-descriptor-with-fc0f", "replace-descriptor-with-fc10",
                ],
                "Modbus operation descriptor mutation class drift",
            )
            for operator, code in zip(descriptor_operators, contract["forbidden_write_function_codes_hex"]):
                changed = copy.deepcopy(plan)
                changed["issue_machine_contracts"]["contracts"][issue]["exact_limits"]["declared_modbus_operation_function_codes_hex"].append(code)
                try:
                    assert_read_only(changed)
                except ValidationError:
                    continue
                raise ValidationError(f"Modbus operation descriptor write mutation accepted: {issue}/{operator}")
        descriptor_mutant = copy.deepcopy(plan)
        descriptor_milestone = next(item for item in descriptor_mutant["milestones"] if item["id"] == "FMB-02A")
        descriptor_milestone["modbus_operation_descriptor"]["capability"] = "none"
        descriptor_milestone["modbus_operation_descriptor"]["capability_sources"] = []
        descriptor_mutant["transport_intents"]["FMB-02A"] = [{"family": "NONE", "when": "ALWAYS"}]
        try:
            assert_read_only(descriptor_mutant)
        except ValidationError:
            pass
        else:
            raise ValidationError("typed Modbus operation descriptor omission mutation accepted")

