    def terminal_repair_16_critical_issue_oracles() -> None:
        critical_ids = ["FMB-02B", "FMB-03E", "FMB-04O", "FMB-06H", "FMB-08A", "FMB-08I"]
        for issue in critical_ids:
            machine = plan["issue_machine_contracts"]["contracts"][issue]
            expected = expected_critical_issue_oracle(issue)
            require(machine["critical_oracle"] == expected and expected is not None, f"critical issue oracle missing: {issue}")
            require(len(expected["required_test_ids"]) == len(set(expected["required_test_ids"])) and len(expected["negative_case_ids"]) == len(set(expected["negative_case_ids"])), f"critical issue oracle case IDs are not exact sets: {issue}")
            require(set(expected["evidence_digest_fields"]) <= set(expected["report_fields"]), f"critical issue evidence digest/report field mismatch: {issue}")
            require("critical_oracle" in issue_external_commitment_surface(machine), f"critical issue oracle absent from external commitment surface: {issue}")
            require(all(binding["command_argv"] in machine["exact_commands"] for binding in expected["case_bindings"]), f"critical issue case command mapping missing: {issue}")
            require(expected["report_verifier_execution"]["cwd"] == "execution-plan-package-root" and expected["report_verifier_execution"]["resolved_argv_digest_field"] == "resolved_verifier_argv_sha256", f"critical report verifier execution contract missing: {issue}")
            fixture_by_id = {row["fixture_id"]: row for row in machine["fixture_matrix"]}
            require(set(binding["fixture_id"] for binding in expected["case_bindings"]) <= set(fixture_by_id) and f"{issue}-CRITICAL-SIGNED-REPORT" in fixture_by_id, f"critical issue executable fixture/report set missing: {issue}")
            require(all(fixture_by_id[binding["fixture_id"]]["input"]["command_argv"] == binding["command_argv"] and fixture_by_id[binding["fixture_id"]]["expected_output"]["outcome"] == binding["expected_outcome"] for binding in expected["case_bindings"]), f"critical issue case fixture mapping drift: {issue}")
            for mutation_kind in ["required-test-omission", "negative-case-substitution", "numeric-limit-downgrade", "report-field-omission", "evidence-digest-omission"]:
                changed = copy.deepcopy(machine["critical_oracle"])
                if mutation_kind == "required-test-omission":
                    changed["required_test_ids"].pop()
                elif mutation_kind == "negative-case-substitution":
                    changed["negative_case_ids"][0] = "ATTACKER-CASE"
                elif mutation_kind == "numeric-limit-downgrade":
                    key = next(iter(changed["numeric_limits"]))
                    changed["numeric_limits"][key] = "ATTACKER"
                elif mutation_kind == "report-field-omission":
                    changed["report_fields"].pop()
                else:
                    changed["evidence_digest_fields"].pop()
                changed_machine = copy.deepcopy(machine)
                changed_machine["critical_oracle"] = changed
                try:
                    validate_issue_execution_contract(plan, by_id[issue], changed_machine)
                except ValidationError:
                    continue
                raise ValidationError(f"critical oracle mutation accepted: {issue}/{mutation_kind}")

