    def ta15_authoritative_pre_m8_rtu_evidence() -> None:
        contract = plan["terminal_repair_15_contracts"]["pre_m8_rtu_evidence"]
        registry = fixture_key_registry()
        now = validate_fixture_clock(fixture_clock_document(plan), plan)
        require("pre_m8_source" not in canonical_json(plan["issue_machine_contracts"]), "caller-controlled pre_m8_source label survived issue fixtures")
        for name in contract["manual_files"]:
            require(markdown_without_generated_block((root / name).read_text(), plan).count(contract["canonical_prose"]) == 1, f"pre-M8 RTU evidence canonical prose parity drift: {name}")
        for outcome in contract["source_outcomes"]:
            bundle = contract["canonical_source_bundles"][outcome]
            for issue in contract["consumer_issues"]:
                context = build_pre_m8_rtu_context_fixture(plan, registry, f"tr15-{issue}-{outcome}", issue, outcome)
                require(not (set(contract["source_tuple_fields"]) & (set(context) - {"producer_release_envelope", "source_contract_evidence"})), "transport envelope contains caller source labels")
                derived = validate_pre_m8_rtu_context(context, plan, registry, now, expected_consumer_repo=by_id[issue]["repo"], expected_consumer_issue=issue)
                enabled = expand_transport_intent(plan, issue, context, registry, now)
                require(("MODBUS_RTU" in enabled) is (outcome == "PASS") and derived["m2r_selected_executable"] is (outcome == "PASS"), f"authoritative RTU dispatch drift: {issue}/{outcome}")
                expected_receipt = pre_m8_rtu_dispatch_receipt(contract, bundle, by_id[issue]["repo"], issue)
                require(set(derived["dispatch_receipt"]) == set(contract["dispatch_receipt_fields"]) and derived["dispatch_receipt"] == expected_receipt, f"verified pre-M8 RTU receipt drift: {issue}/{outcome}")
                require(derived["dispatch_receipt"]["verified_source_tuple"] == bundle["verified_source_tuple"] and derived["dispatch_receipt"]["exact_source_tuple_equality"] is True, f"pre-M8 RTU complete source tuple receipt drift: {issue}/{outcome}")
                if outcome == "PASS":
                    machine = plan["issue_machine_contracts"]["contracts"][issue]
                    fixture = next(row for row in machine["fixture_matrix"] if row["fixture_id"] == f"{issue}-MODBUS_RTU-M2R_SELECTED_EXECUTABLE")
                    require(
                        fixture["input"] == {
                            "source_head": "EXACT",
                            "transport_family": "MODBUS_RTU",
                            "dispatch_condition": "M2R_SELECTED_EXECUTABLE",
                            "producer_release_envelope_sha256": bundle["producer_release_envelope_sha256"],
                            "source_contract_evidence_sha256": bundle["source_contract_evidence_sha256"],
                        }
                        and fixture["expected_receipt"] == expected_receipt,
                        f"pre-M8 issue fixture exact producer envelope digest/receipt drift: {issue}",
                    )
        pass_context = build_pre_m8_rtu_context_fixture(plan, registry, "tr15-mutation", "FMB-04L", "PASS")

        def resigned_mutation(field: str, value: Any, signer: str | None = None) -> dict[str, Any]:
            changed = copy.deepcopy(pass_context)
            envelope = changed["producer_release_envelope"]
            unsigned = {key: item for key, item in envelope.items() if key not in {"signature", "revocation_generation"}}
            unsigned[field] = value
            if signer is not None:
                unsigned["producer_signer_id"] = signer
                unsigned["signer_id"] = signer
            changed["producer_release_envelope"] = sign_fixture(unsigned, registry)
            changed["producer_release_envelope_sha256"] = sha(canonical_json(changed["producer_release_envelope"]).encode())
            return sign_fixture({key: item for key, item in changed.items() if key not in {"signature", "revocation_generation"}}, registry)

        def resigned_envelope_digest_mutation() -> dict[str, Any]:
            changed = copy.deepcopy(pass_context)
            changed["producer_release_envelope_sha256"] = "e" * 64
            return sign_fixture({key: item for key, item in changed.items() if key not in {"signature", "revocation_generation"}}, registry)

        mutations = [
            ("validly-resigned-stale-head", resigned_mutation("producer_head_oid", "e" * 40)),
            ("validly-resigned-wrong-tree", resigned_mutation("producer_tree_oid", "e" * 40)),
            ("validly-resigned-wrong-digest", resigned_mutation("content_digest_sha256", "e" * 64)),
            ("validly-resigned-wrong-repo", resigned_mutation("producer_repo", "attacker-repo")),
            ("validly-resigned-wrong-issue", resigned_mutation("producer_issue", "FMB-ATTACKER")),
            ("validly-resigned-wrong-schema", resigned_mutation("artifact_schema", "attacker-rtu-schema-v1")),
            ("validly-resigned-wrong-signer", resigned_mutation("producer_signer_id", "attacker-release-authority", "attacker-release-authority")),
            ("validly-resigned-wrong-envelope-digest", resigned_envelope_digest_mutation()),
        ]
        require([label for label, _ in mutations] == contract["mutation_classes"], "Terminal Repair 15 pre-M8 mutation class drift")
        for label, mutation in mutations:
            try:
                validate_pre_m8_rtu_context(mutation, plan, registry, now, expected_consumer_repo="helianthus-ebusgateway", expected_consumer_issue="FMB-04L")
            except ValidationError as error:
                require(str(error) == contract["mutation_expected_failures"][label], f"validly re-signed source mutation failed for wrong reason: {label}: {error}")
                continue
            raise ValidationError(f"validly re-signed stale source tuple accepted: {label}")

    check("terminal_repair_15_authoritative_pre_m8_rtu_evidence", ta15_authoritative_pre_m8_rtu_evidence)

