        semantic_mutations.append(("validly-signed-stale-live-binding", semantic_evidence(stale_binding, valid_slos)))
        failed_threshold_slos = copy.deepcopy(valid_slos); failed_threshold_slos["SLO-1"]["profile_metrics"][0]["scheduled_polls"] = 299
        semantic_mutations.append(("validly-signed-SLO-threshold-failure", semantic_evidence(live_report(), failed_threshold_slos)))
        omitted_slo_profile = copy.deepcopy(valid_slos); omitted_slo_profile["SLO-1"]["profile_metrics"] = []
        semantic_mutations.append(("selected-profile-omitted-from-SLO", semantic_evidence(live_report(), omitted_slo_profile)))
        unhealthy_slos = copy.deepcopy(valid_slos); unhealthy_slos["SLO-1"]["profile_metrics"][0]["healthy_polls_within_2x_percent"] = 98
        semantic_mutations.append(("SLO-healthy-poll-threshold-failure", semantic_evidence(live_report(), unhealthy_slos)))
        regression_slos = copy.deepcopy(valid_slos); regression_slos["SLO-1"]["ebus_p95_regression_percent"] = 6
        semantic_mutations.append(("SLO-ebus-regression-threshold-failure", semantic_evidence(live_report(), regression_slos)))
        recovery_slos = copy.deepcopy(valid_slos); recovery_slos["SLO-1"]["recovery_bound_met"] = False
        semantic_mutations.append(("SLO-recovery-bound-failure", semantic_evidence(live_report(), recovery_slos)))
        stale_slo_binding = copy.deepcopy(valid_slos); stale_slo_binding["SLO-1"]["canonical_catalog_sha256"] = "e" * 64
        semantic_mutations.append(("validly-signed-stale-SLO-binding", semantic_evidence(live_report(), stale_slo_binding)))
