    def ta12b_roadmap_chunk_declarations() -> None:
        validate_terminal_repair_12b_contract(plan)
        roadmap = (root / "13-roadmap-issues-risks.md").read_text()
        index = (root / "01-index.md").read_text()
        validate_roadmap_chunk_contract(roadmap, index, plan)
        contract = plan["terminal_repair_12_contracts"]["targeted_repair_12b"]["roadmap_chunk"]
        rendered = render_roadmap_chunk_contract(plan)
        declaration_lines = [f"{contract['declaration_labels'][key]}: {contract['declarations'][key]}" for key in contract["declaration_order"]]
        mutations: list[tuple[str, str, str]] = []
        mutations.append(("omission", roadmap.replace(declaration_lines[0], "", 1), index))
        mutations.append(("duplicate", roadmap.replace(declaration_lines[-1], declaration_lines[-1] + "\n\n" + declaration_lines[-1], 1), index))
        swapped = rendered.replace(declaration_lines[0], "__ROADMAP_DECLARATION_SWAP__", 1).replace(declaration_lines[1], declaration_lines[0], 1).replace("__ROADMAP_DECLARATION_SWAP__", declaration_lines[1], 1)
        mutations.append(("reorder", roadmap.replace(rendered, swapped, 1), index))
        mutations.append(("wrong-value", roadmap.replace(contract["declarations"]["falsifiability"], "Validation always passes.", 1), index))
        mutations.append(("index-detachment", roadmap, index.replace(contract["index_link"], "13-roadmap-issues-risks.md", 1)))
        require([label for label, _, _ in mutations] == contract["mutation_classes"], "roadmap chunk mutation class coverage drift")
        for label, mutated_roadmap, mutated_index in mutations:
            try:
                validate_roadmap_chunk_contract(mutated_roadmap, mutated_index, plan)
            except ValidationError:
                continue
            raise ValidationError(f"roadmap chunk declaration mutation accepted: {label}")
        for key in contract["declaration_order"]:
            mutant = copy.deepcopy(plan)
            del mutant["terminal_repair_12_contracts"]["targeted_repair_12b"]["roadmap_chunk"]["declarations"][key]
            try:
                validate_roadmap_chunk_contract(roadmap, index, mutant)
            except (ValidationError, KeyError):
                continue
            raise ValidationError(f"roadmap plan.yaml declaration omission accepted: {key}")

    check("terminal_repair_12b_roadmap_chunk_declarations", ta12b_roadmap_chunk_declarations)

