            require(producer_summary["base_fixture_binding"] == expected_eebus_base_fixture_binding(plan) and producer_summary["composition_schema"] == repair_12b["eebus_producer_envelope_execution"]["composition_schema"] and producer_summary["composition_mutation_classes"] == repair_12b["eebus_producer_envelope_execution"]["composition_mutation_classes"], f"generated eeBUS base-fixture composition summary drift: {name}")
            roadmap_summary = generated_json_label(markdown, "Indexed roadmap chunk declarations")
            require(roadmap_summary["declaration_order"] == repair_12b["roadmap_chunk"]["declaration_order"] and roadmap_summary["declarations"] == repair_12b["roadmap_chunk"]["declarations"], f"generated roadmap declaration summary drift: {name}")
            current_summary = generated_json_label(markdown, "Audit 12 current round")
