            require(generated_json_label(markdown, "Terminal Repair 13 root singularities") == repair_13["root_authority_singularities"], f"generated Terminal Repair 13 root singularity drift: {name}")
            require(generated_json_label(markdown, "Terminal Repair 13 emergency private owners") == repair_13["emergency_private_owners"], f"generated Terminal Repair 13 emergency owner drift: {name}")
