            require(generated_json_label(markdown, "Terminal Repair 14 sensitive relationships") == repair_14["sensitive_relationship_blocks"], f"generated Terminal Repair 14 sensitive relationship drift: {name}")
            require(generated_json_label(markdown, "Terminal Repair 14 lock assertions") == repair_14["lock_assertion_blocks"], f"generated Terminal Repair 14 lock assertion drift: {name}")
