            require(generated_json_label(markdown, "Terminal Repair 14 canonical coverage") == repair_14["canonical_coverage_ranges"], f"generated Terminal Repair 14 canonical coverage drift: {name}")
            repair_15 = plan["terminal_repair_15_contracts"]
