            require(generated_json_label(markdown, "Terminal Repair 15 issue authority") == repair_15["issue_behavior_authority_pending"], f"generated Terminal Repair 15 issue authority drift: {name}")
            require(generated_json_label(markdown, "Terminal Repair 15 read-only v1") == repair_15["read_only_v1"], f"generated Terminal Repair 15 read-only v1 drift: {name}")
